import type { PublicCard } from '../../../types';

export const mathCards: PublicCard[] = [
  { id: 'dc-math-0001', deck_id: 'deck-math', front: 'Quadratic Formula', back: 'x = (-b ± √(b²-4ac)) / 2a. Solves any quadratic equation ax² + bx + c = 0; the discriminant b²-4ac determines the number of real roots.', front_translations: {"es":"Fórmula cuadrática","de":"Quadratische Formel","fr":"Formule quadratique","tr":"İkinci Dereceden Denklem Formülü","nl":"Kwadratische formule","ru":"Квадратная формула","zh":"求根公式","pt_BR":"Fórmula quadrática","pt_PT":"Fórmula quadrática"}, back_translations: {"es":"x = (-b ± √(b²-4ac)) / 2a. Resuelve cualquier ecuación cuadrática ax² + bx + c = 0; el discriminante b²-4ac determina el número de raíces reais.","de":"x = (-b ± √(b²-4ac)) / 2a. Löst jede quadratische Gleichung ax² + bx + c = 0; die Diskriminante b²-4ac bestimmt die Anzahl der reellen Wurzeln.","fr":"x = (-b ± √(b²-4ac)) / 2a. Résout toute équation du second degré ax² + bx + c = 0 ; le discriminant b²-4ac détermine le nombre de racines réelles.","tr":"x = (-b ± √(b²-4ac)) / 2a. Herhangi bir ax² + bx + c = 0 ikinci dereceden denklemi çözer; diskriminant b²-4ac gerçek köklerin sayısını belirler.","nl":"x = (-b ± √(b²-4ac)) / 2a. Lost elke kwadratische vergelijking ax² + bx + c = 0 op; de discriminant b²-4ac bepaalt het aantal reële wortels.","ru":"x = (-b ± √(b²-4ac)) / 2a. Решает любое квадратное уравнение ax² + bx + c = 0; дискриминант b²-4ac определяет количество вещественных корней.","zh":"x = (-b ± √(b²-4ac)) / 2a。求解任意二次方程 ax² + bx + c = 0；判别式 b²-4ac 决定实根的个数。","pt_BR":"x = (-b ± √(b²-4ac)) / 2a. Resolve qualquer equação quadrática ax² + bx + c = 0; o discriminante b²-4ac determina o número de raízes reais.","pt_PT":"x = (-b ± √(b²-4ac)) / 2a. Resolve qualquer equação quadrática ax² + bx + c = 0; o discriminante b²-4ac determina o número de raízes reais."}, sort_order: 1 },
  { id: 'dc-math-0002', deck_id: 'deck-math', front: 'Pythagorean Theorem', back: 'a² + b² = c². In a right triangle, the square of the hypotenuse (c) equals the sum of squares of the other two sides (a and b).', front_translations: {"es":"Teorema de Pitágoras","de":"Satz des Pythagoras","fr":"Théorème de Pythagore","tr":"Pisagor Teoremi","nl":"Stelling van Pythagoras","ru":"Теорема Пифагора","zh":"勾股定理","pt_BR":"Teorema de Pitágoras","pt_PT":"Teorema de Pitágoras"}, back_translations: {"es":"a² + b² = c². En un triángulo rectángulo, el cuadrado de la hipotenusa (c) es igual a la suma de los cuadrados de los outros de los lados (a y b).","de":"a² + b² = c². In einem rechtwinkligen Dreieck ist das Quadrat der Hypotenuse (c) gleich der Summe der Quadrate der anderen beiden Seiten (a und b).","fr":"a² + b² = c². Dans un triangle rectangle, le carré de l'hypoténuse (c) est égal à la somme des carrés des deux autres côtés (a et b).","tr":"a² + b² = c². Bir dik üçgende hipotenüsün (c) karesi diğer iki kenarın (a ve b) karelerinin toplamına eşittir.","nl":"a² + b² = c². In een rechthoekige driehoek is het kwadraat van de hypotenusa (c) gelijk aan de som van de kwadraten van de andere twee zijden (a en b).","ru":"a² + b² = c². В прямоугольном треугольнике квадрат гипотенузы (c) равен сумме квадратов двух других сторон (a и b).","zh":"a² + b² = c²。在直角三角形中，斜边（c）的平方等于另外两边（a 和 b）的平方和。","pt_BR":"a² + b² = c². Em um triângulo retângulo, o quadrado da hipotenusa (c) é igual à soma dos quadrados dos outros dois lados (a e b).","pt_PT":"a² + b² = c². Num triângulo retângulo, o quadrado da hipotenusa (c) é igual à soma dos quadrados dos outros dois lados (a e b)."}, sort_order: 2 },
  { id: 'dc-math-0003', deck_id: 'deck-math', front: 'Area of a Circle', back: 'A = πr². The area of a circle equals pi times the radius squared; equivalently A = πd²/4 where d is the diameter.', front_translations: {"es":"Área de un círculo","de":"Kreisfläche","fr":"Aire d'un cercle","tr":"Dairenin Alanı","nl":"Oppervlakte van een cirkel","ru":"Площадь круга","zh":"圆的面积","pt_BR":"Área de um círculo","pt_PT":"Área de um círculo"}, back_translations: {"es":"La = πr². La área de un círculo es igual a pi veces el cuadrado del raio; equivalentemente A = πd²/4 donde d es el diametro.","de":"A = πr². Die Kreisfläche ist gleich Pi mal dem Quadrat des Radius; äquivalent A = πd²/4, wobei d der Durchmesser ist.","fr":"A = πr². L'aire d'un cercle est égale à pi fois le carré du rayon ; équivalent à A = πd²/4 où d est le diamètre.","tr":"A = πr². Bir dairenin alanı, pi çarpı yarıçapın karesidir; d çap olmak üzere A = πd²/4 ile eşdeğerdir.","nl":"A = πr². De oppervlakte van een cirkel is gelijk aan pi maal het kwadraat van de straal; equivalent: A = πd²/4 waarbij d de diameter is.","ru":"A = πr². Площадь круга равна числу пи, умноженному на квадрат радиуса; эквивалентно A = πd²/4, где d — диаметр.","zh":"A = πr²。圆的面积等于圆周率乘以半径的平方；等价地，A = πd²/4，其中 d 为直径。","pt_BR":"A = πr². A área de um círculo é igual a pi vezes o quadrado do raio; equivalentemente A = πd²/4 onde d é o diâmetro.","pt_PT":"A = πr². A área de um círculo é igual a pi vezes o quadrado do raio; equivalentemente A = πd²/4 onde d é o diâmetro."}, sort_order: 3 },
  { id: 'dc-math-0004', deck_id: 'deck-math', front: 'Derivative of xⁿ (Power Rule)', back: 'd/dx(xⁿ) = nxⁿ⁻¹. Multiply the coefficient by the exponent, then reduce the exponent by 1; applies to any real exponent.', front_translations: {"es":"Derivada de xⁿ (Regra de la potencia)","de":"Ableitung von xⁿ (Potenzregel)","fr":"Dérivée de xⁿ (règle de la puissance)","tr":"xⁿ'nin Türevi (Kuvvet Kuralı)","nl":"Afgeleide van xⁿ (machtsregel)","ru":"Производная xⁿ (правило степени)","zh":"xⁿ 的导数（幂次法则）","pt_BR":"Derivada de xⁿ (Regra da potência)","pt_PT":"Derivada de xⁿ (Regra da potência)"}, back_translations: {"es":"d/dx(xⁿ) = nxⁿ⁻¹. Multiplique el coeficiente por el exponente y reduza el exponente en 1; se aplica a cualquier exponente real.","de":"d/dx(xⁿ) = nxⁿ⁻¹. Multipliziere den Koeffizienten mit dem Exponenten und reduziere dann den Exponenten um 1; gilt für jeden reellen Exponenten.","fr":"d/dx(xⁿ) = nxⁿ⁻¹. Multiplier le coefficient par l'exposant, puis réduire l'exposant de 1 ; s'applique à tout exposant réel.","tr":"d/dx(xⁿ) = nxⁿ⁻¹. Katsayıyı üsle çarp, ardından üssü 1 azalt; herhangi bir gerçek üsse uygulanır.","nl":"d/dx(xⁿ) = nxⁿ⁻¹. Vermenigvuldig de coëfficiënt met de exponent en verminder de exponent met 1; geldt voor elke reële exponent.","ru":"d/dx(xⁿ) = nxⁿ⁻¹. Умножьте коэффициент на показатель степени, затем уменьшите показатель на 1; применяется к любому вещественному показателю.","zh":"d/dx(xⁿ) = nxⁿ⁻¹。将系数乘以指数，然后将指数减 1；适用于任意实数指数。","pt_BR":"d/dx(xⁿ) = nxⁿ⁻¹. Multiplique o coeficiente pelo expoente e reduza o expoente em 1; aplica-se a qualquer expoente real.","pt_PT":"d/dx(xⁿ) = nxⁿ⁻¹. Multiplique o coeficiente pelo expoente e reduza o expoente em 1; aplica-se a qualquer expoente real."}, sort_order: 4 },
  { id: 'dc-math-0005', deck_id: 'deck-math', front: 'Circumference of a Circle', back: 'C = 2πr = πd. The circumference is the distance around the circle, equal to 2 times pi times the radius.', front_translations: {"es":"Circunferencia de un círculo","de":"Umfang eines Kreises","fr":"Circonférence d'un cercle","tr":"Dairenin Çevresi","nl":"Omtrek van een cirkel","ru":"Длина окружности","zh":"圆的周长","pt_BR":"Circunferência de um círculo","pt_PT":"Circunferência de um círculo"}, back_translations: {"es":"C = 2πr = πd. La circunferencia es a distancia alrededor del círculo, igual a 2 veces pi veces el raio.","de":"C = 2πr = πd. Der Umfang ist die Entfernung um den Kreis herum, gleich 2 mal Pi mal Radius.","fr":"C = 2πr = πd. La circonférence est la distance autour du cercle, égale à 2 fois pi fois le rayon.","tr":"C = 2πr = πd. Çevre, dairenin etrafındaki mesafedir; 2 çarpı pi çarpı yarıçapa eşittir.","nl":"C = 2πr = πd. De omtrek is de afstand rondom de cirkel, gelijk aan 2 maal pi maal de straal.","ru":"C = 2πr = πd. Длина окружности — это расстояние вокруг круга, равное 2 умноженному на π и на радиус.","zh":"C = 2πr = πd。周长是绕圆一圈的距离，等于 2 乘以圆周率乘以半径。","pt_BR":"C = 2πr = πd. A circunferência é a distância ao redor do círculo, igual a 2 vezes pi vezes o raio.","pt_PT":"C = 2πr = πd. A circunferência é a distância ao redor do círculo, igual a 2 vezes pi vezes o raio."}, sort_order: 5 },
  { id: 'dc-math-0006', deck_id: 'deck-math', front: 'Area of a Triangle', back: 'A = (1/2) × base × height. The area equals half the product of the base and the perpendicular height.', front_translations: {"es":"Área de un triángulo","de":"Dreiecksfläche","fr":"Aire d'un triangle","tr":"Üçgenin Alanı","nl":"Oppervlakte van een driehoek","ru":"Площадь треугольника","zh":"三角形面积","pt_BR":"Área de um triângulo","pt_PT":"Área de um triângulo"}, back_translations: {"es":"La = (1/2) × base × altura. La área es igual a la metade del producto de la base por la altura perpendicular.","de":"A = (1/2) × Basis × Höhe. Die Fläche ist das Halbe des Produkts aus Basis und senkrechter Höhe.","fr":"A = (1/2) × base × hauteur. L'aire est la moitié du produit de la base et de la hauteur perpendiculaire.","tr":"A = (1/2) × taban × yükseklik. Alan, taban ile dik yüksekliğin çarpımının yarısına eşittir.","nl":"A = (1/2) × basis × hoogte. De oppervlakte is de helft van het product van de basis en de loodrechte hoogte.","ru":"A = (1/2) × основание × высота. Площадь равна половине произведения основания на перпендикулярную высоту.","zh":"A = (1/2) × 底 × 高。面积等于底与垂直高度之积的一半。","pt_BR":"A = (1/2) × base × altura. A área é igual à metade do produto da base pela altura perpendicular.","pt_PT":"A = (1/2) × base × altura. A área é igual a metade do produto da base pela altura perpendicular."}, sort_order: 6 },
  { id: 'dc-math-0007', deck_id: 'deck-math', front: 'Area of a Rectangle', back: 'A = length × width. The area of a rectangle is simply the product of its two dimensions.', front_translations: {"es":"Área de un rectángulo","de":"Rechteckfläche","fr":"Aire d'un rectangle","tr":"Dikdörtgenin Alanı","nl":"Oppervlakte van een rechthoek","ru":"Площадь прямоугольника","zh":"矩形面积","pt_BR":"Área de um retângulo","pt_PT":"Área de um retângulo"}, back_translations: {"es":"La = comprimento × largura. La área de un rectángulo es simplemente el producto de sus de los dimensões.","de":"A = Länge × Breite. Die Fläche eines Rechtecks ist das Produkt seiner zwei Dimensionen.","fr":"A = longueur × largeur. L'aire d'un rectangle est simplement le produit de ses deux dimensions.","tr":"A = uzunluk × genişlik. Bir dikdörtgenin alanı sadece iki boyutunun çarpımıdır.","nl":"A = lengte × breedte. De oppervlakte van een rechthoek is het product van zijn twee afmetingen.","ru":"A = длина × ширина. Площадь прямоугольника — это просто произведение его двух размеров.","zh":"A = 长 × 宽。矩形面积就是其两个维度的乘积。","pt_BR":"A = comprimento × largura. A área de um retângulo é simplesmente o produto de suas duas dimensões.","pt_PT":"A = comprimento × largura. A área de um rectângulo é simplesmente o produto das suas duas dimensões."}, sort_order: 7 },
  { id: 'dc-math-0008', deck_id: 'deck-math', front: 'Area of a Trapezoid', back: 'A = (1/2)(a + b)h. Where a and b are the lengths of the parallel sides and h is the perpendicular height between them.', front_translations: {"es":"Área de un trapézio","de":"Trapezfläche","fr":"Aire d'un trapèze","tr":"Yamukun Alanı","nl":"Oppervlakte van een trapezium","ru":"Площадь трапеции","zh":"梯形面积","pt_BR":"Área de um trapézio","pt_PT":"Área de um trapézio"}, back_translations: {"es":"La = (1/2)(a + b)h. Donde a y b son los comprimentos de los lados paralelos y h es a altura perpendicular entre eles.","de":"A = (1/2)(a + b)h. Wobei a und b die Längen der parallelen Seiten und h die senkrechte Höhe zwischen ihnen ist.","fr":"A = (1/2)(a + b)h. Où a et b sont les longueurs des côtés parallèles et h est la hauteur perpendiculaire entre eux.","tr":"A = (1/2)(a + b)h. a ve b paralel kenarların uzunlukları, h ise aralarındaki dik yüksekliktir.","nl":"A = (1/2)(a + b)h. Waarbij a en b de lengten van de parallelle zijden zijn en h de loodrechte hoogte daartussen.","ru":"A = (1/2)(a + b)h. Где a и b — длины параллельных сторон, а h — перпендикулярная высота между ними.","zh":"A = (1/2)(a + b)h。其中 a 和 b 是两平行边的长度，h 是它们之间的垂直高度。","pt_BR":"A = (1/2)(a + b)h. Onde a e b são os comprimentos dos lados paralelos e h é a altura perpendicular entre eles.","pt_PT":"A = (1/2)(a + b)h. Onde a e b são os comprimentos dos lados paralelos e h é a altura perpendicular entre eles."}, sort_order: 8 },
  { id: 'dc-math-0009', deck_id: 'deck-math', front: 'Volume of a Sphere', back: 'V = (4/3)πr³. The volume of a sphere is four-thirds times pi times the cube of the radius.', front_translations: {"es":"Volume de una esfera","de":"Kugelvolumen","fr":"Volume d'une sphère","tr":"Kürenin Hacmi","nl":"Volume van een bol","ru":"Объём шара","zh":"球的体积","pt_BR":"Volume de uma esfera","pt_PT":"Volume de uma esfera"}, back_translations: {"es":"V = (4/3)πr³. El volumen de una esfera es cuatro terços veces pi veces el cubo del raio.","de":"V = (4/3)πr³. Das Volumen einer Kugel ist vier Drittel mal Pi mal die dritte Potenz des Radius.","fr":"V = (4/3)πr³. Le volume d'une sphère est quatre tiers fois pi fois le cube du rayon.","tr":"V = (4/3)πr³. Bir kürenin hacmi, dörtte üç çarpı pi çarpı yarıçapın küpüdür.","nl":"V = (4/3)πr³. Het volume van een bol is vier derde maal pi maal de derde macht van de straal.","ru":"V = (4/3)πr³. Объём шара равен четырём третям числа π, умноженного на куб радиуса.","zh":"V = (4/3)πr³。球的体积等于三分之四乘以圆周率乘以半径的三次方。","pt_BR":"V = (4/3)πr³. O volume de uma esfera é quatro terços vezes pi vezes o cubo do raio.","pt_PT":"V = (4/3)πr³. O volume de uma esfera é quatro terços vezes pi vezes o cubo do raio."}, sort_order: 9 },
  { id: 'dc-math-0010', deck_id: 'deck-math', front: 'Surface Area of a Sphere', back: 'SA = 4πr². The surface area is four times pi times the radius squared; note it is 4 times the area of a great circle.', front_translations: {"es":"Área superficial de una esfera","de":"Kugeloberfläche","fr":"Aire d'une sphère","tr":"Kürenin Yüzey Alanı","nl":"Oppervlakte van een bol","ru":"Площадь поверхности шара","zh":"球的表面积","pt_BR":"Área superficial de uma esfera","pt_PT":"Área superficial de uma esfera"}, back_translations: {"es":"SA = 4πr². La área superficial es cuatro veces pi veces el cuadrado del raio; equivale a 4 veces a área de un círculo máximo.","de":"SA = 4πr². Die Oberfläche ist vier mal Pi mal dem Quadrat des Radius; sie entspricht dem 4-fachen der Fläche eines Großkreises.","fr":"SA = 4πr². L'aire de la surface est quatre fois pi fois le carré du rayon ; elle vaut 4 fois l'aire d'un grand cercle.","tr":"SA = 4πr². Yüzey alanı, dört çarpı pi çarpı yarıçapın karesidir; büyük dairenin alanının 4 katıdır.","nl":"SA = 4πr². De oppervlakte is vier maal pi maal het kwadraat van de straal; dit is 4 keer de oppervlakte van een grootcirkel.","ru":"SA = 4πr². Площадь поверхности равна четырём числа π, умноженным на квадрат радиуса; это в 4 раза больше площади большого круга.","zh":"SA = 4πr²。表面积等于四倍圆周率乘以半径的平方；注意它是大圆面积的 4 倍。","pt_BR":"SA = 4πr². A área superficial é quatro vezes pi vezes o quadrado do raio; equivale a 4 vezes a área de um círculo máximo.","pt_PT":"SA = 4πr². A área superficial é quatro vezes pi vezes o quadrado do raio; equivale a 4 vezes a área de um círculo máximo."}, sort_order: 10 },
  { id: 'dc-math-0011', deck_id: 'deck-math', front: 'Volume of a Cylinder', back: 'V = πr²h. The volume is the area of the circular base (πr²) multiplied by the height h.', front_translations: {"es":"Volume de un cilindro","de":"Zylindervolumen","fr":"Volume d'un cylindre","tr":"Silindirin Hacmi","nl":"Volume van een cilinder","ru":"Объём цилиндра","zh":"圆柱体积","pt_BR":"Volume de um cilindro","pt_PT":"Volume de um cilindro"}, back_translations: {"es":"V = πr²h. El volumen es a área de la base circular (πr²) multiplicada por la altura h.","de":"V = πr²h. Das Volumen ist die Fläche der Kreisbasis (πr²) multipliziert mit der Höhe h.","fr":"V = πr²h. Le volume est l'aire de la base circulaire (πr²) multipliée par la hauteur h.","tr":"V = πr²h. Hacim, dairesel tabanın alanının (πr²) yükseklik h ile çarpımıdır.","nl":"V = πr²h. Het volume is de oppervlakte van de cirkelvormige basis (πr²) vermenigvuldigd met de hoogte h.","ru":"V = πr²h. Объём равен площади круглого основания (πr²), умноженной на высоту h.","zh":"V = πr²h。体积等于圆形底面积（πr²）乘以高度 h。","pt_BR":"V = πr²h. O volume é a área da base circular (πr²) multiplicada pela altura h.","pt_PT":"V = πr²h. O volume é a área da base circular (πr²) multiplicada pela altura h."}, sort_order: 11 },
  { id: 'dc-math-0012', deck_id: 'deck-math', front: 'Volume of a Cone', back: 'V = (1/3)πr²h. The volume of a cone is one-third the volume of the cylinder with the same base and height.', front_translations: {"es":"Volume de un cone","de":"Kegelvolumen","fr":"Volume d'un cône","tr":"Koninin Hacmi","nl":"Volume van een kegel","ru":"Объём конуса","zh":"圆锥体积","pt_BR":"Volume de um cone","pt_PT":"Volume de um cone"}, back_translations: {"es":"V = (1/3)πr²h. El volumen de un cone es un terço del volumen del cilindro con a misma base y altura.","de":"V = (1/3)πr²h. Das Kegelvolumen ist ein Drittel des Zylindervolumens mit gleicher Basis und Höhe.","fr":"V = (1/3)πr²h. Le volume d'un cône est le tiers du volume du cylindre de même base et de même hauteur.","tr":"V = (1/3)πr²h. Bir koninin hacmi, aynı taban ve yüksekliğe sahip silindirin hacminin üçte birine eşittir.","nl":"V = (1/3)πr²h. Het volume van een kegel is een derde van het volume van de cilinder met dezelfde basis en hoogte.","ru":"V = (1/3)πr²h. Объём конуса равен одной трети объёма цилиндра с той же основой и высотой.","zh":"V = (1/3)πr²h。圆锥的体积等于具有相同底面和高度的圆柱体积的三分之一。","pt_BR":"V = (1/3)πr²h. O volume de um cone é um terço do volume do cilindro com a mesma base e altura.","pt_PT":"V = (1/3)πr²h. O volume de um cone é um terço do volume do cilindro com a mesma base e altura."}, sort_order: 12 },
  { id: 'dc-math-0013', deck_id: 'deck-math', front: 'Volume of a Rectangular Prism', back: 'V = l × w × h. The volume equals the product of length, width, and height; also called a cuboid.', front_translations: {"es":"Volume de un paralelepípedo","de":"Volumen eines Quaders","fr":"Volume d'un parallélépipède rectangle","tr":"Dikdörtgenler Prizmasının Hacmi","nl":"Volume van een rechthoekig prisma","ru":"Объём прямоугольного параллелепипеда","zh":"长方体体积","pt_BR":"Volume de um paralelepípedo","pt_PT":"Volume de um paralelepípedo"}, back_translations: {"es":"V = c × l × a. El volumen es el producto del comprimento, largura y altura; también llamado de paralelepípedo.","de":"V = l × b × h. Das Volumen ist das Produkt aus Länge, Breite und Höhe; auch Quader genannt.","fr":"V = l × w × h. Le volume est le produit de la longueur, la largeur et la hauteur ; aussi appelé pavé droit.","tr":"V = l × g × h. Hacim, uzunluk, genişlik ve yüksekliğin çarpımına eşittir; dikdörtgenler prizması olarak da bilinir.","nl":"V = l × b × h. Het volume is het product van lengte, breedte en hoogte; ook wel een balk genoemd.","ru":"V = l × w × h. Объём равен произведению длины, ширины и высоты; также называется прямоугольным параллелепипедом.","zh":"V = l × w × h。体积等于长、宽、高的乘积；也称为长方体。","pt_BR":"V = c × l × a. O volume é o produto do comprimento, largura e altura; também chamado de paralelepípedo.","pt_PT":"V = c × l × a. O volume é o produto do comprimento, largura e altura; também chamado de paralelepípedo."}, sort_order: 13 },
  { id: 'dc-math-0014', deck_id: 'deck-math', front: 'Volume of a Cube', back: 'V = s³. The volume of a cube with side length s is s cubed; the surface area is 6s².', front_translations: {"es":"Volume de un cubo","de":"Würfelvolumen","fr":"Volume d'un cube","tr":"Küpün Hacmi","nl":"Volume van een kubus","ru":"Объём куба","zh":"正方体体积","pt_BR":"Volume de um cubo","pt_PT":"Volume de um cubo"}, back_translations: {"es":"V = s³. El volumen de un cubo con lado s es s al cubo; a área superficial es 6s².","de":"V = s³. Das Volumen eines Würfels mit Seitenlänge s ist s hoch 3; die Oberfläche beträgt 6s².","fr":"V = s³. Le volume d'un cube de côté s est s au cube ; l'aire de la surface est 6s².","tr":"V = s³. Kenar uzunluğu s olan bir küpün hacmi s küptür; yüzey alanı ise 6s²'dir.","nl":"V = s³. Het volume van een kubus met zijde s is s tot de derde macht; de oppervlakte is 6s².","ru":"V = s³. Объём куба со стороной s равен s в кубе; площадь поверхности равна 6s².","zh":"V = s³。边长为 s 的正方体体积为 s 的三次方；表面积为 6s²。","pt_BR":"V = s³. O volume de um cubo com lado s é s ao cubo; a área superficial é 6s².","pt_PT":"V = s³. O volume de um cubo com lado s é s ao cubo; a área superficial é 6s²."}, sort_order: 14 },
  { id: 'dc-math-0015', deck_id: 'deck-math', front: 'Distance Formula', back: 'd = √((x₂-x₁)² + (y₂-y₁)²). The distance between two points in a plane; derived directly from the Pythagorean theorem.', front_translations: {"es":"Fórmula de la distancia","de":"Abstandsformel","fr":"Formule de distance","tr":"Uzaklık Formülü","nl":"Afstandsformule","ru":"Формула расстояния","zh":"距离公式","pt_BR":"Fórmula da distância","pt_PT":"Fórmula da distância"}, back_translations: {"es":"d = √((x₂-x₁)² + (y₂-y₁)²). La distancia entre de los puntos en un plano; derivada directamente del teorema de Pitágoras.","de":"d = √((x₂-x₁)² + (y₂-y₁)²). Der Abstand zwischen zwei Punkten in einer Ebene; direkt aus dem Satz des Pythagoras abgeleitet.","fr":"d = √((x₂-x₁)² + (y₂-y₁)²). La distance entre deux points dans un plan ; dérivée directement du théorème de Pythagore.","tr":"d = √((x₂-x₁)² + (y₂-y₁)²). Düzlemdeki iki nokta arasındaki mesafe; doğrudan Pisagor teoreminden türetilir.","nl":"d = √((x₂-x₁)² + (y₂-y₁)²). De afstand tussen twee punten in een vlak; direct afgeleid van de stelling van Pythagoras.","ru":"d = √((x₂-x₁)² + (y₂-y₁)²). Расстояние между двумя точками на плоскости; выводится непосредственно из теоремы Пифагора.","zh":"d = √((x₂-x₁)² + (y₂-y₁)²)。平面上两点间的距离；直接由勾股定理推导而来。","pt_BR":"d = √((x₂-x₁)² + (y₂-y₁)²). A distância entre dois pontos num plano; derivada diretamente do teorema de Pitágoras.","pt_PT":"d = √((x₂-x₁)² + (y₂-y₁)²). A distância entre dois pontos num plano; derivada directamente do teorema de Pitágoras."}, sort_order: 15 },
  { id: 'dc-math-0016', deck_id: 'deck-math', front: 'Midpoint Formula', back: 'M = ((x₁+x₂)/2, (y₁+y₂)/2). The midpoint of a line segment is the average of the x-coordinates and the average of the y-coordinates.', front_translations: {"es":"Fórmula del punto médio","de":"Mittelpunktformel","fr":"Formule du milieu","tr":"Orta Nokta Formülü","nl":"Middelpuntsformule","ru":"Формула середины отрезка","zh":"中点公式","pt_BR":"Fórmula do ponto médio","pt_PT":"Fórmula do ponto médio"}, back_translations: {"es":"M = ((x₁+x₂)/2, (y₁+y₂)/2). El punto médio de un segmento es a média de las coordenadas x y a média de las coordenadas y.","de":"M = ((x₁+x₂)/2, (y₁+y₂)/2). Der Mittelpunkt eines Liniensegments ist der Durchschnitt der x-Koordinaten und der Durchschnitt der y-Koordinaten.","fr":"M = ((x₁+x₂)/2, (y₁+y₂)/2). Le milieu d'un segment est la moyenne des abscisses et la moyenne des ordonnées.","tr":"M = ((x₁+x₂)/2, (y₁+y₂)/2). Bir doğru parçasının orta noktası, x-koordinatlarının ve y-koordinatlarının ortalamasıdır.","nl":"M = ((x₁+x₂)/2, (y₁+y₂)/2). Het middelpunt van een lijnstuk is het gemiddelde van de x-coördinaten en het gemiddelde van de y-coördinaten.","ru":"M = ((x₁+x₂)/2, (y₁+y₂)/2). Середина отрезка — это среднее значение x-координат и среднее значение y-координат.","zh":"M = ((x₁+x₂)/2, (y₁+y₂)/2)。线段的中点是 x 坐标的平均值和 y 坐标的平均值。","pt_BR":"M = ((x₁+x₂)/2, (y₁+y₂)/2). O ponto médio de um segmento é a média das coordenadas x e a média das coordenadas y.","pt_PT":"M = ((x₁+x₂)/2, (y₁+y₂)/2). O ponto médio de um segmento é a média das coordenadas x e a média das coordenadas y."}, sort_order: 16 },
  { id: 'dc-math-0017', deck_id: 'deck-math', front: 'Slope of a Line', back: 'm = (y₂-y₁)/(x₂-x₁) = rise/run. The slope measures steepness; positive slope rises left to right, negative slope falls left to right.', front_translations: {"es":"Inclinación de una reta","de":"Steigung einer Geraden","fr":"Pente d'une droite","tr":"Doğrunun Eğimi","nl":"Helling van een lijn","ru":"Наклон прямой","zh":"直线的斜率","pt_BR":"Inclinação de uma reta","pt_PT":"Declive de uma reta"}, back_translations: {"es":"m = (y₂-y₁)/(x₂-x₁) = subida/corrida. La inclinación mide a declividad; inclinación positiva sobe de la esquerda para a direita, negativa desce.","de":"m = (y₂-y₁)/(x₂-x₁) = Steigung/Lauf. Die Steigung misst die Steilheit; positive Steigung steigt von links nach rechts, negative Steigung fällt von links nach rechts.","fr":"m = (y₂-y₁)/(x₂-x₁) = montée/course. La pente mesure l'inclinaison ; une pente positive monte de gauche à droite, une pente négative descend.","tr":"m = (y₂-y₁)/(x₂-x₁) = yükseliş/yatay mesafe. Eğim dikligi ölçer; pozitif eğim soldan sağa yükselir, negatif eğim düşer.","nl":"m = (y₂-y₁)/(x₂-x₁) = stijging/loop. De helling meet de steilheid; positieve helling stijgt van links naar rechts, negatieve helling daalt.","ru":"m = (y₂-y₁)/(x₂-x₁) = подъём/горизонталь. Наклон измеряет крутизну; положительный наклон возрастает слева направо, отрицательный — убывает.","zh":"m = (y₂-y₁)/(x₂-x₁) = 纵向变化/横向变化。斜率衡量陡峭程度；正斜率从左向右上升，负斜率从左向右下降。","pt_BR":"m = (y₂-y₁)/(x₂-x₁) = subida/corrida. A inclinação mede a declividade; inclinação positiva sobe da esquerda para a direita, negativa desce.","pt_PT":"m = (y₂-y₁)/(x₂-x₁) = subida/corrida. O declive mede a inclinação; declive positivo sobe da esquerda para a direita, negativo desce."}, sort_order: 17 },
  { id: 'dc-math-0018', deck_id: 'deck-math', front: 'Slope-Intercept Form', back: 'y = mx + b. A linear equation where m is the slope and b is the y-intercept (the value of y when x = 0).', front_translations: {"es":"Forma declive-intercepto","de":"Normalform einer Geraden","fr":"Forme pente-ordonnée à l'origine","tr":"Eğim-Kesim Noktası Formu","nl":"Helling-snijpuntvorm","ru":"Уравнение прямой в форме y = mx + b","zh":"斜截式","pt_BR":"Forma declive-intercepto","pt_PT":"Forma declive-intercepto"}, back_translations: {"es":"y = mx + b. Una ecuación linear donde m es a inclinación y b es a interceptación en y (el valor de y cuando x = 0).","de":"y = mx + b. Eine lineare Gleichung, bei der m die Steigung und b der y-Achsenabschnitt ist (der Wert von y wenn x = 0).","fr":"y = mx + b. Une équation linéaire où m est la pente et b l'ordonnée à l'origine (la valeur de y quand x = 0).","tr":"y = mx + b. m eğim ve b, y-kesim noktası (x = 0 iken y'nin değeri) olmak üzere doğrusal bir denklem.","nl":"y = mx + b. Een lineaire vergelijking waarbij m de helling is en b het snijpunt met de y-as (de waarde van y als x = 0).","ru":"y = mx + b. Линейное уравнение, где m — наклон, а b — точка пересечения с осью y (значение y при x = 0).","zh":"y = mx + b。线性方程，其中 m 为斜率，b 为 y 轴截距（当 x = 0 时 y 的值）。","pt_BR":"y = mx + b. Uma equação linear onde m é a inclinação e b é a interceptação em y (o valor de y quando x = 0).","pt_PT":"y = mx + b. Uma equação linear onde m é o declive e b é a ordenada na origem (o valor de y quando x = 0)."}, sort_order: 18 },
  { id: 'dc-math-0019', deck_id: 'deck-math', front: 'Point-Slope Form', back: 'y - y₁ = m(x - x₁). Used to write the equation of a line given slope m and a point (x₁, y₁) on the line.', front_translations: {"es":"Forma punto-declive","de":"Punkt-Steigungs-Form","fr":"Forme point-pente","tr":"Nokta-Eğim Formu","nl":"Punt-hellingvorm","ru":"Уравнение прямой через точку и наклон","zh":"点斜式","pt_BR":"Forma ponto-declive","pt_PT":"Forma ponto-declive"}, back_translations: {"es":"y - y₁ = m(x - x₁). Usado para escrever a ecuación de una reta dato el declive m y un punto (x₁, y₁) en la reta.","de":"y - y₁ = m(x - x₁). Wird verwendet, um die Gleichung einer Geraden mit Steigung m und einem Punkt (x₁, y₁) zu schreiben.","fr":"y - y₁ = m(x - x₁). Utilisé pour écrire l'équation d'une droite connaissant la pente m et un point (x₁, y₁).","tr":"y - y₁ = m(x - x₁). Eğimi m olan ve (x₁, y₁) noktasından geçen bir doğrunun denklemini yazmak için kullanılır.","nl":"y - y₁ = m(x - x₁). Gebruikt om de vergelijking van een lijn te schrijven gegeven helling m en een punt (x₁, y₁) op de lijn.","ru":"y - y₁ = m(x - x₁). Используется для записи уравнения прямой по наклону m и точке (x₁, y₁) на прямой.","zh":"y - y₁ = m(x - x₁)。用于在已知斜率 m 和直线上一点 (x₁, y₁) 的情况下写出直线方程。","pt_BR":"y - y₁ = m(x - x₁). Usado para escrever a equação de uma reta dado o declive m e um ponto (x₁, y₁) na reta.","pt_PT":"y - y₁ = m(x - x₁). Usado para escrever a equação de uma reta dado o declive m e um ponto (x₁, y₁) na reta."}, sort_order: 19 },
  { id: 'dc-math-0020', deck_id: 'deck-math', front: 'Standard Form of a Line', back: 'Ax + By = C. A linear equation written with integer coefficients; useful for finding intercepts directly.', front_translations: {"es":"Forma padrão de una reta","de":"Standardform einer Geraden","fr":"Forme standard d'une droite","tr":"Doğrunun Standart Formu","nl":"Standaardvorm van een lijn","ru":"Стандартная форма уравнения прямой","zh":"直线的标准式","pt_BR":"Forma padrão de uma reta","pt_PT":"Forma padrão de uma reta"}, back_translations: {"es":"Ax + By = C. Una ecuación linear con coeficientes interos; útil para encontrar las interceptaciones directamente.","de":"Ax + By = C. Eine lineare Gleichung mit ganzzahligen Koeffizienten; nützlich zum direkten Finden der Achsenabschnitte.","fr":"Ax + By = C. Une équation linéaire écrite avec des coefficients entiers ; utile pour trouver directement les interceptes.","tr":"Ax + By = C. Tam sayı katsayılarla yazılmış doğrusal bir denklem; kesim noktalarını doğrudan bulmak için kullanışlıdır.","nl":"Ax + By = C. Een lineaire vergelijking met gehele getallen als coëfficiënten; handig voor het direct vinden van snijpunten.","ru":"Ax + By = C. Линейное уравнение с целочисленными коэффициентами; удобно для прямого нахождения точек пересечения.","zh":"Ax + By = C。以整数系数写成的线性方程；便于直接求截距。","pt_BR":"Ax + By = C. Uma equação linear com coeficientes inteiros; útil para encontrar as interceptações diretamente.","pt_PT":"Ax + By = C. Uma equação linear com coeficientes inteiros; útil para encontrar as interceptações directamente."}, sort_order: 20 },
  { id: 'dc-math-0021', deck_id: 'deck-math', front: 'Equation of a Circle', back: '(x - h)² + (y - k)² = r². A circle with center (h, k) and radius r; all points on the circle are distance r from the center.', front_translations: {"es":"Equación de un círculo","de":"Kreisgleichung","fr":"Équation d'un cercle","tr":"Daire Denklemi","nl":"Vergelijking van een cirkel","ru":"Уравнение окружности","zh":"圆的方程","pt_BR":"Equação de um círculo","pt_PT":"Equação de um círculo"}, back_translations: {"es":"(x - h)² + (y - k)² = r². Un círculo con centro (h, k) y raio r; todos los puntos en el círculo están a la distancia r del centro.","de":"(x - h)² + (y - k)² = r². Ein Kreis mit Mittelpunkt (h, k) und Radius r; alle Punkte auf dem Kreis haben den Abstand r vom Mittelpunkt.","fr":"(x - h)² + (y - k)² = r². Un cercle de centre (h, k) et de rayon r ; tous les points du cercle sont à distance r du centre.","tr":"(x - h)² + (y - k)² = r². Merkezi (h, k) ve yarıçapı r olan bir daire; daire üzerindeki tüm noktalar merkezden r uzaklıktadır.","nl":"(x - h)² + (y - k)² = r². Een cirkel met middelpunt (h, k) en straal r; alle punten op de cirkel liggen op afstand r van het middelpunt.","ru":"(x - h)² + (y - k)² = r². Окружность с центром (h, k) и радиусом r; все точки на окружности находятся на расстоянии r от центра.","zh":"(x - h)² + (y - k)² = r²。圆心为 (h, k)、半径为 r 的圆；圆上所有点到圆心的距离均为 r。","pt_BR":"(x - h)² + (y - k)² = r². Um círculo com centro (h, k) e raio r; todos os pontos no círculo estão à distância r do centro.","pt_PT":"(x - h)² + (y - k)² = r². Um círculo com centro (h, k) e raio r; todos os pontos no círculo estão à distância r do centro."}, sort_order: 21 },
  { id: 'dc-math-0022', deck_id: 'deck-math', front: 'Exponent Rule: Product', back: 'aᵐ × aⁿ = aᵐ⁺ⁿ. When multiplying powers with the same base, add the exponents.', front_translations: {"es":"Regra de los exponentes: producto","de":"Potenzregel: Produkt","fr":"Règle des exposants : produit","tr":"Üs Kuralı: Çarpım","nl":"Machtsverheffingsregel: product","ru":"Правило степеней: произведение","zh":"指数法则：积的法则","pt_BR":"Regra dos expoentes: produto","pt_PT":"Regra dos expoentes: produto"}, back_translations: {"es":"aᵐ × aⁿ = aᵐ⁺ⁿ. Ao multiplicar potencias con a misma base, somam-se los exponentes.","de":"aᵐ × aⁿ = aᵐ⁺ⁿ. Beim Multiplizieren von Potenzen mit derselben Basis werden die Exponenten addiert.","fr":"aᵐ × aⁿ = aᵐ⁺ⁿ. Pour multiplier des puissances de même base, on additionne les exposants.","tr":"aᵐ × aⁿ = aᵐ⁺ⁿ. Aynı tabanlı kuvvetler çarpılırken üsler toplanır.","nl":"aᵐ × aⁿ = aᵐ⁺ⁿ. Bij het vermenigvuldigen van machten met dezelfde basis tel je de exponenten op.","ru":"aᵐ × aⁿ = aᵐ⁺ⁿ. При умножении степеней с одинаковым основанием показатели складываются.","zh":"aᵐ × aⁿ = aᵐ⁺ⁿ。将同底数的幂相乘时，指数相加。","pt_BR":"aᵐ × aⁿ = aᵐ⁺ⁿ. Ao multiplicar potências com a mesma base, somam-se os expoentes.","pt_PT":"aᵐ × aⁿ = aᵐ⁺ⁿ. Ao multiplicar potências com a mesma base, somam-se os expoentes."}, sort_order: 22 },
  { id: 'dc-math-0023', deck_id: 'deck-math', front: 'Exponent Rule: Quotient', back: 'aᵐ / aⁿ = aᵐ⁻ⁿ. When dividing powers with the same base, subtract the exponents.', front_translations: {"es":"Regra de los exponentes: quociente","de":"Potenzregel: Quotient","fr":"Règle des exposants : quotient","tr":"Üs Kuralı: Bölüm","nl":"Machtsverheffingsregel: quotiënt","ru":"Правило степеней: частное","zh":"指数法则：商的法则","pt_BR":"Regra dos expoentes: quociente","pt_PT":"Regra dos expoentes: quociente"}, back_translations: {"es":"aᵐ / aⁿ = aᵐ⁻ⁿ. Ao dividir potencias con a misma base, subtraem-se los exponentes.","de":"aᵐ / aⁿ = aᵐ⁻ⁿ. Beim Dividieren von Potenzen mit derselben Basis werden die Exponenten subtrahiert.","fr":"aᵐ / aⁿ = aᵐ⁻ⁿ. Pour diviser des puissances de même base, on soustrait les exposants.","tr":"aᵐ / aⁿ = aᵐ⁻ⁿ. Aynı tabanlı kuvvetler bölünürken üsler çıkarılır.","nl":"aᵐ / aⁿ = aᵐ⁻ⁿ. Bij het delen van machten met dezelfde basis trek je de exponenten van elkaar af.","ru":"aᵐ / aⁿ = aᵐ⁻ⁿ. При делении степеней с одинаковым основанием показатели вычитаются.","zh":"aᵐ / aⁿ = aᵐ⁻ⁿ。将同底数的幂相除时，指数相减。","pt_BR":"aᵐ / aⁿ = aᵐ⁻ⁿ. Ao dividir potências com a mesma base, subtraem-se os expoentes.","pt_PT":"aᵐ / aⁿ = aᵐ⁻ⁿ. Ao dividir potências com a mesma base, subtraem-se os expoentes."}, sort_order: 23 },
  { id: 'dc-math-0024', deck_id: 'deck-math', front: 'Exponent Rule: Power of a Power', back: '(aᵐ)ⁿ = aᵐⁿ. When raising a power to a power, multiply the exponents.', front_translations: {"es":"Regra de los exponentes: potencia de una potencia","de":"Potenzregel: Potenz einer Potenz","fr":"Règle des exposants : puissance d'une puissance","tr":"Üs Kuralı: Üssün Üssü","nl":"Machtsverheffingsregel: macht van een macht","ru":"Правило степеней: степень степени","zh":"指数法则：幂的幂","pt_BR":"Regra dos expoentes: potência de uma potência","pt_PT":"Regra dos expoentes: potência de uma potência"}, back_translations: {"es":"(aᵐ)ⁿ = aᵐⁿ. Ao elevar una potencia a outra potencia, multiplicam-se los exponentes.","de":"(aᵐ)ⁿ = aᵐⁿ. Beim Potenzieren einer Potenz werden die Exponenten multipliziert.","fr":"(aᵐ)ⁿ = aᵐⁿ. Pour élever une puissance à une autre puissance, on multiplie les exposants.","tr":"(aᵐ)ⁿ = aᵐⁿ. Bir kuvveti kuvvete yükseltirken üsler çarpılır.","nl":"(aᵐ)ⁿ = aᵐⁿ. Bij het verheffen van een macht tot een macht, vermenigvuldig je de exponenten.","ru":"(aᵐ)ⁿ = aᵐⁿ. При возведении степени в степень показатели перемножаются.","zh":"(aᵐ)ⁿ = aᵐⁿ。将一个幂再次求幂时，指数相乘。","pt_BR":"(aᵐ)ⁿ = aᵐⁿ. Ao elevar uma potência a outra potência, multiplicam-se os expoentes.","pt_PT":"(aᵐ)ⁿ = aᵐⁿ. Ao elevar uma potência a outra potência, multiplicam-se os expoentes."}, sort_order: 24 },
  { id: 'dc-math-0025', deck_id: 'deck-math', front: 'Zero Exponent Rule', back: 'a⁰ = 1 (for any a ≠ 0). Any nonzero number raised to the power of zero equals 1; follows from the quotient rule.', front_translations: {"es":"Regra del exponente zero","de":"Nullexponentenregel","fr":"Règle de l'exposant zéro","tr":"Sıfır Üs Kuralı","nl":"Nulexponentregel","ru":"Правило нулевого показателя","zh":"零指数法则","pt_BR":"Regra do expoente zero","pt_PT":"Regra do expoente zero"}, back_translations: {"es":"a⁰ = 1 (para cualquier a ≠ 0). Qualquer número no nulo elevado a la potencia zero es igual a 1; decorre de la regra del quociente.","de":"a⁰ = 1 (für jedes a ≠ 0). Jede von null verschiedene Zahl hoch null ergibt 1; folgt aus der Quotientenregel.","fr":"a⁰ = 1 (pour tout a ≠ 0). Tout nombre non nul élevé à la puissance zéro vaut 1 ; découle de la règle du quotient.","tr":"a⁰ = 1 (herhangi bir a ≠ 0 için). Sıfırdan farklı herhangi bir sayının sıfıra yükseltilmesi 1'e eşittir; bölüm kuralından çıkar.","nl":"a⁰ = 1 (voor elke a ≠ 0). Elk getal niet gelijk aan nul tot de macht nul is gelijk aan 1; volgt uit de quotiëntregel.","ru":"a⁰ = 1 (для любого a ≠ 0). Любое ненулевое число в степени нуль равно 1; следует из правила частного.","zh":"a⁰ = 1（对任意 a ≠ 0）。任何非零数的零次方等于 1；由商的法则推导而来。","pt_BR":"a⁰ = 1 (para qualquer a ≠ 0). Qualquer número não nulo elevado à potência zero é igual a 1; decorre da regra do quociente.","pt_PT":"a⁰ = 1 (para qualquer a ≠ 0). Qualquer número não nulo elevado à potência zero é igual a 1; decorre da regra do quociente."}, sort_order: 25 },
  { id: 'dc-math-0026', deck_id: 'deck-math', front: 'Negative Exponent Rule', back: 'a⁻ⁿ = 1/aⁿ. A negative exponent means the reciprocal of the base raised to the positive exponent.', front_translations: {"es":"Regra de los exponentes negativos","de":"Negative Exponentenregel","fr":"Règle des exposants négatifs","tr":"Negatif Üs Kuralı","nl":"Negatieve exponentregel","ru":"Правило отрицательного показателя","zh":"负指数法则","pt_BR":"Regra dos expoentes negativos","pt_PT":"Regra dos expoentes negativos"}, back_translations: {"es":"a⁻ⁿ = 1/aⁿ. Un exponente negativo representa el recíproco de la base elevada al exponente positivo.","de":"a⁻ⁿ = 1/aⁿ. Ein negativer Exponent bedeutet den Kehrwert der Basis hoch dem positiven Exponenten.","fr":"a⁻ⁿ = 1/aⁿ. Un exposant négatif représente l'inverse de la base élevée à l'exposant positif.","tr":"a⁻ⁿ = 1/aⁿ. Negatif bir üs, tabanın pozitif üssüne yükseltilmiş tersini ifade eder.","nl":"a⁻ⁿ = 1/aⁿ. Een negatieve exponent betekent de omgekeerde waarde van de basis tot de positieve exponent.","ru":"a⁻ⁿ = 1/aⁿ. Отрицательный показатель означает обратную величину основания, возведённого в положительную степень.","zh":"a⁻ⁿ = 1/aⁿ。负指数表示底数的正指数次幂的倒数。","pt_BR":"a⁻ⁿ = 1/aⁿ. Um expoente negativo representa o recíproco da base elevada ao expoente positivo.","pt_PT":"a⁻ⁿ = 1/aⁿ. Um expoente negativo representa o recíproco da base elevada ao expoente positivo."}, sort_order: 26 },
  { id: 'dc-math-0027', deck_id: 'deck-math', front: 'Logarithm Definition', back: 'If bˣ = y, then log_b(y) = x. A logarithm is the exponent to which a base b must be raised to produce y. log base 10 is the common log; log base e is the natural log (ln).', front_translations: {"es":"Definición de logaritmo","de":"Logarithmusdefinition","fr":"Définition du logarithme","tr":"Logaritma Tanımı","nl":"Definitie van logaritme","ru":"Определение логарифма","zh":"对数的定义","pt_BR":"Definição de logaritmo","pt_PT":"Definição de logaritmo"}, back_translations: {"es":"Se bˣ = y, entonces log_b(y) = x. Un logaritmo es el exponente al qual a base b deve ser elevada para produzir y. Log base 10 es el logaritmo comum; base y es el logaritmo natural (ln).","de":"Wenn bˣ = y, dann log_b(y) = x. Ein Logarithmus ist der Exponent, auf den die Basis b erhöht werden muss, um y zu erhalten. Logarithmus zur Basis 10 ist der dekadische Logarithmus; Basis e ist der natürliche Logarithmus (ln).","fr":"Si bˣ = y, alors log_b(y) = x. Un logarithme est l'exposant auquel la base b doit être élevée pour produire y. Le log en base 10 est le logarithme commun ; en base e, c'est le logarithme naturel (ln).","tr":"Eğer bˣ = y ise, log_b(y) = x. Logaritma, b tabanının y'yi üretmek için yükseltilmesi gereken üstür. 10 tabanlı log, genel logaritmadır; e tabanlı log, doğal logaritmadır (ln).","nl":"Als bˣ = y, dan log_b(y) = x. Een logaritme is de exponent waartoe een grondtal b verheven moet worden om y te produceren. Log grondtal 10 is de gewone log; grondtal e is de natuurlijke log (ln).","ru":"Если bˣ = y, то log_b(y) = x. Логарифм — это показатель степени, в которую нужно возвести основание b, чтобы получить y. Логарифм по основанию 10 — десятичный; по основанию e — натуральный (ln).","zh":"若 bˣ = y，则 log_b(y) = x。对数是以 b 为底、产生 y 所需的指数。以 10 为底的对数是常用对数；以 e 为底的是自然对数（ln）。","pt_BR":"Se bˣ = y, então log_b(y) = x. Um logaritmo é o expoente ao qual a base b deve ser elevada para produzir y. Log base 10 é o logaritmo comum; base e é o logaritmo natural (ln).","pt_PT":"Se bˣ = y, então log_b(y) = x. Um logaritmo é o expoente ao qual a base b deve ser elevada para produzir y. Log base 10 é o logaritmo comum; base e é o logaritmo natural (ln)."}, sort_order: 27 },
  { id: 'dc-math-0028', deck_id: 'deck-math', front: 'Logarithm Product Rule', back: 'log_b(xy) = log_b(x) + log_b(y). The log of a product equals the sum of the logs; mirrors the exponent product rule.', front_translations: {"es":"Regra del producto del logaritmo","de":"Logarithmus Produktregel","fr":"Règle du produit des logarithmes","tr":"Logaritma Çarpım Kuralı","nl":"Logaritme productregel","ru":"Правило логарифма произведения","zh":"对数积的法则","pt_BR":"Regra do produto do logaritmo","pt_PT":"Regra do produto do logaritmo"}, back_translations: {"es":"log_b(xy) = log_b(x) + log_b(y). El logaritmo de un producto es a suma de los logaritmos; espelha a regra del producto de los exponentes.","de":"log_b(xy) = log_b(x) + log_b(y). Der Logarithmus eines Produkts ist gleich der Summe der Logarithmen; spiegelt die Potenz-Produktregel wider.","fr":"log_b(xy) = log_b(x) + log_b(y). Le logarithme d'un produit est la somme des logarithmes ; miroir de la règle du produit des exposants.","tr":"log_b(xy) = log_b(x) + log_b(y). Bir çarpımın logaritması, logaritmaların toplamına eşittir; üs çarpım kuralını yansıtır.","nl":"log_b(xy) = log_b(x) + log_b(y). De logaritme van een product is de som van de logaritmen; weerspiegelt de machtsproductregel.","ru":"log_b(xy) = log_b(x) + log_b(y). Логарифм произведения равен сумме логарифмов; аналог правила степеней для произведения.","zh":"log_b(xy) = log_b(x) + log_b(y)。积的对数等于各因子对数之和；与指数积的法则相对应。","pt_BR":"log_b(xy) = log_b(x) + log_b(y). O logaritmo de um produto é a soma dos logaritmos; espelha a regra do produto dos expoentes.","pt_PT":"log_b(xy) = log_b(x) + log_b(y). O logaritmo de um produto é a soma dos logaritmos; espelha a regra do produto dos expoentes."}, sort_order: 28 },
  { id: 'dc-math-0029', deck_id: 'deck-math', front: 'Logarithm Quotient Rule', back: 'log_b(x/y) = log_b(x) - log_b(y). The log of a quotient equals the difference of the logs.', front_translations: {"es":"Regra del quociente del logaritmo","de":"Logarithmus Quotientenregel","fr":"Règle du quotient des logarithmes","tr":"Logaritma Bölüm Kuralı","nl":"Logaritme quotiëntregel","ru":"Правило логарифма частного","zh":"对数商的法则","pt_BR":"Regra do quociente do logaritmo","pt_PT":"Regra do quociente do logaritmo"}, back_translations: {"es":"log_b(x/y) = log_b(x) - log_b(y). El logaritmo de un quociente es a diferencia de los logaritmos.","de":"log_b(x/y) = log_b(x) - log_b(y). Der Logarithmus eines Quotienten ist gleich der Differenz der Logarithmen.","fr":"log_b(x/y) = log_b(x) - log_b(y). Le logarithme d'un quotient est la différence des logarithmes.","tr":"log_b(x/y) = log_b(x) - log_b(y). Bir bölümün logaritması, logaritmaların farkına eşittir.","nl":"log_b(x/y) = log_b(x) - log_b(y). De logaritme van een quotiënt is het verschil van de logaritmen.","ru":"log_b(x/y) = log_b(x) - log_b(y). Логарифм частного равен разности логарифмов.","zh":"log_b(x/y) = log_b(x) - log_b(y)。商的对数等于各对数之差。","pt_BR":"log_b(x/y) = log_b(x) - log_b(y). O logaritmo de um quociente é a diferença dos logaritmos.","pt_PT":"log_b(x/y) = log_b(x) - log_b(y). O logaritmo de um quociente é a diferença dos logaritmos."}, sort_order: 29 },
  { id: 'dc-math-0030', deck_id: 'deck-math', front: 'Logarithm Power Rule', back: 'log_b(xⁿ) = n × log_b(x). The log of a power equals the exponent multiplied by the log of the base.', front_translations: {"es":"Regra de la potencia del logaritmo","de":"Logarithmus Potenzregel","fr":"Règle de la puissance des logarithmes","tr":"Logaritma Kuvvet Kuralı","nl":"Logaritme machtsregel","ru":"Правило логарифма степени","zh":"对数幂的法则","pt_BR":"Regra da potência do logaritmo","pt_PT":"Regra da potência do logaritmo"}, back_translations: {"es":"log_b(xⁿ) = n × log_b(x). El logaritmo de una potencia es el exponente multiplicado por el logaritmo de la base.","de":"log_b(xⁿ) = n × log_b(x). Der Logarithmus einer Potenz ist gleich dem Exponenten multipliziert mit dem Logarithmus der Basis.","fr":"log_b(xⁿ) = n × log_b(x). Le logarithme d'une puissance est l'exposant multiplié par le logarithme de la base.","tr":"log_b(xⁿ) = n × log_b(x). Bir kuvvetin logaritması, üs çarpı tabanın logaritmasına eşittir.","nl":"log_b(xⁿ) = n × log_b(x). De logaritme van een macht is de exponent vermenigvuldigd met de logaritme van de grondtal.","ru":"log_b(xⁿ) = n × log_b(x). Логарифм степени равен показателю, умноженному на логарифм основания.","zh":"log_b(xⁿ) = n × log_b(x)。幂的对数等于指数乘以底数的对数。","pt_BR":"log_b(xⁿ) = n × log_b(x). O logaritmo de uma potência é o expoente multiplicado pelo logaritmo da base.","pt_PT":"log_b(xⁿ) = n × log_b(x). O logaritmo de uma potência é o expoente multiplicado pelo logaritmo da base."}, sort_order: 30 },
  { id: 'dc-math-0031', deck_id: 'deck-math', front: 'Change of Base Formula', back: 'log_b(x) = log(x)/log(b) = ln(x)/ln(b). Allows converting logarithms to any base using common or natural logs.', front_translations: {"es":"Fórmula de cambio de base","de":"Basiswechselformel","fr":"Formule de changement de base","tr":"Taban Değiştirme Formülü","nl":"Basiswisselformule","ru":"Формула перехода к другому основанию","zh":"换底公式","pt_BR":"Fórmula de mudança de base","pt_PT":"Fórmula de mudança de base"}, back_translations: {"es":"log_b(x) = log(x)/log(b) = ln(x)/ln(b). Permite converter logaritmos para cualquier base usando logaritmos comuns o naturais.","de":"log_b(x) = log(x)/log(b) = ln(x)/ln(b). Ermöglicht die Umrechnung von Logarithmen in jede Basis mit dekadischen oder natürlichen Logarithmen.","fr":"log_b(x) = log(x)/log(b) = ln(x)/ln(b). Permet de convertir des logarithmes en n'importe quelle base à l'aide de logarithmes communs ou naturels.","tr":"log_b(x) = log(x)/log(b) = ln(x)/ln(b). Ortak veya doğal logaritmaları kullanarak logaritmaları herhangi bir tabana dönüştürmeye olanak tanır.","nl":"log_b(x) = log(x)/log(b) = ln(x)/ln(b). Maakt het mogelijk logaritmen naar elke basis te converteren met gewone of natuurlijke logaritmen.","ru":"log_b(x) = log(x)/log(b) = ln(x)/ln(b). Позволяет переводить логарифмы в любое основание с помощью десятичных или натуральных логарифмов.","zh":"log_b(x) = log(x)/log(b) = ln(x)/ln(b)。使用常用对数或自然对数将对数换算为任意底数。","pt_BR":"log_b(x) = log(x)/log(b) = ln(x)/ln(b). Permite converter logaritmos para qualquer base usando logaritmos comuns ou naturais.","pt_PT":"log_b(x) = log(x)/log(b) = ln(x)/ln(b). Permite converter logaritmos para qualquer base usando logaritmos comuns ou naturais."}, sort_order: 31 },
  { id: 'dc-math-0032', deck_id: 'deck-math', front: 'Natural Exponential Function', back: 'f(x) = eˣ where e ≈ 2.71828. The derivative of eˣ is itself (eˣ); it is the unique function equal to its own derivative.', front_translations: {"es":"Función exponencial natural","de":"Natürliche Exponentialfunktion","fr":"Fonction exponentielle naturelle","tr":"Doğal Üstel Fonksiyon","nl":"Natuurlijke exponentiële functie","ru":"Натуральная показательная функция","zh":"自然指数函数","pt_BR":"Função exponencial natural","pt_PT":"Função exponencial natural"}, back_translations: {"es":"f(x) = yˣ donde y ≈ 2,71828. La derivada de yˣ es ela misma (yˣ); es a función única igual a la su propia derivada.","de":"f(x) = eˣ mit e ≈ 2,71828. Die Ableitung von eˣ ist sie selbst (eˣ); sie ist die einzige Funktion, die ihrer eigenen Ableitung entspricht.","fr":"f(x) = eˣ avec e ≈ 2,71828. La dérivée de eˣ est elle-même (eˣ) ; c'est la seule fonction égale à sa propre dérivée.","tr":"f(x) = eˣ, burada e ≈ 2,71828. eˣ'in türevi kendisidir (eˣ); kendi türevine eşit olan tek fonksiyondur.","nl":"f(x) = eˣ waarbij e ≈ 2,71828. De afgeleide van eˣ is zichzelf (eˣ); het is de unieke functie die gelijk is aan zijn eigen afgeleide.","ru":"f(x) = eˣ, где e ≈ 2,71828. Производная eˣ равна самой функции (eˣ); это единственная функция, равная своей производной.","zh":"f(x) = eˣ，其中 e ≈ 2.71828。eˣ 的导数是其本身（eˣ）；它是唯一等于自身导数的函数。","pt_BR":"f(x) = eˣ onde e ≈ 2,71828. A derivada de eˣ é ela mesma (eˣ); é a função única igual à sua própria derivada.","pt_PT":"f(x) = eˣ onde e ≈ 2,71828. A derivada de eˣ é ela mesma (eˣ); é a função única igual à sua própria derivada."}, sort_order: 32 },
  { id: 'dc-math-0033', deck_id: 'deck-math', front: 'Sine (sin)', back: 'In a right triangle: sin(θ) = opposite/hypotenuse. On the unit circle, sin(θ) is the y-coordinate of the point at angle θ.', front_translations: {"es":"Seno (sin)","de":"Sinus (sin)","fr":"Sinus (sin)","tr":"Sinüs (sin)","nl":"Sinus (sin)","ru":"Синус (sin)","zh":"正弦（sin）","pt_BR":"Seno (sin)","pt_PT":"Seno (sin)"}, back_translations: {"es":"Num triángulo rectángulo: sin(θ) = oposto/hipotenusa. No círculo unitário, sin(θ) es a coordenada y del punto en el ángulo θ.","de":"In einem rechtwinkligen Dreieck: sin(θ) = Gegenkathete/Hypotenuse. Im Einheitskreis ist sin(θ) die y-Koordinate des Punktes beim Winkel θ.","fr":"Dans un triangle rectangle : sin(θ) = opposé/hypoténuse. Sur le cercle unité, sin(θ) est l'ordonnée du point à l'angle θ.","tr":"Dik üçgende: sin(θ) = karşı kenar/hipotenüs. Birim çemberde sin(θ), θ açısındaki noktanın y-koordinatıdır.","nl":"In een rechthoekige driehoek: sin(θ) = overstaande/hypotenusa. Op de eenheidscirkel is sin(θ) de y-coördinaat van het punt bij hoek θ.","ru":"В прямоугольном треугольнике: sin(θ) = противолежащий катет/гипотенуза. На единичной окружности sin(θ) — y-координата точки при угле θ.","zh":"在直角三角形中：sin(θ) = 对边/斜边。在单位圆上，sin(θ) 是角度 θ 处点的 y 坐标。","pt_BR":"Num triângulo retângulo: sin(θ) = oposto/hipotenusa. No círculo unitário, sin(θ) é a coordenada y do ponto no ângulo θ.","pt_PT":"Num triângulo retângulo: sin(θ) = oposto/hipotenusa. No círculo unitário, sin(θ) é a coordenada y do ponto no ângulo θ."}, sort_order: 33 },
  { id: 'dc-math-0034', deck_id: 'deck-math', front: 'Cosine (cos)', back: 'In a right triangle: cos(θ) = adjacent/hypotenuse. On the unit circle, cos(θ) is the x-coordinate of the point at angle θ.', front_translations: {"es":"Cosseno (cos)","de":"Kosinus (cos)","fr":"Cosinus (cos)","tr":"Kosinüs (cos)","nl":"Cosinus (cos)","ru":"Косинус (cos)","zh":"余弦（cos）","pt_BR":"Cosseno (cos)","pt_PT":"Cosseno (cos)"}, back_translations: {"es":"Num triángulo rectángulo: cos(θ) = adjacente/hipotenusa. No círculo unitário, cos(θ) es a coordenada x del punto en el ángulo θ.","de":"In einem rechtwinkligen Dreieck: cos(θ) = Ankathete/Hypotenuse. Im Einheitskreis ist cos(θ) die x-Koordinate des Punktes beim Winkel θ.","fr":"Dans un triangle rectangle : cos(θ) = adjacent/hypoténuse. Sur le cercle unité, cos(θ) est l'abscisse du point à l'angle θ.","tr":"Dik üçgende: cos(θ) = komşu kenar/hipotenüs. Birim çemberde cos(θ), θ açısındaki noktanın x-koordinatıdır.","nl":"In een rechthoekige driehoek: cos(θ) = aanliggende/hypotenusa. Op de eenheidscirkel is cos(θ) de x-coördinaat van het punt bij hoek θ.","ru":"В прямоугольном треугольнике: cos(θ) = прилежащий катет/гипотенуза. На единичной окружности cos(θ) — x-координата точки при угле θ.","zh":"在直角三角形中：cos(θ) = 邻边/斜边。在单位圆上，cos(θ) 是角度 θ 处点的 x 坐标。","pt_BR":"Num triângulo retângulo: cos(θ) = adjacente/hipotenusa. No círculo unitário, cos(θ) é a coordenada x do ponto no ângulo θ.","pt_PT":"Num triângulo retângulo: cos(θ) = adjacente/hipotenusa. No círculo unitário, cos(θ) é a coordenada x do ponto no ângulo θ."}, sort_order: 34 },
  { id: 'dc-math-0035', deck_id: 'deck-math', front: 'Tangent (tan)', back: 'tan(θ) = opposite/adjacent = sin(θ)/cos(θ). Represents the slope of the angle on the unit circle; undefined when cos(θ) = 0.', front_translations: {"es":"Tangente (tan)","de":"Tangens (tan)","fr":"Tangente (tan)","tr":"Tanjant (tan)","nl":"Tangens (tan)","ru":"Тангенс (tan)","zh":"正切（tan）","pt_BR":"Tangente (tan)","pt_PT":"Tangente (tan)"}, back_translations: {"es":"tan(θ) = oposto/adjacente = sin(θ)/cos(θ). Representa a inclinación del ángulo en el círculo unitário; indefinido cuando cos(θ) = 0.","de":"tan(θ) = Gegenkathete/Ankathete = sin(θ)/cos(θ). Stellt die Steigung des Winkels im Einheitskreis dar; undefiniert, wenn cos(θ) = 0.","fr":"tan(θ) = opposé/adjacent = sin(θ)/cos(θ). Représente la pente de l'angle sur le cercle unité ; indéfini quand cos(θ) = 0.","tr":"tan(θ) = karşı kenar/komşu kenar = sin(θ)/cos(θ). Birim çemberdeki açının eğimini temsil eder; cos(θ) = 0 olduğunda tanımsızdır.","nl":"tan(θ) = overstaande/aanliggende = sin(θ)/cos(θ). Vertegenwoordigt de helling van de hoek op de eenheidscirkel; ongedefinieerd wanneer cos(θ) = 0.","ru":"tan(θ) = противолежащий/прилежащий = sin(θ)/cos(θ). Представляет наклон угла на единичной окружности; не определён при cos(θ) = 0.","zh":"tan(θ) = 对边/邻边 = sin(θ)/cos(θ)。表示单位圆上角度的斜率；当 cos(θ) = 0 时无定义。","pt_BR":"tan(θ) = oposto/adjacente = sin(θ)/cos(θ). Representa a inclinação do ângulo no círculo unitário; indefinido quando cos(θ) = 0.","pt_PT":"tan(θ) = oposto/adjacente = sin(θ)/cos(θ). Representa o declive do ângulo no círculo unitário; indefinido quando cos(θ) = 0."}, sort_order: 35 },
  { id: 'dc-math-0036', deck_id: 'deck-math', front: 'SOH-CAH-TOA', back: 'A mnemonic for right triangle trigonometry: Sine = Opposite/Hypotenuse, Cosine = Adjacent/Hypotenuse, Tangent = Opposite/Adjacent.', front_translations: {"es":"SOH-CAH-TOA","de":"SOH-CAH-TOA","fr":"SOH-CAH-TOA","tr":"SOH-CAH-TOA","nl":"SOH-CAH-TOA","ru":"SOH-CAH-TOA","zh":"SOH-CAH-TOA","pt_BR":"SOH-CAH-TOA","pt_PT":"SOH-CAH-TOA"}, back_translations: {"es":"Un mnemonico para trigonometria en triángulo rectángulo: Seno = Oposto/Hipotenusa, Cosseno = Adjacente/Hipotenusa, Tangente = Oposto/Adjacente.","de":"Eine Gedächtnisstütze für rechtwinklige Trigonometrie: Sinus = Gegenkathete/Hypotenuse, Kosinus = Ankathete/Hypotenuse, Tangens = Gegenkathete/Ankathete.","fr":"Un moyen mnémotechnique pour la trigonométrie dans le triangle rectangle : Sinus = Opposé/Hypoténuse, Cosinus = Adjacent/Hypoténuse, Tangente = Opposé/Adjacent.","tr":"Dik üçgen trigonometrisi için bir anımsatıcı: Sinüs = Karşı/Hipotenüs, Kosinüs = Komşu/Hipotenüs, Tanjant = Karşı/Komşu.","nl":"Een geheugensteuntje voor rechthoekige driehoeksmeetkunde: Sinus = Overstaande/Hypotenusa, Cosinus = Aanliggende/Hypotenusa, Tangens = Overstaande/Aanliggende.","ru":"Мнемоника для тригонометрии прямоугольного треугольника: Синус = Противолежащий/Гипотенуза, Косинус = Прилежащий/Гипотенуза, Тангенс = Противолежащий/Прилежащий.","zh":"直角三角形三角函数的记忆口诀：正弦 = 对边/斜边，余弦 = 邻边/斜边，正切 = 对边/邻边。","pt_BR":"Um mnemônico para trigonometria em triângulo retângulo: Seno = Oposto/Hipotenusa, Cosseno = Adjacente/Hipotenusa, Tangente = Oposto/Adjacente.","pt_PT":"Um mnemónico para trigonometria em triângulo rectângulo: Seno = Oposto/Hipotenusa, Cosseno = Adjacente/Hipotenusa, Tangente = Oposto/Adjacente."}, sort_order: 36 },
  { id: 'dc-math-0037', deck_id: 'deck-math', front: 'Pythagorean Identity', back: 'sin²(θ) + cos²(θ) = 1. The fundamental trigonometric identity derived from the Pythagorean theorem applied to the unit circle.', front_translations: {"es":"Identidad pitagórica","de":"Trigonometrischer Pythagoreischer Satz","fr":"Identité pythagoricienne","tr":"Pisagoryen Özdeşlik","nl":"Pythagoreaanse identiteit","ru":"Основное тригонометрическое тождество","zh":"毕达哥拉斯恒等式","pt_BR":"Identidade pitagórica","pt_PT":"Identidade pitagórica"}, back_translations: {"es":"sin²(θ) + cos²(θ) = 1. La identidad trigonométrica fundamental derivada del teorema de Pitágoras aplicado al círculo unitário.","de":"sin²(θ) + cos²(θ) = 1. Das grundlegende trigonometrische Identität, abgeleitet aus dem Satz des Pythagoras angewendet auf den Einheitskreis.","fr":"sin²(θ) + cos²(θ) = 1. L'identité trigonométrique fondamentale dérivée du théorème de Pythagore appliqué au cercle unité.","tr":"sin²(θ) + cos²(θ) = 1. Birim çembere uygulanan Pisagor teoreminden türetilen temel trigonometrik özdeşlik.","nl":"sin²(θ) + cos²(θ) = 1. De fundamentele trigonometrische identiteit afgeleid van de stelling van Pythagoras toegepast op de eenheidscirkel.","ru":"sin²(θ) + cos²(θ) = 1. Основное тригонометрическое тождество, выведенное из теоремы Пифагора применительно к единичной окружности.","zh":"sin²(θ) + cos²(θ) = 1。将勾股定理应用于单位圆所得的基本三角恒等式。","pt_BR":"sin²(θ) + cos²(θ) = 1. A identidade trigonométrica fundamental derivada do teorema de Pitágoras aplicado ao círculo unitário.","pt_PT":"sin²(θ) + cos²(θ) = 1. A identidade trigonométrica fundamental derivada do teorema de Pitágoras aplicado ao círculo unitário."}, sort_order: 37 },
  { id: 'dc-math-0038', deck_id: 'deck-math', front: 'Other Pythagorean Identities', back: '1 + tan²(θ) = sec²(θ) and 1 + cot²(θ) = csc²(θ). Derived by dividing sin²θ + cos²θ = 1 by cos²θ or sin²θ respectively.', front_translations: {"es":"Outras identidades pitagóricas","de":"Weitere pythagoreische Identitäten","fr":"Autres identités pythagoriciennes","tr":"Diğer Pisagoryen Özdeşlikler","nl":"Andere Pythagoreaanse identiteiten","ru":"Другие пифагоровы тождества","zh":"其他毕达哥拉斯恒等式","pt_BR":"Outras identidades pitagóricas","pt_PT":"Outras identidades pitagóricas"}, back_translations: {"es":"1 + tan²(θ) = sec²(θ) y 1 + cot²(θ) = csc²(θ). Derivadas dividindo sin²θ + cos²θ = 1 por cos²θ o sin²θ respectivamente.","de":"1 + tan²(θ) = sec²(θ) und 1 + cot²(θ) = csc²(θ). Abgeleitet durch Division von sin²θ + cos²θ = 1 durch cos²θ bzw. sin²θ.","fr":"1 + tan²(θ) = sec²(θ) et 1 + cot²(θ) = csc²(θ). Obtenues en divisant sin²θ + cos²θ = 1 par cos²θ ou sin²θ respectivement.","tr":"1 + tan²(θ) = sec²(θ) ve 1 + cot²(θ) = csc²(θ). sin²θ + cos²θ = 1'in sırasıyla cos²θ veya sin²θ'ya bölünmesiyle elde edilir.","nl":"1 + tan²(θ) = sec²(θ) en 1 + cot²(θ) = csc²(θ). Afgeleid door sin²θ + cos²θ = 1 te delen door respectievelijk cos²θ of sin²θ.","ru":"1 + tan²(θ) = sec²(θ) и 1 + cot²(θ) = csc²(θ). Получены делением sin²θ + cos²θ = 1 на cos²θ или sin²θ соответственно.","zh":"1 + tan²(θ) = sec²(θ) 和 1 + cot²(θ) = csc²(θ)。分别由 sin²θ + cos²θ = 1 除以 cos²θ 或 sin²θ 推导而来。","pt_BR":"1 + tan²(θ) = sec²(θ) e 1 + cot²(θ) = csc²(θ). Derivadas dividindo sin²θ + cos²θ = 1 por cos²θ ou sin²θ respectivamente.","pt_PT":"1 + tan²(θ) = sec²(θ) e 1 + cot²(θ) = csc²(θ). Derivadas dividindo sin²θ + cos²θ = 1 por cos²θ ou sin²θ respectivamente."}, sort_order: 38 },
  { id: 'dc-math-0039', deck_id: 'deck-math', front: 'Double Angle Formula (sin)', back: 'sin(2θ) = 2sin(θ)cos(θ). Expresses the sine of twice an angle in terms of the original angle\'s sine and cosine.', front_translations: {"es":"Fórmula del ángulo duplo (sin)","de":"Doppelwinkelformel (sin)","fr":"Formule de l'angle double (sin)","tr":"Çift Açı Formülü (sin)","nl":"Dubbele-hoekformule (sin)","ru":"Формула двойного угла (sin)","zh":"二倍角公式（sin）","pt_BR":"Fórmula do ângulo duplo (sin)","pt_PT":"Fórmula do ângulo duplo (sin)"}, back_translations: {"es":"sin(2θ) = 2sin(θ)cos(θ). Expressa el seno del dobro de un ángulo en termos del seno y cosseno del ángulo original.","de":"sin(2θ) = 2sin(θ)cos(θ). Drückt den Sinus des doppelten Winkels durch Sinus und Kosinus des ursprünglichen Winkels aus.","fr":"sin(2θ) = 2sin(θ)cos(θ). Exprime le sinus du double d'un angle en fonction du sinus et du cosinus de l'angle original.","tr":"sin(2θ) = 2sin(θ)cos(θ). Bir açının iki katının sinüsünü, orijinal açının sinüsü ve kosinüsü cinsinden ifade eder.","nl":"sin(2θ) = 2sin(θ)cos(θ). Drukt de sinus van de dubbele hoek uit in termen van de sinus en cosinus van de oorspronkelijke hoek.","ru":"sin(2θ) = 2sin(θ)cos(θ). Выражает синус удвоенного угла через синус и косинус исходного угла.","zh":"sin(2θ) = 2sin(θ)cos(θ)。用原角的正弦和余弦表示二倍角的正弦。","pt_BR":"sin(2θ) = 2sin(θ)cos(θ). Expressa o seno do dobro de um ângulo em termos do seno e cosseno do ângulo original.","pt_PT":"sin(2θ) = 2sin(θ)cos(θ). Expressa o seno do dobro de um ângulo em termos do seno e cosseno do ângulo original."}, sort_order: 39 },
  { id: 'dc-math-0040', deck_id: 'deck-math', front: 'Double Angle Formula (cos)', back: 'cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ). Multiple equivalent forms for the cosine of a doubled angle.', front_translations: {"es":"Fórmula del ángulo duplo (cos)","de":"Doppelwinkelformel (cos)","fr":"Formule de l'angle double (cos)","tr":"Çift Açı Formülü (cos)","nl":"Dubbele-hoekformule (cos)","ru":"Формула двойного угла (cos)","zh":"二倍角公式（cos）","pt_BR":"Fórmula do ângulo duplo (cos)","pt_PT":"Fórmula do ângulo duplo (cos)"}, back_translations: {"es":"cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ). Múltiplas formas equivalentes para el cosseno de un ángulo duplicado.","de":"cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ). Mehrere äquivalente Formen für den Kosinus eines verdoppelten Winkels.","fr":"cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ). Plusieurs formes équivalentes pour le cosinus d'un angle doublé.","tr":"cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ). Çift açının kosinüsü için birden fazla eşdeğer form.","nl":"cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ). Meerdere equivalente vormen voor de cosinus van een verdubbelde hoek.","ru":"cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ). Несколько эквивалентных форм для косинуса удвоенного угла.","zh":"cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ)。二倍角余弦的多种等价形式。","pt_BR":"cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ). Múltiplas formas equivalentes para o cosseno de um ângulo duplicado.","pt_PT":"cos(2θ) = cos²(θ) - sin²(θ) = 2cos²(θ) - 1 = 1 - 2sin²(θ). Múltiplas formas equivalentes para o cosseno de um ângulo duplicado."}, sort_order: 40 },
  { id: 'dc-math-0041', deck_id: 'deck-math', front: 'Law of Sines', back: 'a/sin(A) = b/sin(B) = c/sin(C). Relates the sides and angles of any triangle; used when two angles and a side, or two sides and a non-included angle are known.', front_translations: {"es":"Ley de los senos","de":"Sinussatz","fr":"Loi des sinus","tr":"Sinüs Kuralı","nl":"Sinusregel","ru":"Теорема синусов","zh":"正弦定理","pt_BR":"Lei dos senos","pt_PT":"Lei dos senos"}, back_translations: {"es":"a/sin(A) = b/sin(B) = c/sin(C). Relaciona los lados y ángulos de cualquier triángulo; usado cuando de los ángulos y un lado, o de los lados y un ángulo no incluído son conocidos.","de":"a/sin(A) = b/sin(B) = c/sin(C). Verknüpft Seiten und Winkel eines beliebigen Dreiecks; verwendet wenn zwei Winkel und eine Seite oder zwei Seiten und ein nicht eingeschlossener Winkel bekannt sind.","fr":"a/sin(A) = b/sin(B) = c/sin(C). Relie les côtés et les angles de n'importe quel triangle ; utilisé quand deux angles et un côté, ou deux côtés et un angle non compris sont connus.","tr":"a/sin(A) = b/sin(B) = c/sin(C). Herhangi bir üçgenin kenarlarını ve açılarını ilişkilendirir; iki açı ve bir kenar veya iki kenar ve dahil olmayan bir açı bilindiğinde kullanılır.","nl":"a/sin(A) = b/sin(B) = c/sin(C). Relateert de zijden en hoeken van een willekeurige driehoek; gebruikt wanneer twee hoeken en een zijde, of twee zijden en een niet-ingesloten hoek bekend zijn.","ru":"a/sin(A) = b/sin(B) = c/sin(C). Связывает стороны и углы любого треугольника; используется когда известны два угла и сторона, или две стороны и не заключённый угол.","zh":"a/sin(A) = b/sin(B) = c/sin(C)。将任意三角形的边和角联系起来；当已知两角一边或两边及非夹角时使用。","pt_BR":"a/sin(A) = b/sin(B) = c/sin(C). Relaciona os lados e ângulos de qualquer triângulo; usado quando dois ângulos e um lado, ou dois lados e um ângulo não incluído são conhecidos.","pt_PT":"a/sin(A) = b/sin(B) = c/sin(C). Relaciona os lados e ângulos de qualquer triângulo; usado quando dois ângulos e um lado, ou dois lados e um ângulo não incluído são conhecidos."}, sort_order: 41 },
  { id: 'dc-math-0042', deck_id: 'deck-math', front: 'Law of Cosines', back: 'c² = a² + b² - 2ab·cos(C). Generalizes the Pythagorean theorem to any triangle; used when two sides and the included angle, or all three sides, are known.', front_translations: {"es":"Ley de los cossenos","de":"Kosinussatz","fr":"Loi des cosinus","tr":"Kosinüs Kuralı","nl":"Cosinusregel","ru":"Теорема косинусов","zh":"余弦定理","pt_BR":"Lei dos cossenos","pt_PT":"Lei dos cossenos"}, back_translations: {"es":"c² = a² + b² - 2ab·cos(C). Generaliza el teorema de Pitágoras para cualquier triángulo; usado cuando de los lados y el ángulo incluído, o todos los tres lados, son conocidos.","de":"c² = a² + b² - 2ab·cos(C). Verallgemeinert den Satz des Pythagoras auf beliebige Dreiecke; verwendet wenn zwei Seiten und der eingeschlossene Winkel oder alle drei Seiten bekannt sind.","fr":"c² = a² + b² - 2ab·cos(C). Généralise le théorème de Pythagore à n'importe quel triangle ; utilisé quand deux côtés et l'angle compris, ou les trois côtés, sont connus.","tr":"c² = a² + b² - 2ab·cos(C). Pisagor teoremini herhangi bir üçgene genelleştirir; iki kenar ve aralarındaki açı veya üç kenarın tümü bilindiğinde kullanılır.","nl":"c² = a² + b² - 2ab·cos(C). Generaliseert de stelling van Pythagoras naar elke driehoek; gebruikt wanneer twee zijden en de ingesloten hoek, of alle drie de zijden bekend zijn.","ru":"c² = a² + b² - 2ab·cos(C). Обобщает теорему Пифагора на любой треугольник; используется, когда известны две стороны и заключённый угол, или все три стороны.","zh":"c² = a² + b² - 2ab·cos(C)。将勾股定理推广到任意三角形；当已知两边及夹角或三边均已知时使用。","pt_BR":"c² = a² + b² - 2ab·cos(C). Generaliza o teorema de Pitágoras para qualquer triângulo; usado quando dois lados e o ângulo incluído, ou todos os três lados, são conhecidos.","pt_PT":"c² = a² + b² - 2ab·cos(C). Generaliza o teorema de Pitágoras para qualquer triângulo; usado quando dois lados e o ângulo incluído, ou todos os três lados, são conhecidos."}, sort_order: 42 },
  { id: 'dc-math-0043', deck_id: 'deck-math', front: 'Radian Measure', back: 'One radian is the angle subtended at the center of a circle by an arc equal in length to the radius. π radians = 180°; to convert degrees to radians, multiply by π/180.', front_translations: {"es":"Medida en radianos","de":"Bogenmaß","fr":"Mesure en radians","tr":"Radyan Ölçüsü","nl":"Radianmaat","ru":"Радианная мера","zh":"弧度制","pt_BR":"Medida em radianos","pt_PT":"Medida em radianos"}, back_translations: {"es":"Un radiano es el ángulo subtendido en el centro de un círculo por un arco de comprimento igual al raio. π radianos = 180°; para converter graus en radianos, multiplique por π/180.","de":"Ein Radian ist der Winkel, den ein Bogen gleicher Länge wie der Radius im Mittelpunkt eines Kreises einschließt. π Radian = 180°; zur Umrechnung von Grad in Radian mit π/180 multiplizieren.","fr":"Un radian est l'angle au centre d'un cercle sous-tendu par un arc de longueur égale au rayon. π radians = 180° ; pour convertir des degrés en radians, multiplier par π/180.","tr":"Bir radyan, yayın uzunluğunun yarıçapa eşit olduğu durumda dairenin merkezinde oluşan açıdır. π radyan = 180°; dereceyi radyana çevirmek için π/180 ile çarp.","nl":"Eén radiaan is de hoek die een boog ter lengte van de straal insluit in het middelpunt van een cirkel. π radianen = 180°; om graden naar radianen te converteren, vermenigvuldig met π/180.","ru":"Один радиан — это угол, стягиваемый в центре круга дугой, равной по длине радиусу. π радиан = 180°; для перевода градусов в радианы умножают на π/180.","zh":"一弧度是圆心角所对应弧长等于半径时的角度。π 弧度 = 180°；将角度转换为弧度，乘以 π/180。","pt_BR":"Um radiano é o ângulo subtendido no centro de um círculo por um arco de comprimento igual ao raio. π radianos = 180°; para converter graus em radianos, multiplique por π/180.","pt_PT":"Um radiano é o ângulo subtendido no centro de um círculo por um arco de comprimento igual ao raio. π radianos = 180°; para converter graus em radianos, multiplique por π/180."}, sort_order: 43 },
  { id: 'dc-math-0044', deck_id: 'deck-math', front: 'Unit Circle Key Values', back: 'At 0°(0): (1,0); 30°(π/6): (√3/2, 1/2); 45°(π/4): (√2/2, √2/2); 60°(π/3): (1/2, √3/2); 90°(π/2): (0,1). These (cos,sin) pairs are essential for trigonometry.', front_translations: {"es":"Valores-chave del círculo unitário","de":"Einheitskreis-Schlüsselwerte","fr":"Valeurs clés du cercle unité","tr":"Birim Çember Anahtar Değerleri","nl":"Eenheidscirkel sleutelwaarden","ru":"Ключевые значения единичной окружности","zh":"单位圆关键值","pt_BR":"Valores-chave do círculo unitário","pt_PT":"Valores-chave do círculo unitário"}, back_translations: {"es":"En 0°(0): (1,0); 30°(π/6): (√3/2, 1/2); 45°(π/4): (√2/2, √2/2); 60°(π/3): (1/2, √3/2); 90°(π/2): (0,1). Esses pares (cos,sin) son esenciales para trigonometria.","de":"Bei 0°(0): (1,0); 30°(π/6): (√3/2, 1/2); 45°(π/4): (√2/2, √2/2); 60°(π/3): (1/2, √3/2); 90°(π/2): (0,1). Diese (cos,sin)-Paare sind essenziell für die Trigonometrie.","fr":"À 0°(0) : (1,0) ; 30°(π/6) : (√3/2, 1/2) ; 45°(π/4) : (√2/2, √2/2) ; 60°(π/3) : (1/2, √3/2) ; 90°(π/2) : (0,1). Ces paires (cos,sin) sont essentielles en trigonométrie.","tr":"0°(0)'da: (1,0); 30°(π/6)'da: (√3/2, 1/2); 45°(π/4)'de: (√2/2, √2/2); 60°(π/3)'de: (1/2, √3/2); 90°(π/2)'de: (0,1). Bu (cos,sin) çiftleri trigonometri için temeldir.","nl":"Bij 0°(0): (1,0); 30°(π/6): (√3/2, 1/2); 45°(π/4): (√2/2, √2/2); 60°(π/3): (1/2, √3/2); 90°(π/2): (0,1). Deze (cos,sin)-paren zijn essentieel voor trigonometrie.","ru":"При 0°(0): (1,0); 30°(π/6): (√3/2, 1/2); 45°(π/4): (√2/2, √2/2); 60°(π/3): (1/2, √3/2); 90°(π/2): (0,1). Эти пары (cos,sin) необходимы для тригонометрии.","zh":"0°(0) 处：(1,0)；30°(π/6)：(√3/2, 1/2)；45°(π/4)：(√2/2, √2/2)；60°(π/3)：(1/2, √3/2)；90°(π/2)：(0,1)。这些 (cos,sin) 对在三角函数中至关重要。","pt_BR":"Em 0°(0): (1,0); 30°(π/6): (√3/2, 1/2); 45°(π/4): (√2/2, √2/2); 60°(π/3): (1/2, √3/2); 90°(π/2): (0,1). Esses pares (cos,sin) são essenciais para trigonometria.","pt_PT":"Em 0°(0): (1,0); 30°(π/6): (√3/2, 1/2); 45°(π/4): (√2/2, √2/2); 60°(π/3): (1/2, √3/2); 90°(π/2): (0,1). Estes pares (cos,sin) são essenciais para trigonometria."}, sort_order: 44 },
  { id: 'dc-math-0045', deck_id: 'deck-math', front: 'Definition of a Derivative', back: 'f\'(x) = lim[h→0] (f(x+h) - f(x)) / h. The derivative is the instantaneous rate of change, representing the slope of the tangent line to f(x) at a given point.', front_translations: {"es":"Definición de derivada","de":"Definition der Ableitung","fr":"Définition de la dérivée","tr":"Türevin Tanımı","nl":"Definitie van een afgeleide","ru":"Определение производной","zh":"导数的定义","pt_BR":"Definição de derivada","pt_PT":"Definição de derivada"}, back_translations: {"es":"f'(x) = lim[h→0] (f(x+h) - f(x)) / h. La derivada es a taxa de variación instantanea, representando el declive de la reta tangente a f(x) en un punto dato.","de":"f'(x) = lim[h→0] (f(x+h) - f(x)) / h. Die Ableitung ist die momentane Änderungsrate und stellt die Steigung der Tangente an f(x) in einem gegebenen Punkt dar.","fr":"f'(x) = lim[h→0] (f(x+h) - f(x)) / h. La dérivée est le taux de variation instantané, représentant la pente de la tangente à f(x) en un point donné.","tr":"f'(x) = lim[h→0] (f(x+h) - f(x)) / h. Türev, anlık değişim hızıdır ve belirli bir noktada f(x)'e çizilen teğetin eğimini temsil eder.","nl":"f'(x) = lim[h→0] (f(x+h) - f(x)) / h. De afgeleide is de momentane veranderingssnelheid en stelt de helling voor van de raaklijn aan f(x) in een gegeven punt.","ru":"f'(x) = lim[h→0] (f(x+h) - f(x)) / h. Производная — это мгновенная скорость изменения, представляющая наклон касательной к f(x) в данной точке.","zh":"f'(x) = lim[h→0] (f(x+h) - f(x)) / h。导数是瞬时变化率，表示 f(x) 在给定点处切线的斜率。","pt_BR":"f'(x) = lim[h→0] (f(x+h) - f(x)) / h. A derivada é a taxa de variação instantânea, representando o declive da reta tangente a f(x) num ponto dado.","pt_PT":"f'(x) = lim[h→0] (f(x+h) - f(x)) / h. A derivada é a taxa de variação instantânea, representando o declive da reta tangente a f(x) num ponto dado."}, sort_order: 45 },
  { id: 'dc-math-0046', deck_id: 'deck-math', front: 'Chain Rule', back: 'd/dx[f(g(x))] = f\'(g(x)) · g\'(x). To differentiate a composite function, multiply the derivative of the outer function (evaluated at the inner) by the derivative of the inner.', front_translations: {"es":"Regra de la cadeia","de":"Kettenregel","fr":"Règle de la chaîne","tr":"Zincir Kuralı","nl":"Kettingregel","ru":"Правило цепочки","zh":"链式法则","pt_BR":"Regra da cadeia","pt_PT":"Regra da cadeia"}, back_translations: {"es":"d/dx[f(g(x))] = f'(g(x)) · g'(x). Para derivar una función compuesta, multiplica-se a derivada de la función exterior (avaliada en la interior) por la derivada de la función interior.","de":"d/dx[f(g(x))] = f'(g(x)) · g'(x). Zum Differenzieren einer zusammengesetzten Funktion multipliziert man die Ableitung der äußeren Funktion (ausgewertet bei der inneren) mit der Ableitung der inneren.","fr":"d/dx[f(g(x))] = f'(g(x)) · g'(x). Pour dériver une fonction composée, on multiplie la dérivée de la fonction externe (évaluée en la fonction interne) par la dérivée de la fonction interne.","tr":"d/dx[f(g(x))] = f'(g(x)) · g'(x). Bileşik bir fonksiyonu türevlendirmek için dış fonksiyonun türevini (iç fonksiyonda değerlendirilmiş) iç fonksiyonun türevi ile çarp.","nl":"d/dx[f(g(x))] = f'(g(x)) · g'(x). Om een samengestelde functie te differentiëren, vermenigvuldig je de afgeleide van de buitenste functie (geëvalueerd bij de binnenste) met de afgeleide van de binnenste.","ru":"d/dx[f(g(x))] = f'(g(x)) · g'(x). Для дифференцирования сложной функции умножают производную внешней функции (вычисленную при значении внутренней) на производную внутренней.","zh":"d/dx[f(g(x))] = f'(g(x)) · g'(x)。对复合函数求导时，将外层函数的导数（在内层函数处取值）乘以内层函数的导数。","pt_BR":"d/dx[f(g(x))] = f'(g(x)) · g'(x). Para derivar uma função composta, multiplica-se a derivada da função exterior (avaliada na interior) pela derivada da função interior.","pt_PT":"d/dx[f(g(x))] = f'(g(x)) · g'(x). Para derivar uma função composta, multiplica-se a derivada da função exterior (avaliada na interior) pela derivada da função interior."}, sort_order: 46 },
  { id: 'dc-math-0047', deck_id: 'deck-math', front: 'Product Rule', back: 'd/dx[f(x)·g(x)] = f\'(x)·g(x) + f(x)·g\'(x). To differentiate a product, take derivative of first times second plus first times derivative of second.', front_translations: {"es":"Regra del producto","de":"Produktregel","fr":"Règle du produit","tr":"Çarpım Kuralı","nl":"Productregel","ru":"Правило произведения","zh":"乘积法则","pt_BR":"Regra do produto","pt_PT":"Regra do produto"}, back_translations: {"es":"d/dx[f(x)·g(x)] = f'(x)·g(x) + f(x)·g'(x). Para derivar un producto: derivada del primero veces el según, más el primero veces a derivada del según.","de":"d/dx[f(x)·g(x)] = f'(x)·g(x) + f(x)·g'(x). Zum Ableiten eines Produkts: Ableitung der ersten Funktion mal zweite plus erste mal Ableitung der zweiten.","fr":"d/dx[f(x)·g(x)] = f'(x)·g(x) + f(x)·g'(x). Pour dériver un produit : dérivée de la première fois la seconde, plus la première fois la dérivée de la seconde.","tr":"d/dx[f(x)·g(x)] = f'(x)·g(x) + f(x)·g'(x). Bir çarpımı türevlendirmek için: birincinin türevi çarpı ikinci, artı birinci çarpı ikincinin türevi.","nl":"d/dx[f(x)·g(x)] = f'(x)·g(x) + f(x)·g'(x). Om een product te differentiëren: afgeleide van de eerste maal de tweede plus de eerste maal de afgeleide van de tweede.","ru":"d/dx[f(x)·g(x)] = f'(x)·g(x) + f(x)·g'(x). Для дифференцирования произведения: производная первой на вторую плюс первая на производную второй.","zh":"d/dx[f(x)·g(x)] = f'(x)·g(x) + f(x)·g'(x)。对乘积求导：第一个函数的导数乘以第二个，加上第一个乘以第二个函数的导数。","pt_BR":"d/dx[f(x)·g(x)] = f'(x)·g(x) + f(x)·g'(x). Para derivar um produto: derivada do primeiro vezes o segundo, mais o primeiro vezes a derivada do segundo.","pt_PT":"d/dx[f(x)·g(x)] = f'(x)·g(x) + f(x)·g'(x). Para derivar um produto: derivada do primeiro vezes o segundo, mais o primeiro vezes a derivada do segundo."}, sort_order: 47 },
  { id: 'dc-math-0048', deck_id: 'deck-math', front: 'Quotient Rule', back: 'd/dx[f(x)/g(x)] = [f\'(x)·g(x) - f(x)·g\'(x)] / [g(x)]². To differentiate a quotient: (lo·d(hi) - hi·d(lo)) / lo².', front_translations: {"es":"Regra del quociente","de":"Quotientenregel","fr":"Règle du quotient","tr":"Bölüm Kuralı","nl":"Quotiëntregel","ru":"Правило частного","zh":"商的法则","pt_BR":"Regra do quociente","pt_PT":"Regra do quociente"}, back_translations: {"es":"d/dx[f(x)/g(x)] = [f'(x)·g(x) - f(x)·g'(x)] / [g(x)]². Para derivar un quociente: (bajo·d(cima) - cima·d(bajo)) / bajo².","de":"d/dx[f(x)/g(x)] = [f'(x)·g(x) - f(x)·g'(x)] / [g(x)]². Zum Ableiten eines Quotienten: (Nenner·Ableitung(Zähler) - Zähler·Ableitung(Nenner)) / Nenner².","fr":"d/dx[f(x)/g(x)] = [f'(x)·g(x) - f(x)·g'(x)] / [g(x)]². Pour dériver un quotient : (bas·d(haut) - haut·d(bas)) / bas².","tr":"d/dx[f(x)/g(x)] = [f'(x)·g(x) - f(x)·g'(x)] / [g(x)]². Bir bölümü türevlendirmek için: (paydа·d(pay) - pay·d(payda)) / payda².","nl":"d/dx[f(x)/g(x)] = [f'(x)·g(x) - f(x)·g'(x)] / [g(x)]². Om een quotiënt te differentiëren: (noemer·d(teller) - teller·d(noemer)) / noemer².","ru":"d/dx[f(x)/g(x)] = [f'(x)·g(x) - f(x)·g'(x)] / [g(x)]². Для дифференцирования частного: (знаменатель·d(числитель) - числитель·d(знаменатель)) / знаменатель².","zh":"d/dx[f(x)/g(x)] = [f'(x)·g(x) - f(x)·g'(x)] / [g(x)]²。对商求导：(分母·d(分子) - 分子·d(分母)) / 分母²。","pt_BR":"d/dx[f(x)/g(x)] = [f'(x)·g(x) - f(x)·g'(x)] / [g(x)]². Para derivar um quociente: (baixo·d(cima) - cima·d(baixo)) / baixo².","pt_PT":"d/dx[f(x)/g(x)] = [f'(x)·g(x) - f(x)·g'(x)] / [g(x)]². Para derivar um quociente: (baixo·d(cima) - cima·d(baixo)) / baixo²."}, sort_order: 48 },
  { id: 'dc-math-0049', deck_id: 'deck-math', front: 'Derivative of sin(x)', back: 'd/dx[sin(x)] = cos(x). The derivative of sine is cosine; the rate of change of the sine function equals the cosine function.', front_translations: {"es":"Derivada de sin(x)","de":"Ableitung von sin(x)","fr":"Dérivée de sin(x)","tr":"sin(x)'in Türevi","nl":"Afgeleide van sin(x)","ru":"Производная sin(x)","zh":"sin(x) 的导数","pt_BR":"Derivada de sin(x)","pt_PT":"Derivada de sin(x)"}, back_translations: {"es":"d/dx[sin(x)] = cos(x). La derivada del seno es el cosseno; a taxa de variación de la función seno es igual a la función cosseno.","de":"d/dx[sin(x)] = cos(x). Die Ableitung des Sinus ist der Kosinus; die Änderungsrate der Sinusfunktion entspricht der Kosinusfunktion.","fr":"d/dx[sin(x)] = cos(x). La dérivée du sinus est le cosinus ; le taux de variation de la fonction sinus est égal à la fonction cosinus.","tr":"d/dx[sin(x)] = cos(x). Sinüsün türevi kosinüstür; sinüs fonksiyonunun değişim hızı kosinüs fonksiyonuna eşittir.","nl":"d/dx[sin(x)] = cos(x). De afgeleide van sinus is cosinus; de veranderingssnelheid van de sinusfunctie is gelijk aan de cosinusfunctie.","ru":"d/dx[sin(x)] = cos(x). Производная синуса — косинус; скорость изменения функции синуса равна функции косинуса.","zh":"d/dx[sin(x)] = cos(x)。正弦的导数是余弦；正弦函数的变化率等于余弦函数。","pt_BR":"d/dx[sin(x)] = cos(x). A derivada do seno é o cosseno; a taxa de variação da função seno é igual à função cosseno.","pt_PT":"d/dx[sin(x)] = cos(x). A derivada do seno é o cosseno; a taxa de variação da função seno é igual à função cosseno."}, sort_order: 49 },
  { id: 'dc-math-0050', deck_id: 'deck-math', front: 'Derivative of cos(x)', back: 'd/dx[cos(x)] = -sin(x). The derivative of cosine is negative sine; note the negative sign.', front_translations: {"es":"Derivada de cos(x)","de":"Ableitung von cos(x)","fr":"Dérivée de cos(x)","tr":"cos(x)'in Türevi","nl":"Afgeleide van cos(x)","ru":"Производная cos(x)","zh":"cos(x) 的导数","pt_BR":"Derivada de cos(x)","pt_PT":"Derivada de cos(x)"}, back_translations: {"es":"d/dx[cos(x)] = -sin(x). La derivada del cosseno es el seno negativo; note el señal negativo.","de":"d/dx[cos(x)] = -sin(x). Die Ableitung des Kosinus ist der negative Sinus; das negative Vorzeichen ist zu beachten.","fr":"d/dx[cos(x)] = -sin(x). La dérivée du cosinus est le sinus négatif ; noter le signe négatif.","tr":"d/dx[cos(x)] = -sin(x). Kosinüsün türevi negatif sinüstür; negatif işarete dikkat edin.","nl":"d/dx[cos(x)] = -sin(x). De afgeleide van cosinus is negatieve sinus; let op het minteken.","ru":"d/dx[cos(x)] = -sin(x). Производная косинуса — отрицательный синус; обратите внимание на знак минус.","zh":"d/dx[cos(x)] = -sin(x)。余弦的导数是负正弦；注意负号。","pt_BR":"d/dx[cos(x)] = -sin(x). A derivada do cosseno é o seno negativo; note o sinal negativo.","pt_PT":"d/dx[cos(x)] = -sin(x). A derivada do cosseno é o seno negativo; note o sinal negativo."}, sort_order: 50 },
  { id: 'dc-math-0051', deck_id: 'deck-math', front: 'Derivative of tan(x)', back: 'd/dx[tan(x)] = sec²(x). The derivative of tangent equals the square of the secant function.', front_translations: {"es":"Derivada de tan(x)","de":"Ableitung von tan(x)","fr":"Dérivée de tan(x)","tr":"tan(x)'in Türevi","nl":"Afgeleide van tan(x)","ru":"Производная tan(x)","zh":"tan(x) 的导数","pt_BR":"Derivada de tan(x)","pt_PT":"Derivada de tan(x)"}, back_translations: {"es":"d/dx[tan(x)] = sec²(x). La derivada de la tangente es el cuadrado de la secante.","de":"d/dx[tan(x)] = sec²(x). Die Ableitung des Tangens ist das Quadrat der Sekante.","fr":"d/dx[tan(x)] = sec²(x). La dérivée de la tangente est le carré de la sécante.","tr":"d/dx[tan(x)] = sec²(x). Tanjantın türevi, sekant fonksiyonunun karesidir.","nl":"d/dx[tan(x)] = sec²(x). De afgeleide van tangens is het kwadraat van de secans.","ru":"d/dx[tan(x)] = sec²(x). Производная тангенса равна квадрату секанса.","zh":"d/dx[tan(x)] = sec²(x)。正切的导数等于正割函数的平方。","pt_BR":"d/dx[tan(x)] = sec²(x). A derivada da tangente é o quadrado da secante.","pt_PT":"d/dx[tan(x)] = sec²(x). A derivada da tangente é o quadrado da secante."}, sort_order: 51 },
  { id: 'dc-math-0052', deck_id: 'deck-math', front: 'Derivative of ln(x)', back: 'd/dx[ln(x)] = 1/x. The derivative of the natural logarithm of x is the reciprocal of x, valid for x > 0.', front_translations: {"es":"Derivada de ln(x)","de":"Ableitung von ln(x)","fr":"Dérivée de ln(x)","tr":"ln(x)'in Türevi","nl":"Afgeleide van ln(x)","ru":"Производная ln(x)","zh":"ln(x) 的导数","pt_BR":"Derivada de ln(x)","pt_PT":"Derivada de ln(x)"}, back_translations: {"es":"d/dx[ln(x)] = 1/x. La derivada del logaritmo natural de x es el recíproco de x, válida para x > 0.","de":"d/dx[ln(x)] = 1/x. Die Ableitung des natürlichen Logarithmus von x ist der Kehrwert von x, gültig für x > 0.","fr":"d/dx[ln(x)] = 1/x. La dérivée du logarithme naturel de x est l'inverse de x, valable pour x > 0.","tr":"d/dx[ln(x)] = 1/x. x'in doğal logaritmasının türevi, x > 0 için x'in tersidir.","nl":"d/dx[ln(x)] = 1/x. De afgeleide van de natuurlijke logaritme van x is de inverse van x, geldig voor x > 0.","ru":"d/dx[ln(x)] = 1/x. Производная натурального логарифма x равна 1/x, что справедливо при x > 0.","zh":"d/dx[ln(x)] = 1/x。x 的自然对数的导数是 x 的倒数，在 x > 0 时成立。","pt_BR":"d/dx[ln(x)] = 1/x. A derivada do logaritmo natural de x é o recíproco de x, válida para x > 0.","pt_PT":"d/dx[ln(x)] = 1/x. A derivada do logaritmo natural de x é o recíproco de x, válida para x > 0."}, sort_order: 52 },
  { id: 'dc-math-0053', deck_id: 'deck-math', front: 'Derivative of eˣ', back: 'd/dx[eˣ] = eˣ. The natural exponential function is its own derivative; this unique property makes it fundamental in differential equations.', front_translations: {"es":"Derivada de yˣ","de":"Ableitung von eˣ","fr":"Dérivée de eˣ","tr":"eˣ'in Türevi","nl":"Afgeleide van eˣ","ru":"Производная eˣ","zh":"eˣ 的导数","pt_BR":"Derivada de eˣ","pt_PT":"Derivada de eˣ"}, back_translations: {"es":"d/dx[yˣ] = yˣ. La función exponencial natural es su propia derivada; esta propiedad única a torna fundamental en las ecuaciones diferenciais.","de":"d/dx[eˣ] = eˣ. Die natürliche Exponentialfunktion ist ihre eigene Ableitung; diese einzigartige Eigenschaft macht sie fundamental für Differentialgleichungen.","fr":"d/dx[eˣ] = eˣ. La fonction exponentielle naturelle est sa propre dérivée ; cette propriété unique la rend fondamentale dans les équations différentielles.","tr":"d/dx[eˣ] = eˣ. Doğal üstel fonksiyon kendi türevinin kendisidir; bu benzersiz özellik onu diferansiyel denklemlerde temel kılar.","nl":"d/dx[eˣ] = eˣ. De natuurlijke exponentiële functie is zijn eigen afgeleide; deze unieke eigenschap maakt het fundamenteel in differentiaalvergelijkingen.","ru":"d/dx[eˣ] = eˣ. Натуральная показательная функция является собственной производной; это уникальное свойство делает её фундаментальной в дифференциальных уравнениях.","zh":"d/dx[eˣ] = eˣ。自然指数函数是其自身的导数；这一独特性质使其在微分方程中具有基础地位。","pt_BR":"d/dx[eˣ] = eˣ. A função exponencial natural é sua própria derivada; esta propriedade única a torna fundamental nas equações diferenciais.","pt_PT":"d/dx[eˣ] = eˣ. A função exponencial natural é a sua própria derivada; esta propriedade única torna-a fundamental nas equações diferenciais."}, sort_order: 53 },
  { id: 'dc-math-0054', deck_id: 'deck-math', front: 'Fundamental Theorem of Calculus (Part 1)', back: 'If F(x) = ∫[a to x] f(t)dt, then F\'(x) = f(x). Differentiation and integration are inverse operations; the derivative of an integral recovers the original function.', front_translations: {"es":"Teorema fundamental del cálculo (Parte 1)","de":"Hauptsatz der Infinitesimalrechnung (Teil 1)","fr":"Théorème fondamental du calcul (partie 1)","tr":"Kalkülüsün Temel Teoremi (Bölüm 1)","nl":"Hoofdstelling van de integraalrekening (deel 1)","ru":"Основная теорема математического анализа (часть 1)","zh":"微积分基本定理（第一部分）","pt_BR":"Teorema fundamental do cálculo (Parte 1)","pt_PT":"Teorema fundamental do cálculo (Parte 1)"}, back_translations: {"es":"Se F(x) = ∫[a a x] f(t)dt, entonces F'(x) = f(x). La derivación y a integración son operaciones inversas; a derivada de una integral recupera a función original.","de":"Wenn F(x) = ∫[a bis x] f(t)dt, dann F'(x) = f(x). Differentiation und Integration sind inverse Operationen; die Ableitung eines Integrals liefert die ursprüngliche Funktion zurück.","fr":"Si F(x) = ∫[a à x] f(t)dt, alors F'(x) = f(x). La différentiation et l'intégration sont des opérations inverses ; la dérivée d'une intégrale retrouve la fonction originale.","tr":"Eğer F(x) = ∫[a'dan x'e] f(t)dt ise, F'(x) = f(x). Türev alma ve integral alma ters işlemlerdir; bir integralin türevi orijinal fonksiyonu geri verir.","nl":"Als F(x) = ∫[a tot x] f(t)dt, dan F'(x) = f(x). Differentiatie en integratie zijn inverse bewerkingen; de afgeleide van een integraal geeft de oorspronkelijke functie terug.","ru":"Если F(x) = ∫[a до x] f(t)dt, то F'(x) = f(x). Дифференцирование и интегрирование — обратные операции; производная интеграла восстанавливает исходную функцию.","zh":"若 F(x) = ∫[a 到 x] f(t)dt，则 F'(x) = f(x)。微分和积分是互逆运算；积分的导数还原出原函数。","pt_BR":"Se F(x) = ∫[a a x] f(t)dt, então F'(x) = f(x). A derivação e a integração são operações inversas; a derivada de uma integral recupera a função original.","pt_PT":"Se F(x) = ∫[a a x] f(t)dt, então F'(x) = f(x). A derivação e a integração são operações inversas; a derivada de um integral recupera a função original."}, sort_order: 54 },
  { id: 'dc-math-0055', deck_id: 'deck-math', front: 'Fundamental Theorem of Calculus (Part 2)', back: '∫[a to b] f(x)dx = F(b) - F(a), where F is any antiderivative of f. It connects definite integration to antidifferentiation.', front_translations: {"es":"Teorema fundamental del cálculo (Parte 2)","de":"Hauptsatz der Infinitesimalrechnung (Teil 2)","fr":"Théorème fondamental du calcul (partie 2)","tr":"Kalkülüsün Temel Teoremi (Bölüm 2)","nl":"Hoofdstelling van de integraalrekening (deel 2)","ru":"Основная теорема математического анализа (часть 2)","zh":"微积分基本定理（第二部分）","pt_BR":"Teorema fundamental do cálculo (Parte 2)","pt_PT":"Teorema fundamental do cálculo (Parte 2)"}, back_translations: {"es":"∫[a a b] f(x)dx = F(b) - F(a), donde F es cualquier primitiva de f. Conecta a integración definida a la antiderivación.","de":"∫[a bis b] f(x)dx = F(b) - F(a), wobei F eine beliebige Stammfunktion von f ist. Es verbindet bestimmte Integration mit Antidifferentiation.","fr":"∫[a à b] f(x)dx = F(b) - F(a), où F est une primitive de f. Relie l'intégration définie à la recherche de primitive.","tr":"∫[a'dan b'ye] f(x)dx = F(b) - F(a), burada F, f'nin herhangi bir terimi türevidir. Belirli integrali ters türev almaya bağlar.","nl":"∫[a tot b] f(x)dx = F(b) - F(a), waarbij F een willekeurige antiderivaat van f is. Het verbindt bepaalde integratie met antidifferentiatie.","ru":"∫[a до b] f(x)dx = F(b) - F(a), где F — любая первообразная f. Это связывает определённое интегрирование с нахождением первообразной.","zh":"∫[a 到 b] f(x)dx = F(b) - F(a)，其中 F 是 f 的任意原函数。它将定积分与求原函数联系起来。","pt_BR":"∫[a a b] f(x)dx = F(b) - F(a), onde F é qualquer primitiva de f. Conecta a integração definida à antiderivação.","pt_PT":"∫[a a b] f(x)dx = F(b) - F(a), onde F é qualquer primitiva de f. Liga a integração definida à antiderivação."}, sort_order: 55 },
  { id: 'dc-math-0056', deck_id: 'deck-math', front: 'Power Rule for Integration', back: '∫xⁿ dx = xⁿ⁺¹/(n+1) + C (for n ≠ -1). Increase the exponent by 1 and divide by the new exponent; add the constant of integration C.', front_translations: {"es":"Regra de la potencia para integración","de":"Potenzregel für Integration","fr":"Règle de puissance pour l'intégration","tr":"İntegral için Kuvvet Kuralı","nl":"Machtsregel voor integratie","ru":"Правило степени для интегрирования","zh":"积分幂次法则","pt_BR":"Regra da potência para integração","pt_PT":"Regra da potência para integração"}, back_translations: {"es":"∫xⁿ dx = xⁿ⁺¹/(n+1) + C (para n ≠ -1). Aumente el exponente en 1 y divida por el nuevo exponente; adicione a constante de integración C.","de":"∫xⁿ dx = xⁿ⁺¹/(n+1) + C (für n ≠ -1). Den Exponenten um 1 erhöhen und durch den neuen Exponenten teilen; Integrationskonstante C addieren.","fr":"∫xⁿ dx = xⁿ⁺¹/(n+1) + C (pour n ≠ -1). Augmenter l'exposant de 1 et diviser par le nouvel exposant ; ajouter la constante d'intégration C.","tr":"∫xⁿ dx = xⁿ⁺¹/(n+1) + C (n ≠ -1 için). Üssü 1 artır ve yeni üsse böl; integral sabiti C'yi ekle.","nl":"∫xⁿ dx = xⁿ⁺¹/(n+1) + C (voor n ≠ -1). Verhoog de exponent met 1 en deel door de nieuwe exponent; voeg de integratieconstante C toe.","ru":"∫xⁿ dx = xⁿ⁺¹/(n+1) + C (при n ≠ -1). Увеличьте показатель на 1 и разделите на новый показатель; добавьте константу интегрирования C.","zh":"∫xⁿ dx = xⁿ⁺¹/(n+1) + C（n ≠ -1）。将指数加 1，然后除以新指数；加上积分常数 C。","pt_BR":"∫xⁿ dx = xⁿ⁺¹/(n+1) + C (para n ≠ -1). Aumente o expoente em 1 e divida pelo novo expoente; adicione a constante de integração C.","pt_PT":"∫xⁿ dx = xⁿ⁺¹/(n+1) + C (para n ≠ -1). Aumente o expoente em 1 e divida pelo novo expoente; adicione a constante de integração C."}, sort_order: 56 },
  { id: 'dc-math-0057', deck_id: 'deck-math', front: 'Integral of 1/x', back: '∫(1/x) dx = ln|x| + C. The special case where the power rule does not apply (n = -1); the antiderivative is the natural logarithm.', front_translations: {"es":"Integral de 1/x","de":"Integral von 1/x","fr":"Intégrale de 1/x","tr":"1/x'in İntegrali","nl":"Integraal van 1/x","ru":"Интеграл от 1/x","zh":"1/x 的积分","pt_BR":"Integral de 1/x","pt_PT":"Integral de 1/x"}, back_translations: {"es":"∫(1/x) dx = ln|x| + C. El caso especial donde a regra de la potencia no se aplica (n = -1); a primitiva es el logaritmo natural.","de":"∫(1/x) dx = ln|x| + C. Der Spezialfall, bei dem die Potenzregel nicht gilt (n = -1); die Stammfunktion ist der natürliche Logarithmus.","fr":"∫(1/x) dx = ln|x| + C. Le cas particulier où la règle de puissance ne s'applique pas (n = -1) ; la primitive est le logarithme naturel.","tr":"∫(1/x) dx = ln|x| + C. Kuvvet kuralının geçerli olmadığı özel durum (n = -1); ters türev doğal logaritmadır.","nl":"∫(1/x) dx = ln|x| + C. Het speciale geval waarbij de machtsregel niet van toepassing is (n = -1); de antiderivaat is de natuurlijke logaritme.","ru":"∫(1/x) dx = ln|x| + C. Частный случай, когда правило степени не применяется (n = -1); первообразная — натуральный логарифм.","zh":"∫(1/x) dx = ln|x| + C。幂次法则不适用的特殊情形（n = -1）；原函数是自然对数。","pt_BR":"∫(1/x) dx = ln|x| + C. O caso especial onde a regra da potência não se aplica (n = -1); a primitiva é o logaritmo natural.","pt_PT":"∫(1/x) dx = ln|x| + C. O caso especial onde a regra da potência não se aplica (n = -1); a primitiva é o logaritmo natural."}, sort_order: 57 },
  { id: 'dc-math-0058', deck_id: 'deck-math', front: 'Integral of eˣ', back: '∫eˣ dx = eˣ + C. The exponential function is its own antiderivative, just as it is its own derivative.', front_translations: {"es":"Integral de yˣ","de":"Integral von eˣ","fr":"Intégrale de eˣ","tr":"eˣ'in İntegrali","nl":"Integraal van eˣ","ru":"Интеграл от eˣ","zh":"eˣ 的积分","pt_BR":"Integral de eˣ","pt_PT":"Integral de eˣ"}, back_translations: {"es":"∫yˣ dx = yˣ + C. La función exponencial es su propia primitiva, así como es su propia derivada.","de":"∫eˣ dx = eˣ + C. Die Exponentialfunktion ist ihre eigene Stammfunktion, genau wie sie ihre eigene Ableitung ist.","fr":"∫eˣ dx = eˣ + C. La fonction exponentielle est sa propre primitive, tout comme elle est sa propre dérivée.","tr":"∫eˣ dx = eˣ + C. Üstel fonksiyon, tıpkı kendi türevi gibi kendi ters türevidir.","nl":"∫eˣ dx = eˣ + C. De exponentiële functie is zijn eigen antiderivaat, net zoals het zijn eigen afgeleide is.","ru":"∫eˣ dx = eˣ + C. Показательная функция является своей собственной первообразной, так же как и своей производной.","zh":"∫eˣ dx = eˣ + C。指数函数是其自身的原函数，正如它是其自身的导数一样。","pt_BR":"∫eˣ dx = eˣ + C. A função exponencial é sua própria primitiva, assim como é sua própria derivada.","pt_PT":"∫eˣ dx = eˣ + C. A função exponencial é a sua própria primitiva, tal como é a sua própria derivada."}, sort_order: 58 },
  { id: 'dc-math-0059', deck_id: 'deck-math', front: 'Integration by Parts', back: '∫u dv = uv - ∫v du. Used for integrals of products; choose u and dv using the LIATE rule (Logarithm, Inverse trig, Algebraic, Trig, Exponential).', front_translations: {"es":"Integración por partes","de":"Partielle Integration","fr":"Intégration par parties","tr":"Kısmi İntegrasyon","nl":"Integratie per delen","ru":"Интегрирование по частям","zh":"分部积分法","pt_BR":"Integração por partes","pt_PT":"Integração por partes"}, back_translations: {"es":"∫u dv = uv - ∫v du. Usado para integrais de productos; escolha u y dv por la regra LIATE (Logaritmo, Trig inversa, Algébrico, Trig, Exponencial).","de":"∫u dv = uv - ∫v du. Für Integrale von Produkten; u und dv nach der LIATE-Regel wählen (Logarithmus, Inverser Trig, Algebraisch, Trig, Exponentiell).","fr":"∫u dv = uv - ∫v du. Utilisé pour les intégrales de produits ; choisir u et dv selon la règle LIATE (Logarithme, Trig inverse, Algébrique, Trig, Exponentielle).","tr":"∫u dv = uv - ∫v du. Çarpım integralleri için kullanılır; LIATE kuralına göre u ve dv seçilir (Logaritma, Ters trig, Cebirsel, Trig, Üstel).","nl":"∫u dv = uv - ∫v du. Gebruikt voor integralen van producten; kies u en dv met de LIATE-regel (Logaritme, Inverse trig, Algebraïsch, Trig, Exponentieel).","ru":"∫u dv = uv - ∫v du. Используется для интегралов произведений; u и dv выбираются по правилу LIATE (Логарифм, Обратный триг, Алгебраический, Триг, Экспоненциальный).","zh":"∫u dv = uv - ∫v du。用于乘积的积分；按照 LIATE 法则选择 u 和 dv（对数、反三角、代数、三角、指数）。","pt_BR":"∫u dv = uv - ∫v du. Usado para integrais de produtos; escolha u e dv pela regra LIATE (Logaritmo, Trig inversa, Algébrico, Trig, Exponencial).","pt_PT":"∫u dv = uv - ∫v du. Usado para integrais de produtos; escolha u e dv pela regra LIATE (Logaritmo, Trig inversa, Algébrico, Trig, Exponencial)."}, sort_order: 59 },
  { id: 'dc-math-0060', deck_id: 'deck-math', front: 'U-Substitution', back: 'A technique for integrating composite functions: let u = g(x), substitute, integrate with respect to u, then substitute back. It reverses the chain rule.', front_translations: {"es":"Substituición por u","de":"U-Substitution","fr":"Substitution u","tr":"U-İkame","nl":"U-substitutie","ru":"Метод замены переменной (u-подстановка)","zh":"u 代换法","pt_BR":"Substituição por u","pt_PT":"Substituição por u"}, back_translations: {"es":"Una técnica para integrar funciones compuestas: seja u = g(x), substitua, integre en relación con u, después substitua de volta. Reverte a regra de la cadeia.","de":"Eine Technik zur Integration zusammengesetzter Funktionen: u = g(x) setzen, einsetzen, nach u integrieren, dann zurückeinsetzen. Kehrt die Kettenregel um.","fr":"Une technique pour intégrer des fonctions composées : poser u = g(x), substituer, intégrer par rapport à u, puis resubstituer. Elle inverse la règle de la chaîne.","tr":"Bileşik fonksiyonları integre etmek için bir teknik: u = g(x) koy, yerine koy, u'ya göre integre et, sonra geri yerine koy. Zincir kuralını tersine çevirir.","nl":"Een techniek voor het integreren van samengestelde functies: stel u = g(x), substitueer, integreer naar u, substitueer dan terug. Het keert de kettingregel om.","ru":"Метод интегрирования сложных функций: пусть u = g(x), произведите замену, проинтегрируйте по u, затем вернитесь к исходной переменной. Обращает правило цепочки.","zh":"对复合函数进行积分的技巧：令 u = g(x)，代入，对 u 积分，然后回代。它是链式法则的逆运算。","pt_BR":"Uma técnica para integrar funções compostas: seja u = g(x), substitua, integre em relação a u, depois substitua de volta. Reverte a regra da cadeia.","pt_PT":"Uma técnica para integrar funções compostas: seja u = g(x), substitua, integre em relação a u, depois substitua de volta. Reverte a regra da cadeia."}, sort_order: 60 },
  { id: 'dc-math-0061', deck_id: 'deck-math', front: 'Limit Definition', back: 'lim[x→a] f(x) = L means f(x) can be made arbitrarily close to L by taking x sufficiently close to a (but not equal to a).', front_translations: {"es":"Definición de limite","de":"Grenzwertdefinition","fr":"Définition de la limite","tr":"Limit Tanımı","nl":"Definitie van een limiet","ru":"Определение предела","zh":"极限的定义","pt_BR":"Definição de limite","pt_PT":"Definição de limite"}, back_translations: {"es":"lim[x→a] f(x) = L significa que f(x) puede ser aproximado arbitrariamente de L tomando x suficientemente próximo de a (pero no igual a a).","de":"lim[x→a] f(x) = L bedeutet, dass f(x) beliebig nahe an L gebracht werden kann, indem x genügend nahe an a genommen wird (aber nicht gleich a).","fr":"lim[x→a] f(x) = L signifie que f(x) peut être rendu arbitrairement proche de L en prenant x suffisamment proche de a (sans être égal à a).","tr":"lim[x→a] f(x) = L, x'i a'ya yeterince yakın (ancak a'ya eşit olmayan) alarak f(x)'in L'ye istenildiği kadar yakın yapılabileceği anlamına gelir.","nl":"lim[x→a] f(x) = L betekent dat f(x) willekeurig dicht bij L kan worden gemaakt door x voldoende dicht bij a te nemen (maar niet gelijk aan a).","ru":"lim[x→a] f(x) = L означает, что f(x) можно сделать сколь угодно близким к L, взяв x достаточно близко к a (но не равным a).","zh":"lim[x→a] f(x) = L 意味着，通过使 x 充分接近 a（但不等于 a），可以使 f(x) 任意接近 L。","pt_BR":"lim[x→a] f(x) = L significa que f(x) pode ser aproximado arbitrariamente de L tomando x suficientemente próximo de a (mas não igual a a).","pt_PT":"lim[x→a] f(x) = L significa que f(x) pode ser aproximado arbitrariamente de L tomando x suficientemente próximo de a (mas não igual a a)."}, sort_order: 61 },
  { id: 'dc-math-0062', deck_id: 'deck-math', front: 'L\'Hôpital\'s Rule', back: 'If lim f(x)/g(x) is 0/0 or ∞/∞, then lim f(x)/g(x) = lim f\'(x)/g\'(x). Used to evaluate indeterminate form limits by differentiating numerator and denominator separately.', front_translations: {"es":"Regra de L'Hopital","de":"L'Hôpitals Regel","fr":"Règle de L'Hôpital","tr":"L'Hôpital Kuralı","nl":"Regel van L'Hôpital","ru":"Правило Лопиталя","zh":"洛必达法则","pt_BR":"Regra de L'Hôpital","pt_PT":"Regra de L'Hôpital"}, back_translations: {"es":"Se lim f(x)/g(x) es 0/0 o ∞/∞, entonces lim f(x)/g(x) = lim f'(x)/g'(x). Usado para avaliar limites de formas indeterminadas diferenciando numerador y denominador separadamente.","de":"Wenn lim f(x)/g(x) 0/0 oder ∞/∞ ist, dann lim f(x)/g(x) = lim f'(x)/g'(x). Wird zur Auswertung unbestimmter Grenzwerte durch getrenntes Differenzieren von Zähler und Nenner verwendet.","fr":"Si lim f(x)/g(x) vaut 0/0 ou ∞/∞, alors lim f(x)/g(x) = lim f'(x)/g'(x). Utilisé pour évaluer les limites de formes indéterminées en différentiant séparément numérateur et dénominateur.","tr":"Eğer lim f(x)/g(x) 0/0 veya ∞/∞ ise, lim f(x)/g(x) = lim f'(x)/g'(x). Pay ve paydayı ayrı ayrı türevlendirerek belirsiz form limitlerini hesaplamak için kullanılır.","nl":"Als lim f(x)/g(x) gelijk is aan 0/0 of ∞/∞, dan lim f(x)/g(x) = lim f'(x)/g'(x). Gebruikt om limieten van onbepaalde vormen te evalueren door teller en noemer afzonderlijk te differentiëren.","ru":"Если lim f(x)/g(x) принимает форму 0/0 или ∞/∞, то lim f(x)/g(x) = lim f'(x)/g'(x). Используется для вычисления пределов неопределённых форм путём отдельного дифференцирования числителя и знаменателя.","zh":"若 lim f(x)/g(x) 为 0/0 或 ∞/∞，则 lim f(x)/g(x) = lim f'(x)/g'(x)。通过分别对分子和分母求导来计算不定型极限。","pt_BR":"Se lim f(x)/g(x) é 0/0 ou ∞/∞, então lim f(x)/g(x) = lim f'(x)/g'(x). Usado para avaliar limites de formas indeterminadas diferenciando numerador e denominador separadamente.","pt_PT":"Se lim f(x)/g(x) é 0/0 ou ∞/∞, então lim f(x)/g(x) = lim f'(x)/g'(x). Usado para avaliar limites de formas indeterminadas diferenciando numerador e denominador separadamente."}, sort_order: 62 },
  { id: 'dc-math-0063', deck_id: 'deck-math', front: 'Squeeze Theorem', back: 'If g(x) ≤ f(x) ≤ h(x) and lim g(x) = lim h(x) = L, then lim f(x) = L. Used to prove limits by bounding a function between two functions with known limits.', front_translations: {"es":"Teorema del confronto","de":"Einschnürungssatz","fr":"Théorème des gendarmes","tr":"Sıkıştırma Teoremi","nl":"Insluitstelling","ru":"Теорема о сжатой переменной","zh":"夹逼定理","pt_BR":"Teorema do confronto","pt_PT":"Teorema das funções enquadradas"}, back_translations: {"es":"Se g(x) ≤ f(x) ≤ h(x) y lim g(x) = lim h(x) = L, entonces lim f(x) = L. Usado para provar limites delimitando una función entre de los funciones con limites conocidos.","de":"Wenn g(x) ≤ f(x) ≤ h(x) und lim g(x) = lim h(x) = L, dann lim f(x) = L. Wird verwendet, um Grenzwerte zu beweisen, indem eine Funktion zwischen zwei Funktionen mit bekannten Grenzwerten eingeschlossen wird.","fr":"Si g(x) ≤ f(x) ≤ h(x) et lim g(x) = lim h(x) = L, alors lim f(x) = L. Utilisé pour prouver des limites en encadrant une fonction entre deux fonctions de limites connues.","tr":"Eğer g(x) ≤ f(x) ≤ h(x) ve lim g(x) = lim h(x) = L ise, lim f(x) = L. Bir fonksiyonu bilinen limitlere sahip iki fonksiyon arasına sıkıştırarak limitleri kanıtlamak için kullanılır.","nl":"Als g(x) ≤ f(x) ≤ h(x) en lim g(x) = lim h(x) = L, dan lim f(x) = L. Gebruikt om limieten te bewijzen door een functie te omvatten tussen twee functies met bekende limieten.","ru":"Если g(x) ≤ f(x) ≤ h(x) и lim g(x) = lim h(x) = L, то lim f(x) = L. Используется для доказательства пределов путём ограничения функции двумя функциями с известными пределами.","zh":"若 g(x) ≤ f(x) ≤ h(x) 且 lim g(x) = lim h(x) = L，则 lim f(x) = L。通过将函数夹在两个已知极限的函数之间来证明极限。","pt_BR":"Se g(x) ≤ f(x) ≤ h(x) e lim g(x) = lim h(x) = L, então lim f(x) = L. Usado para provar limites delimitando uma função entre duas funções com limites conhecidos.","pt_PT":"Se g(x) ≤ f(x) ≤ h(x) e lim g(x) = lim h(x) = L, então lim f(x) = L. Usado para provar limites enquadrando uma função entre duas funções com limites conhecidos."}, sort_order: 63 },
  { id: 'dc-math-0064', deck_id: 'deck-math', front: 'Mean Value Theorem', back: 'If f is continuous on [a,b] and differentiable on (a,b), then there exists c in (a,b) where f\'(c) = [f(b)-f(a)]/(b-a); the instantaneous rate equals the average rate at some point.', front_translations: {"es":"Teorema del valor médio","de":"Mittelwertsatz","fr":"Théorème des accroissements finis","tr":"Ortalama Değer Teoremi","nl":"Middelwaardestelling","ru":"Теорема о среднем значении","zh":"中值定理","pt_BR":"Teorema do valor médio","pt_PT":"Teorema do valor médio"}, back_translations: {"es":"Se f es contínua en [a,b] y diferenciable en (a,b), existe c en (a,b) donde f'(c) = [f(b)-f(a)]/(b-a); a taxa instantanea iguala a taxa média en algún punto.","de":"Wenn f auf [a,b] stetig und auf (a,b) differenzierbar ist, dann gibt es ein c in (a,b) mit f'(c) = [f(b)-f(a)]/(b-a); die momentane Rate entspricht der Durchschnittsrate an einem Punkt.","fr":"Si f est continue sur [a,b] et dérivable sur (a,b), il existe c dans (a,b) tel que f'(c) = [f(b)-f(a)]/(b-a) ; le taux instantané égale le taux moyen en un certain point.","tr":"Eğer f, [a,b] üzerinde sürekli ve (a,b) üzerinde türevlenebilir ise, (a,b) içinde f'(c) = [f(b)-f(a)]/(b-a) olan bir c vardır; anlık hız bir noktada ortalama hıza eşittir.","nl":"Als f continu is op [a,b] en differentieerbaar op (a,b), bestaat er een c in (a,b) waarvoor f'(c) = [f(b)-f(a)]/(b-a); de momentane snelheid gelijk is aan de gemiddelde snelheid op een punt.","ru":"Если f непрерывна на [a,b] и дифференцируема на (a,b), то существует c в (a,b), где f'(c) = [f(b)-f(a)]/(b-a); мгновенная скорость равна средней скорости в некоторой точке.","zh":"若 f 在 [a,b] 上连续且在 (a,b) 上可微，则存在 c ∈ (a,b) 使得 f'(c) = [f(b)-f(a)]/(b-a)；瞬时变化率在某点等于平均变化率。","pt_BR":"Se f é contínua em [a,b] e diferenciável em (a,b), existe c em (a,b) onde f'(c) = [f(b)-f(a)]/(b-a); a taxa instantânea iguala a taxa média em algum ponto.","pt_PT":"Se f é contínua em [a,b] e diferenciável em (a,b), existe c em (a,b) onde f'(c) = [f(b)-f(a)]/(b-a); a taxa instantânea iguala a taxa média em algum ponto."}, sort_order: 64 },
  { id: 'dc-math-0065', deck_id: 'deck-math', front: 'Rolle\'s Theorem', back: 'If f is continuous on [a,b], differentiable on (a,b), and f(a) = f(b), then there exists c in (a,b) where f\'(c) = 0; a special case of the Mean Value Theorem.', front_translations: {"es":"Teorema de Rolle","de":"Satz von Rolle","fr":"Théorème de Rolle","tr":"Rolle Teoremi","nl":"Stelling van Rolle","ru":"Теорема Ролля","zh":"罗尔定理","pt_BR":"Teorema de Rolle","pt_PT":"Teorema de Rolle"}, back_translations: {"es":"Se f es contínua en [a,b], diferenciable en (a,b), y f(a) = f(b), entonces existe c en (a,b) donde f'(c) = 0; un caso especial del Teorema del Valor Médio.","de":"Wenn f auf [a,b] stetig, auf (a,b) differenzierbar und f(a) = f(b) ist, dann gibt es ein c in (a,b) mit f'(c) = 0; ein Spezialfall des Mittelwertsatzes.","fr":"Si f est continue sur [a,b], dérivable sur (a,b), et f(a) = f(b), alors il existe c dans (a,b) tel que f'(c) = 0 ; cas particulier du théorème des accroissements finis.","tr":"Eğer f, [a,b] üzerinde sürekli, (a,b) üzerinde türevlenebilir ve f(a) = f(b) ise, (a,b) içinde f'(c) = 0 olan bir c vardır; Ortalama Değer Teoreminin özel bir halidir.","nl":"Als f continu is op [a,b], differentieerbaar op (a,b), en f(a) = f(b), dan bestaat er een c in (a,b) waarvoor f'(c) = 0; een speciaal geval van de middelwaardestelling.","ru":"Если f непрерывна на [a,b], дифференцируема на (a,b) и f(a) = f(b), то существует c в (a,b), где f'(c) = 0; частный случай теоремы о среднем значении.","zh":"若 f 在 [a,b] 上连续、在 (a,b) 上可微且 f(a) = f(b)，则存在 c ∈ (a,b) 使得 f'(c) = 0；这是中值定理的特殊情形。","pt_BR":"Se f é contínua em [a,b], diferenciável em (a,b), e f(a) = f(b), então existe c em (a,b) onde f'(c) = 0; um caso especial do Teorema do Valor Médio.","pt_PT":"Se f é contínua em [a,b], diferenciável em (a,b), e f(a) = f(b), então existe c em (a,b) onde f'(c) = 0; um caso especial do Teorema do Valor Médio."}, sort_order: 65 },
  { id: 'dc-math-0066', deck_id: 'deck-math', front: 'Critical Point', back: 'A point where f\'(x) = 0 or f\'(x) is undefined; candidates for local maxima, minima, or saddle points. Determined by the first or second derivative test.', front_translations: {"es":"Ponto crítico","de":"Kritischer Punkt","fr":"Point critique","tr":"Kritik Nokta","nl":"Kritiek punt","ru":"Критическая точка","zh":"临界点","pt_BR":"Ponto crítico","pt_PT":"Ponto crítico"}, back_translations: {"es":"Un punto donde f'(x) = 0 o f'(x) es indefinido; candidatos a máximos ubicaciones, mínimos o puntos de sela. Determinado por el prueba de la primera o segunda derivada.","de":"Ein Punkt, an dem f'(x) = 0 oder f'(x) undefiniert ist; Kandidaten für lokale Maxima, Minima oder Sattelpunkte. Wird durch den Ersten- oder Zweiten-Ableitungstest bestimmt.","fr":"Un point où f'(x) = 0 ou f'(x) est indéfini ; candidats aux maxima locaux, minima ou points col. Déterminé par le test de la première ou seconde dérivée.","tr":"f'(x) = 0 veya f'(x) tanımsız olduğu nokta; yerel maksimum, minimum veya eyer noktaları için adaydır. Birinci veya ikinci türev testi ile belirlenir.","nl":"Een punt waar f'(x) = 0 of f'(x) ongedefinieerd is; kandidaten voor lokale maxima, minima of zadelpunten. Bepaald door de eerste- of tweede-afgeleidetest.","ru":"Точка, в которой f'(x) = 0 или f'(x) не определена; кандидаты на локальные максимумы, минимумы или точки перегиба. Определяется с помощью первой или второй производной.","zh":"f'(x) = 0 或 f'(x) 不存在的点；是局部极大值、极小值或鞍点的候选点。通过一阶或二阶导数检验确定。","pt_BR":"Um ponto onde f'(x) = 0 ou f'(x) é indefinido; candidatos a máximos locais, mínimos ou pontos de sela. Determinado pelo teste da primeira ou segunda derivada.","pt_PT":"Um ponto onde f'(x) = 0 ou f'(x) é indefinido; candidatos a máximos locais, mínimos ou pontos de sela. Determinado pelo teste da primeira ou segunda derivada."}, sort_order: 66 },
  { id: 'dc-math-0067', deck_id: 'deck-math', front: 'Second Derivative Test', back: 'If f\'(c) = 0 and f\'\'(c) > 0, then c is a local minimum; if f\'\'(c) < 0, it is a local maximum; if f\'\'(c) = 0, the test is inconclusive.', front_translations: {"es":"Teste de la segunda derivada","de":"Zweiter Ableitungstest","fr":"Test de la dérivée seconde","tr":"İkinci Türev Testi","nl":"Tweede-afgeleidetest","ru":"Признак второй производной","zh":"二阶导数检验","pt_BR":"Teste da segunda derivada","pt_PT":"Teste da segunda derivada"}, back_translations: {"es":"Se f'(c) = 0 y f''(c) > 0, entonces c es un mínimo local; se f''(c) < 0, es un máximo local; se f''(c) = 0, el prueba es inconclusivo.","de":"Wenn f'(c) = 0 und f''(c) > 0, ist c ein lokales Minimum; wenn f''(c) < 0, ein lokales Maximum; wenn f''(c) = 0, ist der Test nicht aussagekräftig.","fr":"Si f'(c) = 0 et f''(c) > 0, alors c est un minimum local ; si f''(c) < 0, c'est un maximum local ; si f''(c) = 0, le test est non concluant.","tr":"Eğer f'(c) = 0 ve f''(c) > 0 ise, c yerel bir minimumdur; f''(c) < 0 ise yerel maksimum; f''(c) = 0 ise test sonuçsuz kalır.","nl":"Als f'(c) = 0 en f''(c) > 0, is c een lokaal minimum; als f''(c) < 0, is het een lokaal maximum; als f''(c) = 0, is de test niet sluitend.","ru":"Если f'(c) = 0 и f''(c) > 0, то c — локальный минимум; если f''(c) < 0 — локальный максимум; если f''(c) = 0, тест не даёт результата.","zh":"若 f'(c) = 0 且 f''(c) > 0，则 c 是局部极小值；若 f''(c) < 0，则是局部极大值；若 f''(c) = 0，则检验无结论。","pt_BR":"Se f'(c) = 0 e f''(c) > 0, então c é um mínimo local; se f''(c) < 0, é um máximo local; se f''(c) = 0, o teste é inconclusivo.","pt_PT":"Se f'(c) = 0 e f''(c) > 0, então c é um mínimo local; se f''(c) < 0, é um máximo local; se f''(c) = 0, o teste é inconclusivo."}, sort_order: 67 },
  { id: 'dc-math-0068', deck_id: 'deck-math', front: 'Inflection Point', back: 'A point where the concavity of f(x) changes; occurs where f\'\'(x) = 0 or is undefined and changes sign. At an inflection point, the curve switches from concave up to concave down or vice versa.', front_translations: {"es":"Ponto de inflexão","de":"Wendepunkt","fr":"Point d'inflexion","tr":"Büküm Noktası","nl":"Buigpunt","ru":"Точка перегиба","zh":"拐点","pt_BR":"Ponto de inflexão","pt_PT":"Ponto de inflexão"}, back_translations: {"es":"Un punto donde a concavidad de f(x) muda; ocurre donde f''(x) = 0 o es indefinido y muda de señal. Num punto de inflexão, a curva muda de concava para cima para concava para bajo o vice-versa.","de":"Ein Punkt, an dem sich die Konkavität von f(x) ändert; tritt auf, wenn f''(x) = 0 oder undefiniert ist und das Vorzeichen wechselt. An einem Wendepunkt wechselt die Kurve von konkav nach oben zu konkav nach unten oder umgekehrt.","fr":"Un point où la concavité de f(x) change ; se produit là où f''(x) = 0 ou est indéfini et change de signe. En un point d'inflexion, la courbe passe de concave vers le haut à concave vers le bas ou vice versa.","tr":"f(x)'in içbükeyliğinin değiştiği nokta; f''(x) = 0 olduğu veya tanımsız olup işaret değiştirdiği yerde oluşur. Büküm noktasında eğri, yukarı içbükeyden aşağı içbükeyliğe veya tersine geçer.","nl":"Een punt waar de concaviteit van f(x) verandert; treedt op waar f''(x) = 0 is of ongedefinieerd en van teken wisselt. Op een buigpunt wisselt de curve van concaaf omhoog naar concaaf omlaag of vice versa.","ru":"Точка, в которой меняется знак кривизны f(x); возникает там, где f''(x) = 0 или не определена и меняет знак. В точке перегиба кривая переходит от выпуклости к вогнутости или наоборот.","zh":"f(x) 凹凸性发生改变的点；发生在 f''(x) = 0 或不存在且变号的地方。在拐点处，曲线从上凸变为下凸，或反之。","pt_BR":"Um ponto onde a concavidade de f(x) muda; ocorre onde f''(x) = 0 ou é indefinido e muda de sinal. Num ponto de inflexão, a curva muda de côncava para cima para côncava para baixo ou vice-versa.","pt_PT":"Um ponto onde a concavidade de f(x) muda; ocorre onde f''(x) = 0 ou é indefinido e muda de sinal. Num ponto de inflexão, a curva muda de côncava para cima para côncava para baixo ou vice-versa."}, sort_order: 68 },
  { id: 'dc-math-0069', deck_id: 'deck-math', front: 'Arithmetic Mean (Average)', back: 'μ = (x₁ + x₂ + ... + xₙ) / n. The sum of all values divided by the number of values; sensitive to outliers.', front_translations: {"es":"Média aritmética","de":"Arithmetisches Mittel (Durchschnitt)","fr":"Moyenne arithmétique","tr":"Aritmetik Ortalama","nl":"Rekenkundig gemiddelde","ru":"Среднее арифметическое","zh":"算术平均数","pt_BR":"Média aritmética","pt_PT":"Média aritmética"}, back_translations: {"es":"μ = (x₁ + x₂ + ... + xₙ) / n. La suma de todos los valores dividida por el número de valores; sensible a valores atípicos.","de":"μ = (x₁ + x₂ + ... + xₙ) / n. Die Summe aller Werte geteilt durch die Anzahl der Werte; empfindlich gegenüber Ausreißern.","fr":"μ = (x₁ + x₂ + ... + xₙ) / n. La somme de toutes les valeurs divisée par leur nombre ; sensible aux valeurs aberrantes.","tr":"μ = (x₁ + x₂ + ... + xₙ) / n. Tüm değerlerin toplamının değer sayısına bölümü; aykırı değerlere duyarlıdır.","nl":"μ = (x₁ + x₂ + ... + xₙ) / n. De som van alle waarden gedeeld door het aantal waarden; gevoelig voor uitschieters.","ru":"μ = (x₁ + x₂ + ... + xₙ) / n. Сумма всех значений, делённая на их количество; чувствительна к выбросам.","zh":"μ = (x₁ + x₂ + ... + xₙ) / n。所有值之和除以值的个数；对异常值敏感。","pt_BR":"μ = (x₁ + x₂ + ... + xₙ) / n. A soma de todos os valores dividida pelo número de valores; sensível a valores atípicos.","pt_PT":"μ = (x₁ + x₂ + ... + xₙ) / n. A soma de todos os valores dividida pelo número de valores; sensível a valores atípicos."}, sort_order: 69 },
  { id: 'dc-math-0070', deck_id: 'deck-math', front: 'Median', back: 'The middle value of an ordered dataset; for an even number of values, it is the average of the two middle values. More robust than the mean in the presence of outliers.', front_translations: {"es":"Mediana","de":"Median","fr":"Médiane","tr":"Medyan","nl":"Mediaan","ru":"Медиана","zh":"中位数","pt_BR":"Mediana","pt_PT":"Mediana"}, back_translations: {"es":"El valor central de un conjunto de datos ordenado; para un número par de valores, es a média de los de los valores centrais. Más robusto que a média en la presencia de valores atípicos.","de":"Der mittlere Wert eines geordneten Datensatzes; bei gerader Anzahl von Werten ist es der Durchschnitt der beiden mittleren Werte. Robuster als der Mittelwert bei Ausreißern.","fr":"La valeur centrale d'un ensemble de données ordonné ; pour un nombre pair de valeurs, c'est la moyenne des deux valeurs centrales. Plus robuste que la moyenne en présence de valeurs aberrantes.","tr":"Sıralı bir veri kümesinin orta değeri; çift sayıda değer için iki orta değerin ortalamasıdır. Aykırı değerlerin varlığında ortalamadan daha sağlamdır.","nl":"De middelste waarde van een geordende dataset; voor een even aantal waarden is het het gemiddelde van de twee middelste waarden. Robuuster dan het gemiddelde bij uitschieters.","ru":"Среднее значение упорядоченного набора данных; при чётном числе значений — среднее двух средних значений. Более устойчива к выбросам, чем среднее арифметическое.","zh":"有序数据集的中间值；若值的个数为偶数，则为两个中间值的平均数。在存在异常值时比均值更稳健。","pt_BR":"O valor central de um conjunto de dados ordenado; para um número par de valores, é a média dos dois valores centrais. Mais robusto que a média na presença de valores atípicos.","pt_PT":"O valor central de um conjunto de dados ordenado; para um número par de valores, é a média dos dois valores centrais. Mais robusto que a média na presença de valores atípicos."}, sort_order: 70 },
  { id: 'dc-math-0071', deck_id: 'deck-math', front: 'Mode', back: 'The value that appears most frequently in a dataset. A dataset can be unimodal (one mode), bimodal (two modes), or multimodal (several modes).', front_translations: {"es":"Moda","de":"Modus","fr":"Mode","tr":"Mod","nl":"Modus","ru":"Мода","zh":"众数","pt_BR":"Moda","pt_PT":"Moda"}, back_translations: {"es":"El valor que aparece con mayor frecuencia en un conjunto de datos. Un conjunto puede ser unimodal (una moda), bimodal (de los modas) o multimodal (várias modas).","de":"Der Wert, der in einem Datensatz am häufigsten vorkommt. Ein Datensatz kann unimodal (ein Modus), bimodal (zwei Modi) oder multimodal (mehrere Modi) sein.","fr":"La valeur qui apparaît le plus fréquemment dans un ensemble de données. Un ensemble peut être unimodal (un mode), bimodal (deux modes) ou multimodal (plusieurs modes).","tr":"Bir veri kümesinde en sık görünen değer. Bir veri kümesi tek modlu (bir mod), çift modlu (iki mod) veya çok modlu (birkaç mod) olabilir.","nl":"De waarde die het vaakst voorkomt in een dataset. Een dataset kan unimodaal (één modus), bimodaal (twee modi) of multimodaal (meerdere modi) zijn.","ru":"Значение, которое встречается в наборе данных наиболее часто. Набор данных может быть одномодальным, двумодальным или многомодальным.","zh":"数据集中出现频率最高的值。数据集可以是单峰（一个众数）、双峰（两个众数）或多峰（多个众数）的。","pt_BR":"O valor que aparece com maior frequência num conjunto de dados. Um conjunto pode ser unimodal (uma moda), bimodal (duas modas) ou multimodal (várias modas).","pt_PT":"O valor que aparece com maior frequência num conjunto de dados. Um conjunto pode ser unimodal (uma moda), bimodal (duas modas) ou multimodal (várias modas)."}, sort_order: 71 },
  { id: 'dc-math-0072', deck_id: 'deck-math', front: 'Variance', back: 'σ² = Σ(xᵢ - μ)² / N (population). The average of squared deviations from the mean; measures data spread. Sample variance uses (N-1) as the denominator (Bessel\'s correction).', front_translations: {"es":"Variancia","de":"Varianz","fr":"Variance","tr":"Varyans","nl":"Variantie","ru":"Дисперсия","zh":"方差","pt_BR":"Variância","pt_PT":"Variância"}, back_translations: {"es":"σ² = Σ(xᵢ - μ)² / N (población). La média de los desvios al cuadrado en relación con la média; mide a dispersão de los datos. La variancia amostral usa (N-1) como denominador (correción de Bessel).","de":"σ² = Σ(xᵢ - μ)² / N (Population). Der Durchschnitt der quadrierten Abweichungen vom Mittelwert; misst die Streuung der Daten. Die Stichprobenvarianz verwendet (N-1) als Nenner (Bessel-Korrektur).","fr":"σ² = Σ(xᵢ - μ)² / N (population). La moyenne des carrés des écarts à la moyenne ; mesure la dispersion des données. La variance d'échantillon utilise (N-1) comme dénominateur (correction de Bessel).","tr":"σ² = Σ(xᵢ - μ)² / N (popülasyon). Ortalamadan kare sapmaların ortalaması; veri yayılımını ölçer. Örneklem varyansı payda olarak (N-1) kullanır (Bessel düzeltmesi).","nl":"σ² = Σ(xᵢ - μ)² / N (populatie). Het gemiddelde van de gekwadrateerde afwijkingen van het gemiddelde; meet de spreiding van gegevens. Steekproefvariantie gebruikt (N-1) als noemer (Bessel-correctie).","ru":"σ² = Σ(xᵢ - μ)² / N (генеральная совокупность). Среднее квадратичных отклонений от среднего; измеряет разброс данных. Выборочная дисперсия использует (N-1) в знаменателе (поправка Бесселя).","zh":"σ² = Σ(xᵢ - μ)² / N（总体）。各值与均值偏差的平方的平均数；衡量数据的分散程度。样本方差使用 (N-1) 作为分母（贝塞尔修正）。","pt_BR":"σ² = Σ(xᵢ - μ)² / N (população). A média dos desvios ao quadrado em relação à média; mede a dispersão dos dados. A variância amostral usa (N-1) como denominador (correção de Bessel).","pt_PT":"σ² = Σ(xᵢ - μ)² / N (população). A média dos desvios ao quadrado em relação à média; mede a dispersão dos dados. A variância amostral usa (N-1) como denominador (correcção de Bessel)."}, sort_order: 72 },
  { id: 'dc-math-0073', deck_id: 'deck-math', front: 'Standard Deviation', back: 'σ = √(variance). The square root of variance; expresses spread in the same units as the data. About 68% of data falls within ±1σ for a normal distribution.', front_translations: {"es":"Desvio padrão","de":"Standardabweichung","fr":"Écart type","tr":"Standart Sapma","nl":"Standaardafwijking","ru":"Стандартное отклонение","zh":"标准差","pt_BR":"Desvio padrão","pt_PT":"Desvio padrão"}, back_translations: {"es":"σ = √(variancia). La raíz quadrada de la variancia; expressa a dispersão en las mismas unidades de los datos. Cerca de 68% de los datos caem dentro de ±1σ para una distribución normal.","de":"σ = √(Varianz). Die Quadratwurzel der Varianz; drückt die Streuung in denselben Einheiten wie die Daten aus. Etwa 68% der Daten liegen bei einer Normalverteilung innerhalb von ±1σ.","fr":"σ = √(variance). La racine carrée de la variance ; exprime la dispersion dans les mêmes unités que les données. Environ 68% des données se situent dans ±1σ pour une distribution normale.","tr":"σ = √(varyans). Varyansın kare kökü; yayılımı verilerle aynı birimde ifade eder. Normal dağılımda verilerin yaklaşık %68'i ±1σ içinde düşer.","nl":"σ = √(variantie). De vierkantswortel van de variantie; drukt spreiding uit in dezelfde eenheden als de gegevens. Ongeveer 68% van de gegevens valt binnen ±1σ voor een normale verdeling.","ru":"σ = √(дисперсия). Квадратный корень из дисперсии; выражает разброс в тех же единицах, что и данные. Около 68% данных попадают в пределы ±1σ для нормального распределения.","zh":"σ = √(方差)。方差的平方根；以与数据相同的单位表示分散程度。对于正态分布，约 68% 的数据落在 ±1σ 范围内。","pt_BR":"σ = √(variância). A raiz quadrada da variância; expressa a dispersão nas mesmas unidades dos dados. Cerca de 68% dos dados caem dentro de ±1σ para uma distribuição normal.","pt_PT":"σ = √(variância). A raiz quadrada da variância; expressa a dispersão nas mesmas unidades dos dados. Cerca de 68% dos dados caem dentro de ±1σ para uma distribuição normal."}, sort_order: 73 },
  { id: 'dc-math-0074', deck_id: 'deck-math', front: '68-95-99.7 Rule (Empirical Rule)', back: 'For a normal distribution: ~68% of data falls within ±1σ, ~95% within ±2σ, and ~99.7% within ±3σ of the mean.', front_translations: {"es":"Regra 68-95-99,7 (Regra Empírica)","de":"68-95-99,7-Regel (Empirische Regel)","fr":"Règle 68-95-99,7 (règle empirique)","tr":"68-95-99,7 Kuralı (Ampirik Kural)","nl":"68-95-99,7-regel (empirische regel)","ru":"Правило 68-95-99,7 (эмпирическое правило)","zh":"68-95-99.7 法则（经验法则）","pt_BR":"Regra 68-95-99,7 (Regra Empírica)","pt_PT":"Regra 68-95-99,7 (Regra Empírica)"}, back_translations: {"es":"Para una distribución normal: ~68% de los datos caem dentro de ±1σ, ~95% dentro de ±2σ y ~99,7% dentro de ±3σ de la média.","de":"Für eine Normalverteilung: ~68% der Daten liegen innerhalb von ±1σ, ~95% innerhalb von ±2σ und ~99,7% innerhalb von ±3σ des Mittelwerts.","fr":"Pour une distribution normale : ~68% des données se trouvent dans ±1σ, ~95% dans ±2σ et ~99,7% dans ±3σ de la moyenne.","tr":"Normal dağılım için: verilerin ~%68'i ±1σ içinde, ~%95'i ±2σ içinde ve ~%99,7'si ortalamadan ±3σ içinde düşer.","nl":"Voor een normale verdeling: ~68% van de gegevens valt binnen ±1σ, ~95% binnen ±2σ en ~99,7% binnen ±3σ van het gemiddelde.","ru":"Для нормального распределения: ~68% данных попадают в пределы ±1σ, ~95% — в ±2σ и ~99,7% — в ±3σ от среднего.","zh":"对于正态分布：约 68% 的数据落在均值 ±1σ 范围内，约 95% 在 ±2σ 内，约 99.7% 在 ±3σ 内。","pt_BR":"Para uma distribuição normal: ~68% dos dados caem dentro de ±1σ, ~95% dentro de ±2σ e ~99,7% dentro de ±3σ da média.","pt_PT":"Para uma distribuição normal: ~68% dos dados caem dentro de ±1σ, ~95% dentro de ±2σ e ~99,7% dentro de ±3σ da média."}, sort_order: 74 },
  { id: 'dc-math-0075', deck_id: 'deck-math', front: 'Z-Score', back: 'z = (x - μ) / σ. Measures how many standard deviations a value x is from the mean; allows comparison across different distributions.', front_translations: {"es":"Pontuación Z","de":"Z-Score","fr":"Score Z","tr":"Z-Skoru","nl":"Z-score","ru":"Z-оценка","zh":"Z 分数","pt_BR":"Pontuação Z","pt_PT":"Pontuação Z"}, back_translations: {"es":"z = (x - μ) / σ. Mede quantos desvios padrão un valor x está de la média; permite comparación entre diferentes distribuiciones.","de":"z = (x - μ) / σ. Misst, wie viele Standardabweichungen ein Wert x vom Mittelwert entfernt ist; ermöglicht den Vergleich über verschiedene Verteilungen hinweg.","fr":"z = (x - μ) / σ. Mesure combien d'écarts-types une valeur x est éloignée de la moyenne ; permet la comparaison entre différentes distributions.","tr":"z = (x - μ) / σ. Bir x değerinin ortalamadan kaç standart sapma uzakta olduğunu ölçer; farklı dağılımlar arasında karşılaştırmaya olanak tanır.","nl":"z = (x - μ) / σ. Meet hoeveel standaardafwijkingen een waarde x verwijderd is van het gemiddelde; maakt vergelijking tussen verschillende verdelingen mogelijk.","ru":"z = (x - μ) / σ. Измеряет, на сколько стандартных отклонений значение x отдалено от среднего; позволяет сравнивать различные распределения.","zh":"z = (x - μ) / σ。衡量值 x 距均值有多少个标准差；允许在不同分布之间进行比较。","pt_BR":"z = (x - μ) / σ. Mede quantos desvios padrão um valor x está da média; permite comparação entre diferentes distribuições.","pt_PT":"z = (x - μ) / σ. Mede quantos desvios padrão um valor x está da média; permite comparação entre diferentes distribuições."}, sort_order: 75 },
  { id: 'dc-math-0076', deck_id: 'deck-math', front: 'Normal Distribution', back: 'A symmetric, bell-shaped probability distribution defined by its mean (μ) and standard deviation (σ). Many natural phenomena approximate normal distributions by the Central Limit Theorem.', front_translations: {"es":"Distribuición normal","de":"Normalverteilung","fr":"Distribution normale","tr":"Normal Dağılım","nl":"Normale verdeling","ru":"Нормальное распределение","zh":"正态分布","pt_BR":"Distribuição normal","pt_PT":"Distribuição normal"}, back_translations: {"es":"Una distribución de probabilidad simétrica en forma de sino definida por la su média (μ) y desvio padrão (σ). Muitos fenómenos naturais aproximam-se de distribuiciones normais por el Teorema Central del Limite.","de":"Eine symmetrische, glockenförmige Wahrscheinlichkeitsverteilung, definiert durch ihren Mittelwert (μ) und ihre Standardabweichung (σ). Viele natürliche Phänomene nähern sich durch den Zentralen Grenzwertsatz einer Normalverteilung an.","fr":"Une distribution de probabilité symétrique en forme de cloche définie par sa moyenne (μ) et son écart type (σ). De nombreux phénomènes naturels s'approchent des distributions normales par le théorème central limite.","tr":"Ortalama (μ) ve standart sapma (σ) ile tanımlanan simetrik, çan şeklinde bir olasılık dağılımı. Pek çok doğal fenomen, Merkezi Limit Teoremi aracılığıyla normal dağılımlara yaklaşır.","nl":"Een symmetrische, klokvormige kansverdelingsdistributie gedefinieerd door het gemiddelde (μ) en standaardafwijking (σ). Veel natuurlijke fenomenen benaderen normale verdelingen via de centrale limietstelling.","ru":"Симметричное колоколообразное распределение вероятностей, определяемое средним значением (μ) и стандартным отклонением (σ). Многие природные явления приближаются к нормальному распределению согласно центральной предельной теореме.","zh":"由均值 (μ) 和标准差 (σ) 定义的对称钟形概率分布。根据中心极限定理，许多自然现象近似正态分布。","pt_BR":"Uma distribuição de probabilidade simétrica em forma de sino definida pela sua média (μ) e desvio padrão (σ). Muitos fenômenos naturais aproximam-se de distribuições normais pelo Teorema Central do Limite.","pt_PT":"Uma distribuição de probabilidade simétrica em forma de sino definida pela sua média (μ) e desvio padrão (σ). Muitos fenómenos naturais aproximam-se de distribuições normais pelo Teorema do Limite Central."}, sort_order: 76 },
  { id: 'dc-math-0077', deck_id: 'deck-math', front: 'Central Limit Theorem', back: 'For sufficiently large samples (n ≥ 30), the distribution of sample means approaches a normal distribution regardless of the population\'s original distribution.', front_translations: {"es":"Teorema Central del Limite","de":"Zentraler Grenzwertsatz","fr":"Théorème central limite","tr":"Merkezi Limit Teoremi","nl":"Centrale limietstelling","ru":"Центральная предельная теорема","zh":"中心极限定理","pt_BR":"Teorema Central do Limite","pt_PT":"Teorema do Limite Central"}, back_translations: {"es":"Para amostras suficientemente grandes (n ≥ 30), a distribución de las médias amostrais se aproxima de una distribución normal independentemente de la distribución original de la población.","de":"Für ausreichend große Stichproben (n ≥ 30) nähert sich die Verteilung der Stichprobenmittelwerte unabhängig von der ursprünglichen Verteilung der Population einer Normalverteilung an.","fr":"Pour des échantillons suffisamment grands (n ≥ 30), la distribution des moyennes d'échantillons s'approche d'une distribution normale quelle que soit la distribution originale de la population.","tr":"Yeterince büyük örnekler için (n ≥ 30), örneklem ortalamalarının dağılımı, popülasyonun orijinal dağılımından bağımsız olarak normal dağılıma yaklaşır.","nl":"Voor voldoende grote steekproeven (n ≥ 30) benadert de verdeling van steekproefgemiddelden een normale verdeling, ongeacht de oorspronkelijke verdeling van de populatie.","ru":"Для достаточно больших выборок (n ≥ 30) распределение выборочных средних приближается к нормальному независимо от исходного распределения генеральной совокупности.","zh":"对于足够大的样本（n ≥ 30），无论总体的原始分布如何，样本均值的分布趋近于正态分布。","pt_BR":"Para amostras suficientemente grandes (n ≥ 30), a distribuição das médias amostrais se aproxima de uma distribuição normal independentemente da distribuição original da população.","pt_PT":"Para amostras suficientemente grandes (n ≥ 30), a distribuição das médias amostrais aproxima-se de uma distribuição normal independentemente da distribuição original da população."}, sort_order: 77 },
  { id: 'dc-math-0078', deck_id: 'deck-math', front: 'Probability of an Event', back: 'P(A) = Number of favorable outcomes / Total number of equally likely outcomes. Probabilities range from 0 (impossible) to 1 (certain).', front_translations: {"es":"Probabilidad de un evento","de":"Wahrscheinlichkeit eines Ereignisses","fr":"Probabilité d'un événement","tr":"Bir Olayın Olasılığı","nl":"Kans op een gebeurtenis","ru":"Вероятность события","zh":"事件的概率","pt_BR":"Probabilidade de um evento","pt_PT":"Probabilidade de um evento"}, back_translations: {"es":"P(A) = Número de resultados favorables / Número total de resultados igualmente provables. As probabilidades variam de 0 (impossible) a 1 (certo).","de":"P(A) = Anzahl günstiger Ergebnisse / Gesamtzahl gleichwahrscheinlicher Ergebnisse. Wahrscheinlichkeiten reichen von 0 (unmöglich) bis 1 (sicher).","fr":"P(A) = Nombre de résultats favorables / Nombre total de résultats équiprobables. Les probabilités vont de 0 (impossible) à 1 (certain).","tr":"P(A) = Olumlu sonuç sayısı / Eşit olası toplam sonuç sayısı. Olasılıklar 0 (imkânsız) ile 1 (kesin) arasında değişir.","nl":"P(A) = Aantal gunstige uitkomsten / Totaal aantal even waarschijnlijke uitkomsten. Kansen variëren van 0 (onmogelijk) tot 1 (zeker).","ru":"P(A) = Количество благоприятных исходов / Общее количество равновероятных исходов. Вероятности варьируются от 0 (невозможно) до 1 (достоверно).","zh":"P(A) = 有利结果数 / 等可能结果总数。概率范围从 0（不可能）到 1（确定）。","pt_BR":"P(A) = Número de resultados favoráveis / Número total de resultados igualmente prováveis. As probabilidades variam de 0 (impossível) a 1 (certo).","pt_PT":"P(A) = Número de resultados favoráveis / Número total de resultados igualmente prováveis. As probabilidades variam de 0 (impossível) a 1 (certo)."}, sort_order: 78 },
  { id: 'dc-math-0079', deck_id: 'deck-math', front: 'Complementary Probability', back: 'P(A\') = 1 - P(A). The probability of an event not occurring equals 1 minus the probability of it occurring.', front_translations: {"es":"Probabilidad complementar","de":"Komplementärwahrscheinlichkeit","fr":"Probabilité complémentaire","tr":"Tümleyen Olasılık","nl":"Complementaire kans","ru":"Вероятность дополнения","zh":"互补概率","pt_BR":"Probabilidade complementar","pt_PT":"Probabilidade complementar"}, back_translations: {"es":"P(A') = 1 - P(A). La probabilidad de un evento no ocorrer es igual a 1 menos a probabilidad de ocorrer.","de":"P(A') = 1 - P(A). Die Wahrscheinlichkeit, dass ein Ereignis nicht eintritt, ist gleich 1 minus die Wahrscheinlichkeit seines Eintretens.","fr":"P(A') = 1 - P(A). La probabilité qu'un événement ne se produise pas est égale à 1 moins la probabilité qu'il se produise.","tr":"P(A') = 1 - P(A). Bir olayın gerçekleşmeme olasılığı, gerçekleşme olasılığının 1 eksiğine eşittir.","nl":"P(A') = 1 - P(A). De kans dat een gebeurtenis niet optreedt is gelijk aan 1 minus de kans dat het optreedt.","ru":"P(A') = 1 - P(A). Вероятность того, что событие не произойдёт, равна 1 минус вероятность его наступления.","zh":"P(A') = 1 - P(A)。事件不发生的概率等于 1 减去它发生的概率。","pt_BR":"P(A') = 1 - P(A). A probabilidade de um evento não ocorrer é igual a 1 menos a probabilidade de ocorrer.","pt_PT":"P(A') = 1 - P(A). A probabilidade de um evento não ocorrer é igual a 1 menos a probabilidade de ocorrer."}, sort_order: 79 },
  { id: 'dc-math-0080', deck_id: 'deck-math', front: 'Addition Rule of Probability', back: 'P(A ∪ B) = P(A) + P(B) - P(A ∩ B). For mutually exclusive events, P(A ∩ B) = 0, so P(A ∪ B) = P(A) + P(B).', front_translations: {"es":"Regra de la adición de probabilidades","de":"Additionsregel der Wahrscheinlichkeit","fr":"Règle d'addition des probabilités","tr":"Olasılık Toplama Kuralı","nl":"Optellingsregel van kansen","ru":"Теорема сложения вероятностей","zh":"概率加法法则","pt_BR":"Regra da adição de probabilidades","pt_PT":"Regra da adição de probabilidades"}, back_translations: {"es":"P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Para eventos mutuamente exclusivos, P(A ∩ B) = 0, entonces P(A ∪ B) = P(A) + P(B).","de":"P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Für sich gegenseitig ausschließende Ereignisse gilt P(A ∩ B) = 0, also P(A ∪ B) = P(A) + P(B).","fr":"P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Pour des événements mutuellement exclusifs, P(A ∩ B) = 0, donc P(A ∪ B) = P(A) + P(B).","tr":"P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Birbirini dışlayan olaylar için P(A ∩ B) = 0, yani P(A ∪ B) = P(A) + P(B).","nl":"P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Voor onderling uitsluitende gebeurtenissen geldt P(A ∩ B) = 0, dus P(A ∪ B) = P(A) + P(B).","ru":"P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Для несовместных событий P(A ∩ B) = 0, поэтому P(A ∪ B) = P(A) + P(B).","zh":"P(A ∪ B) = P(A) + P(B) - P(A ∩ B)。对于互斥事件，P(A ∩ B) = 0，故 P(A ∪ B) = P(A) + P(B)。","pt_BR":"P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Para eventos mutuamente exclusivos, P(A ∩ B) = 0, então P(A ∪ B) = P(A) + P(B).","pt_PT":"P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Para eventos mutuamente exclusivos, P(A ∩ B) = 0, então P(A ∪ B) = P(A) + P(B)."}, sort_order: 80 },
  { id: 'dc-math-0081', deck_id: 'deck-math', front: 'Multiplication Rule of Probability', back: 'P(A ∩ B) = P(A) × P(B|A). For independent events, P(A ∩ B) = P(A) × P(B), since P(B|A) = P(B).', front_translations: {"es":"Regra de la multiplicación de probabilidades","de":"Multiplikationsregel der Wahrscheinlichkeit","fr":"Règle de multiplication des probabilités","tr":"Olasılık Çarpım Kuralı","nl":"Vermenigvuldigingsregel van kansen","ru":"Теорема умножения вероятностей","zh":"概率乘法法则","pt_BR":"Regra da multiplicação de probabilidades","pt_PT":"Regra da multiplicação de probabilidades"}, back_translations: {"es":"P(A ∩ B) = P(A) × P(B|A). Para eventos independentes, P(A ∩ B) = P(A) × P(B), pois P(B|A) = P(B).","de":"P(A ∩ B) = P(A) × P(B|A). Für unabhängige Ereignisse gilt P(A ∩ B) = P(A) × P(B), da P(B|A) = P(B).","fr":"P(A ∩ B) = P(A) × P(B|A). Pour des événements indépendants, P(A ∩ B) = P(A) × P(B), car P(B|A) = P(B).","tr":"P(A ∩ B) = P(A) × P(B|A). Bağımsız olaylar için P(B|A) = P(B) olduğundan P(A ∩ B) = P(A) × P(B).","nl":"P(A ∩ B) = P(A) × P(B|A). Voor onafhankelijke gebeurtenissen geldt P(A ∩ B) = P(A) × P(B), omdat P(B|A) = P(B).","ru":"P(A ∩ B) = P(A) × P(B|A). Для независимых событий P(A ∩ B) = P(A) × P(B), поскольку P(B|A) = P(B).","zh":"P(A ∩ B) = P(A) × P(B|A)。对于独立事件，由于 P(B|A) = P(B)，故 P(A ∩ B) = P(A) × P(B)。","pt_BR":"P(A ∩ B) = P(A) × P(B|A). Para eventos independentes, P(A ∩ B) = P(A) × P(B), pois P(B|A) = P(B).","pt_PT":"P(A ∩ B) = P(A) × P(B|A). Para eventos independentes, P(A ∩ B) = P(A) × P(B), pois P(B|A) = P(B)."}, sort_order: 81 },
  { id: 'dc-math-0082', deck_id: 'deck-math', front: 'Conditional Probability', back: 'P(B|A) = P(A ∩ B) / P(A). The probability of B occurring given that A has already occurred; read as "probability of B given A."', front_translations: {"es":"Probabilidad condicional","de":"Bedingte Wahrscheinlichkeit","fr":"Probabilité conditionnelle","tr":"Koşullu Olasılık","nl":"Voorwaardelijke kans","ru":"Условная вероятность","zh":"条件概率","pt_BR":"Probabilidade condicional","pt_PT":"Probabilidade condicional"}, back_translations: {"es":"P(B|A) = P(A ∩ B) / P(A). La probabilidad de B ocorrer dato que A ya ocorreu; se lee 'probabilidad de B dato A'.","de": "P(B|A) = P(A ∩ B) / P(A). Die Wahrscheinlichkeit, dass B eintritt, gegeben dass A bereits eingetreten ist; gelesen als 'Wahrscheinlichkeit von B gegeben A'.", "fr": "P(B|A) = P(A ∩ B) / P(A). La probabilité que B se produise sachant que A s'est déjà produit ; se lit 'probabilité de B sachant A'.", "tr": "P(B|A) = P(A ∩ B) / P(A). A'nın zaten gerçekleştiği koşuluyla B'nin gerçekleşme olasılığı; 'A verildiğinde B'nin olasılığı' olarak okunur.", "nl": "P(B|A) = P(A ∩ B) / P(A). De kans dat B optreedt gegeven dat A al heeft plaatsgevonden; gelezen als 'kans op B gegeven A'.", "ru": "P(B|A) = P(A ∩ B) / P(A). Вероятность наступления B при условии, что A уже произошло; читается как «вероятность B при условии A».", "zh": "P(B|A) = P(A ∩ B) / P(A)。在 A 已经发生的条件下 B 发生的概率；读作\\\"在 A 条件下 B 的概率\\\"。", "pt_BR": "P(B|A) = P(A ∩ B) / P(A). A probabilidade de B ocorrer dado que A já ocorreu; lê-se 'probabilidade de B dado A'.", "pt_PT": "P(B|A) = P(A ∩ B) / P(A). A probabilidade de B ocorrer dado que A já ocorreu; lê-se 'probabilidade de B dado A'."}, sort_order: 82 },
  { id: 'dc-math-0083', deck_id: 'deck-math', front: 'Bayes\' Theorem', back: 'P(A|B) = P(B|A) × P(A) / P(B). Allows updating the probability of a hypothesis A given new evidence B; fundamental to statistical inference and machine learning.', front_translations: {"es":"Teorema de Bayes","de":"Satz von Bayes","fr":"Théorème de Bayes","tr":"Bayes Teoremi","nl":"Theorema van Bayes","ru":"Теорема Байеса","zh":"贝叶斯定理","pt_BR":"Teorema de Bayes","pt_PT":"Teorema de Bayes"}, back_translations: {"es":"P(A|B) = P(B|A) × P(A) / P(B). Permite atualizar a probabilidad de una hipótese A dato nuevo evidencia B; fundamental para inferencia estadística y aprendizaje automático.","de":"P(A|B) = P(B|A) × P(A) / P(B). Ermöglicht die Aktualisierung der Wahrscheinlichkeit einer Hypothese A angesichts neuer Evidenz B; grundlegend für statistische Inferenz und maschinelles Lernen.","fr":"P(A|B) = P(B|A) × P(A) / P(B). Permet de mettre à jour la probabilité d'une hypothèse A à la lumière de nouvelles preuves B ; fondamental en inférence statistique et en apprentissage automatique.","tr":"P(A|B) = P(B|A) × P(A) / P(B). Yeni B kanıtı göz önünde bulundurularak A hipotezinin olasılığını güncellemeye olanak tanır; istatistiksel çıkarım ve makine öğrenmesinde temeldir.","nl":"P(A|B) = P(B|A) × P(A) / P(B). Maakt het mogelijk de kans van hypothese A bij te werken gegeven nieuw bewijs B; fundamenteel voor statistische inferentie en machine learning.","ru":"P(A|B) = P(B|A) × P(A) / P(B). Позволяет обновить вероятность гипотезы A при наличии новых данных B; основополагающая теорема для статистического вывода и машинного обучения.","zh":"P(A|B) = P(B|A) × P(A) / P(B)。在获得新证据 B 的情况下更新假设 A 的概率；是统计推断和机器学习的基础。","pt_BR":"P(A|B) = P(B|A) × P(A) / P(B). Permite atualizar a probabilidade de uma hipótese A dado novo evidência B; fundamental para inferência estatística e aprendizado de máquina.","pt_PT":"P(A|B) = P(B|A) × P(A) / P(B). Permite actualizar a probabilidade de uma hipótese A dada nova evidência B; fundamental para inferência estatística e aprendizagem automática."}, sort_order: 83 },
  { id: 'dc-math-0084', deck_id: 'deck-math', front: 'Permutation', back: 'P(n,r) = n! / (n-r)!. The number of ways to arrange r items from n distinct items where order matters; "n permute r."', front_translations: {"es":"Permutación","de":"Permutation","fr":"Permutation","tr":"Permütasyon","nl":"Permutatie","ru":"Перестановка","zh":"排列","pt_BR":"Permutação","pt_PT":"Permutação"}, back_translations: {"es":"P(n,r) = n! / (n-r)!. El número de maneras de arranjar r itens de n itens distintos donde a ordem importa; 'n arranjar r'.","de": "P(n,r) = n! / (n-r)!. Die Anzahl der Möglichkeiten, r Elemente aus n verschiedenen Elementen anzuordnen, wobei die Reihenfolge wichtig ist; 'n permutiere r'.", "fr": "P(n,r) = n! / (n-r)!. Le nombre de façons d'arranger r éléments parmi n éléments distincts où l'ordre compte ; 'arrangement de r parmi n'.", "tr": "P(n,r) = n! / (n-r)!. Sıranın önemli olduğu n farklı elemandan r elemanı düzenleme yollarının sayısı; 'n'den r'nin permütasyonu'.", "nl": "P(n,r) = n! / (n-r)!. Het aantal manieren om r items van n verschillende items te rangschikken waarbij volgorde van belang is; 'n permuteer r'.", "ru": "P(n,r) = n! / (n-r)!. Количество способов расположить r элементов из n различных элементов, где порядок важен; «перестановки из n по r».", "zh": "P(n,r) = n! / (n-r)!。从 n 个不同元素中取出 r 个元素进行排列（顺序有关）的方法数；\\\"从 n 中取 r 个的排列\\\"。", "pt_BR": "P(n,r) = n! / (n-r)!. O número de maneiras de arranjar r itens de n itens distintos onde a ordem importa; 'n arranjar r'.", "pt_PT": "P(n,r) = n! / (n-r)!. O número de formas de arranjar r itens de n itens distintos onde a ordem importa; 'n arranjar r'."}, sort_order: 84 },
  { id: 'dc-math-0085', deck_id: 'deck-math', front: 'Combination', back: 'C(n,r) = n! / (r!(n-r)!). The number of ways to choose r items from n distinct items where order does not matter; also written as "n choose r" or ⁿCᵣ.', front_translations: {"es":"Combinación","de":"Kombination","fr":"Combinaison","tr":"Kombinasyon","nl":"Combinatie","ru":"Сочетание","zh":"组合","pt_BR":"Combinação","pt_PT":"Combinação"}, back_translations: {"es":"C(n,r) = n! / (r!(n-r)!). El número de maneras de escolher r itens de n itens distintos donde a ordem no importa; también escrito como 'n escolher r' o ⁿCᵣ.","de": "C(n,r) = n! / (r!(n-r)!). Die Anzahl der Möglichkeiten, r Elemente aus n verschiedenen Elementen auszuwählen, wobei die Reihenfolge keine Rolle spielt; auch 'n über r' geschrieben.", "fr": "C(n,r) = n! / (r!(n-r)!). Le nombre de façons de choisir r éléments parmi n éléments distincts où l'ordre ne compte pas ; aussi noté 'n choisir r' ou ⁿCᵣ.", "tr": "C(n,r) = n! / (r!(n-r)!). Sıranın önemli olmadığı n farklı elemandan r eleman seçme yollarının sayısı; 'n'den r seç' veya ⁿCᵣ olarak da yazılır.", "nl": "C(n,r) = n! / (r!(n-r)!). Het aantal manieren om r items te kiezen uit n verschillende items waarbij volgorde niet uitmaakt; ook geschreven als 'n kies r' of ⁿCᵣ.", "ru": "C(n,r) = n! / (r!(n-r)!). Количество способов выбрать r элементов из n различных элементов, где порядок не важен; также записывается как «сочетания из n по r» или ⁿCᵣ.", "zh": "C(n,r) = n! / (r!(n-r)!)。从 n 个不同元素中取出 r 个元素（顺序无关）的方法数；也写作\\\"从 n 中取 r\\\"或 ⁿCᵣ。", "pt_BR": "C(n,r) = n! / (r!(n-r)!). O número de maneiras de escolher r itens de n itens distintos onde a ordem não importa; também escrito como 'n escolher r' ou ⁿCᵣ.", "pt_PT": "C(n,r) = n! / (r!(n-r)!). O número de formas de escolher r itens de n itens distintos onde a ordem não importa; também escrito como 'n escolher r' ou ⁿCᵣ."}, sort_order: 85 },
  { id: 'dc-math-0086', deck_id: 'deck-math', front: 'Factorial', back: 'n! = n × (n-1) × (n-2) × ... × 1. The product of all positive integers up to n; by definition, 0! = 1.', front_translations: {"es":"Fatorial","de":"Fakultät","fr":"Factorielle","tr":"Faktöriyel","nl":"Faculteit","ru":"Факториал","zh":"阶乘","pt_BR":"Fatorial","pt_PT":"Fatorial"}, back_translations: {"es":"n! = n × (n-1) × (n-2) × ... × 1. El producto de todos los interos positivos hasta n; por definición, 0! = 1.","de":"n! = n × (n-1) × (n-2) × ... × 1. Das Produkt aller positiven ganzen Zahlen bis n; per Definition gilt 0! = 1.","fr":"n! = n × (n-1) × (n-2) × ... × 1. Le produit de tous les entiers positifs jusqu'à n ; par définition, 0! = 1.","tr":"n! = n × (n-1) × (n-2) × ... × 1. n'ye kadar tüm pozitif tam sayıların çarpımı; tanım gereği 0! = 1.","nl":"n! = n × (n-1) × (n-2) × ... × 1. Het product van alle positieve gehele getallen tot en met n; per definitie geldt 0! = 1.","ru":"n! = n × (n-1) × (n-2) × ... × 1. Произведение всех натуральных чисел от 1 до n; по определению, 0! = 1.","zh":"n! = n × (n-1) × (n-2) × ... × 1。所有不超过 n 的正整数之积；按定义，0! = 1。","pt_BR":"n! = n × (n-1) × (n-2) × ... × 1. O produto de todos os inteiros positivos até n; por definição, 0! = 1.","pt_PT":"n! = n × (n-1) × (n-2) × ... × 1. O produto de todos os inteiros positivos até n; por definição, 0! = 1."}, sort_order: 86 },
  { id: 'dc-math-0087', deck_id: 'deck-math', front: 'Binomial Theorem', back: '(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ. Expands a binomial raised to any power n using binomial coefficients; Pascal\'s triangle gives the coefficients.', front_translations: {"es":"Teorema binomial","de":"Binomischer Lehrsatz","fr":"Théorème binomial","tr":"Binom Teoremi","nl":"Binomiumstelling","ru":"Бином Ньютона","zh":"二项式定理","pt_BR":"Teorema binomial","pt_PT":"Teorema binomial"}, back_translations: {"es":"(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ. Expande un binomio elevado a cualquier potencia n usando coeficientes binomiais; el triángulo de Pascal proporciona los coeficientes.","de":"(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ. Entwickelt ein Binom, das zu einer beliebigen Potenz n erhoben wird, mithilfe von Binomialkoeffizienten; das Pascalsche Dreieck liefert die Koeffizienten.","fr":"(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ. Développe un binôme élevé à n'importe quelle puissance n en utilisant les coefficients binomiaux ; le triangle de Pascal donne les coefficients.","tr":"(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ. Binom katsayılarını kullanarak herhangi bir n kuvvetine yükseltilmiş bir binomi açar; Pascal üçgeni katsayıları verir.","nl":"(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ. Ontwikkelt een binomium tot een willekeurige macht n met behulp van binomiaalcoëfficiënten; de driehoek van Pascal geeft de coëfficiënten.","ru":"(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ. Раскрывает двучлен в степени n через биномиальные коэффициенты; треугольник Паскаля даёт коэффициенты.","zh":"(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ。用二项式系数展开 n 次幂的二项式；帕斯卡三角给出系数。","pt_BR":"(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ. Expande um binômio elevado a qualquer potência n usando coeficientes binomiais; o triângulo de Pascal fornece os coeficientes.","pt_PT":"(a + b)ⁿ = Σₖ C(n,k) aⁿ⁻ᵏ bᵏ. Expande um binómio elevado a qualquer potência n usando coeficientes binomiais; o triângulo de Pascal fornece os coeficientes."}, sort_order: 87 },
  { id: 'dc-math-0088', deck_id: 'deck-math', front: 'Arithmetic Sequence', back: 'A sequence with a constant difference d between consecutive terms: aₙ = a₁ + (n-1)d. The sum of n terms is Sₙ = n/2 × (a₁ + aₙ).', front_translations: {"es":"Progresión aritmética","de":"Arithmetische Folge","fr":"Suite arithmétique","tr":"Aritmetik Dizi","nl":"Rekenkundige rij","ru":"Арифметическая прогрессия","zh":"等差数列","pt_BR":"Progressão aritmética","pt_PT":"Progressão aritmética"}, back_translations: {"es":"Una secuencia con diferencia constante d entre termos consecutivos: aₙ = a₁ + (n-1)d. La suma de n termos es Sₙ = n/2 × (a₁ + aₙ).","de":"Eine Folge mit einer konstanten Differenz d zwischen aufeinanderfolgenden Gliedern: aₙ = a₁ + (n-1)d. Die Summe von n Gliedern ist Sₙ = n/2 × (a₁ + aₙ).","fr":"Une suite avec une différence constante d entre les termes consécutifs : aₙ = a₁ + (n-1)d. La somme de n termes est Sₙ = n/2 × (a₁ + aₙ).","tr":"Ardışık terimler arasında sabit d farkı olan bir dizi: aₙ = a₁ + (n-1)d. n teriminin toplamı Sₙ = n/2 × (a₁ + aₙ).","nl":"Een rij met een constante verschil d tussen opeenvolgende termen: aₙ = a₁ + (n-1)d. De som van n termen is Sₙ = n/2 × (a₁ + aₙ).","ru":"Последовательность с постоянной разностью d между соседними членами: aₙ = a₁ + (n-1)d. Сумма n членов: Sₙ = n/2 × (a₁ + aₙ).","zh":"相邻项之间有常数差 d 的数列：aₙ = a₁ + (n-1)d。前 n 项之和为 Sₙ = n/2 × (a₁ + aₙ)。","pt_BR":"Uma sequência com diferença constante d entre termos consecutivos: aₙ = a₁ + (n-1)d. A soma de n termos é Sₙ = n/2 × (a₁ + aₙ).","pt_PT":"Uma sequência com diferença constante d entre termos consecutivos: aₙ = a₁ + (n-1)d. A soma de n termos é Sₙ = n/2 × (a₁ + aₙ)."}, sort_order: 88 },
  { id: 'dc-math-0089', deck_id: 'deck-math', front: 'Geometric Sequence', back: 'A sequence with a constant ratio r between consecutive terms: aₙ = a₁ × rⁿ⁻¹. The sum of n terms is Sₙ = a₁(1 - rⁿ)/(1 - r) for r ≠ 1.', front_translations: {"es":"Progresión geométrica","de":"Geometrische Folge","fr":"Suite géométrique","tr":"Geometrik Dizi","nl":"Meetkundige rij","ru":"Геометрическая прогрессия","zh":"等比数列","pt_BR":"Progressão geométrica","pt_PT":"Progressão geométrica"}, back_translations: {"es":"Una secuencia con razão constante r entre termos consecutivos: aₙ = a₁ × rⁿ⁻¹. La suma de n termos es Sₙ = a₁(1 - rⁿ)/(1 - r) para r ≠ 1.","de":"Eine Folge mit einem konstanten Verhältnis r zwischen aufeinanderfolgenden Gliedern: aₙ = a₁ × rⁿ⁻¹. Die Summe von n Gliedern ist Sₙ = a₁(1 - rⁿ)/(1 - r) für r ≠ 1.","fr":"Une suite avec un rapport constant r entre les termes consécutifs : aₙ = a₁ × rⁿ⁻¹. La somme de n termes est Sₙ = a₁(1 - rⁿ)/(1 - r) pour r ≠ 1.","tr":"Ardışık terimler arasında sabit r oranı olan bir dizi: aₙ = a₁ × rⁿ⁻¹. r ≠ 1 için n teriminin toplamı Sₙ = a₁(1 - rⁿ)/(1 - r).","nl":"Een rij met een constante verhouding r tussen opeenvolgende termen: aₙ = a₁ × rⁿ⁻¹. De som van n termen is Sₙ = a₁(1 - rⁿ)/(1 - r) voor r ≠ 1.","ru":"Последовательность с постоянным отношением r между соседними членами: aₙ = a₁ × rⁿ⁻¹. Сумма n членов: Sₙ = a₁(1 - rⁿ)/(1 - r) при r ≠ 1.","zh":"相邻项之间有常数比 r 的数列：aₙ = a₁ × rⁿ⁻¹。当 r ≠ 1 时，前 n 项之和为 Sₙ = a₁(1 - rⁿ)/(1 - r)。","pt_BR":"Uma sequência com razão constante r entre termos consecutivos: aₙ = a₁ × rⁿ⁻¹. A soma de n termos é Sₙ = a₁(1 - rⁿ)/(1 - r) para r ≠ 1.","pt_PT":"Uma sequência com razão constante r entre termos consecutivos: aₙ = a₁ × rⁿ⁻¹. A soma de n termos é Sₙ = a₁(1 - rⁿ)/(1 - r) para r ≠ 1."}, sort_order: 89 },
  { id: 'dc-math-0090', deck_id: 'deck-math', front: 'Infinite Geometric Series', back: 'S = a₁/(1 - r) for |r| < 1. An infinite geometric series converges to this sum only when the common ratio has absolute value less than 1.', front_translations: {"es":"Série geométrica infinita","de":"Unendliche geometrische Reihe","fr":"Série géométrique infinie","tr":"Sonsuz Geometrik Seri","nl":"Oneindige meetkundige reeks","ru":"Бесконечная геометрическая прогрессия","zh":"无穷等比级数","pt_BR":"Série geométrica infinita","pt_PT":"Série geométrica infinita"}, back_translations: {"es":"S = a₁/(1 - r) para |r| < 1. Una série geométrica infinita converge para esta suma solo cuando el valor absoluto de la razão comum es menor que 1.","de":"S = a₁/(1 - r) für |r| < 1. Eine unendliche geometrische Reihe konvergiert nur dann zu dieser Summe, wenn der Betrag des gemeinsamen Verhältnisses kleiner als 1 ist.","fr":"S = a₁/(1 - r) pour |r| < 1. Une série géométrique infinie converge vers cette somme uniquement lorsque la valeur absolue de la raison est inférieure à 1.","tr":"S = a₁/(1 - r), |r| < 1 için. Sonsuz bir geometrik seri, yalnızca ortak oranın mutlak değeri 1'den küçük olduğunda bu toplamda yakınsar.","nl":"S = a₁/(1 - r) voor |r| < 1. Een oneindige meetkundige reeks convergeert naar deze som alleen wanneer de absolute waarde van de gemeenschappelijke ratio kleiner is dan 1.","ru":"S = a₁/(1 - r) при |r| < 1. Бесконечная геометрическая прогрессия сходится к этой сумме только тогда, когда модуль знаменателя меньше 1.","zh":"S = a₁/(1 - r)，当 |r| < 1 时。无穷等比级数仅在公比的绝对值小于 1 时收敛到此和。","pt_BR":"S = a₁/(1 - r) para |r| < 1. Uma série geométrica infinita converge para esta soma apenas quando o valor absoluto da razão comum é menor que 1.","pt_PT":"S = a₁/(1 - r) para |r| < 1. Uma série geométrica infinita converge para esta soma apenas quando o valor absoluto da razão comum é menor que 1."}, sort_order: 90 },
  { id: 'dc-math-0091', deck_id: 'deck-math', front: 'Sum of First n Integers', back: 'Σk (k=1 to n) = n(n+1)/2. The sum 1 + 2 + 3 + ... + n equals n times (n+1) divided by 2; Gauss\'s formula.', front_translations: {"es":"Soma de los primeros n interos","de":"Summe der ersten n ganzen Zahlen","fr":"Somme des n premiers entiers","tr":"İlk n Tam Sayının Toplamı","nl":"Som van de eerste n gehele getallen","ru":"Сумма первых n натуральных чисел","zh":"前 n 个整数之和","pt_BR":"Soma dos primeiros n inteiros","pt_PT":"Soma dos primeiros n inteiros"}, back_translations: {"es":"Σk (k=1 a n) = n(n+1)/2. La suma 1 + 2 + 3 + ... + n es igual a n veces (n+1) dividido por 2; fórmula de Gauss.","de":"Σk (k=1 bis n) = n(n+1)/2. Die Summe 1 + 2 + 3 + ... + n ist gleich n mal (n+1) geteilt durch 2; Gaußsche Formel.","fr":"Σk (k=1 à n) = n(n+1)/2. La somme 1 + 2 + 3 + ... + n est égale à n fois (n+1) divisé par 2 ; formule de Gauss.","tr":"Σk (k=1'den n'ye) = n(n+1)/2. 1 + 2 + 3 + ... + n toplamı, n çarpı (n+1) bölü 2'ye eşittir; Gauss formülü.","nl":"Σk (k=1 tot n) = n(n+1)/2. De som 1 + 2 + 3 + ... + n is gelijk aan n maal (n+1) gedeeld door 2; de formule van Gauss.","ru":"Σk (k=1 до n) = n(n+1)/2. Сумма 1 + 2 + 3 + ... + n равна n умноженному на (n+1) и делённому на 2; формула Гаусса.","zh":"Σk (k=1 到 n) = n(n+1)/2。1 + 2 + 3 + ... + n 的和等于 n 乘以 (n+1) 除以 2；高斯公式。","pt_BR":"Σk (k=1 a n) = n(n+1)/2. A soma 1 + 2 + 3 + ... + n é igual a n vezes (n+1) dividido por 2; fórmula de Gauss.","pt_PT":"Σk (k=1 a n) = n(n+1)/2. A soma 1 + 2 + 3 + ... + n é igual a n vezes (n+1) dividido por 2; fórmula de Gauss."}, sort_order: 91 },
  { id: 'dc-math-0092', deck_id: 'deck-math', front: 'Sum of First n Squares', back: 'Σk² (k=1 to n) = n(n+1)(2n+1)/6. The sum of the first n perfect squares.', front_translations: {"es":"Soma de los primeros n cuadrados","de":"Summe der ersten n Quadratzahlen","fr":"Somme des n premiers carrés","tr":"İlk n Karenin Toplamı","nl":"Som van de eerste n kwadraten","ru":"Сумма первых n квадратов","zh":"前 n 个完全平方数之和","pt_BR":"Soma dos primeiros n quadrados","pt_PT":"Soma dos primeiros n quadrados"}, back_translations: {"es":"Σk² (k=1 a n) = n(n+1)(2n+1)/6. La suma de los primeros n cuadrados perfeitos.","de":"Σk² (k=1 bis n) = n(n+1)(2n+1)/6. Die Summe der ersten n Quadratzahlen.","fr":"Σk² (k=1 à n) = n(n+1)(2n+1)/6. La somme des n premiers carrés parfaits.","tr":"Σk² (k=1'den n'ye) = n(n+1)(2n+1)/6. İlk n tam karenin toplamı.","nl":"Σk² (k=1 tot n) = n(n+1)(2n+1)/6. De som van de eerste n kwadraten.","ru":"Σk² (k=1 до n) = n(n+1)(2n+1)/6. Сумма первых n точных квадратов.","zh":"Σk² (k=1 到 n) = n(n+1)(2n+1)/6。前 n 个完全平方数之和。","pt_BR":"Σk² (k=1 a n) = n(n+1)(2n+1)/6. A soma dos primeiros n quadrados perfeitos.","pt_PT":"Σk² (k=1 a n) = n(n+1)(2n+1)/6. A soma dos primeiros n quadrados perfeitos."}, sort_order: 92 },
  { id: 'dc-math-0093', deck_id: 'deck-math', front: 'Matrix Addition', back: 'Matrices of the same dimensions are added element-by-element: (A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ. The dimensions of the result are the same as the original matrices.', front_translations: {"es":"Adición de matrizes","de":"Matrizenaddition","fr":"Addition de matrices","tr":"Matris Toplama","nl":"Matrixoptelling","ru":"Сложение матриц","zh":"矩阵加法","pt_BR":"Adição de matrizes","pt_PT":"Adição de matrizes"}, back_translations: {"es":"Matrizes de las mismas dimensões son somadas elemento a elemento: (A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ. As dimensões del resultado son las mismas de las matrizes originais.","de":"Matrizen gleicher Dimensionen werden elementweise addiert: (A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ. Die Dimensionen des Ergebnisses sind dieselben wie die der ursprünglichen Matrizen.","fr":"Les matrices de mêmes dimensions sont additionnées élément par élément : (A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ. Les dimensions du résultat sont les mêmes que celles des matrices originales.","tr":"Aynı boyutlardaki matrisler eleman bazında toplanır: (A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ. Sonucun boyutları orijinal matrislerle aynıdır.","nl":"Matrices van dezelfde afmetingen worden element voor element opgeteld: (A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ. De afmetingen van het resultaat zijn hetzelfde als de oorspronkelijke matrices.","ru":"Матрицы одинаковых размерностей складываются поэлементно: (A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ. Размерность результата совпадает с размерностью исходных матриц.","zh":"相同维度的矩阵逐元素相加：(A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ。结果的维度与原始矩阵相同。","pt_BR":"Matrizes das mesmas dimensões são somadas elemento a elemento: (A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ. As dimensões do resultado são as mesmas das matrizes originais.","pt_PT":"Matrizes das mesmas dimensões são somadas elemento a elemento: (A+B)ᵢⱼ = Aᵢⱼ + Bᵢⱼ. As dimensões do resultado são as mesmas das matrizes originais."}, sort_order: 93 },
  { id: 'dc-math-0094', deck_id: 'deck-math', front: 'Matrix Multiplication', back: '(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ. Multiply row i of A by column j of B (dot product); requires the number of columns in A to equal the number of rows in B.', front_translations: {"es":"Multiplicación de matrizes","de":"Matrizenmultiplikation","fr":"Multiplication de matrices","tr":"Matris Çarpımı","nl":"Matrixvermenigvuldiging","ru":"Умножение матриц","zh":"矩阵乘法","pt_BR":"Multiplicação de matrizes","pt_PT":"Multiplicação de matrizes"}, back_translations: {"es":"(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ. Multiplique a línea i de A por la columna j de B (producto escalar); requiere que el número de colunas de A seja igual al número de líneas de B.","de":"(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ. Multipliziere Zeile i von A mit Spalte j von B (Skalarprodukt); die Spaltenzahl von A muss der Zeilenzahl von B entsprechen.","fr":"(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ. Multiplier la ligne i de A par la colonne j de B (produit scalaire) ; le nombre de colonnes de A doit être égal au nombre de lignes de B.","tr":"(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ. A'nın i. satırını B'nin j. sütunuyla çarp (nokta çarpımı); A'nın sütun sayısı B'nin satır sayısına eşit olmalıdır.","nl":"(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ. Vermenigvuldig rij i van A met kolom j van B (inproduct); het aantal kolommen van A moet gelijk zijn aan het aantal rijen van B.","ru":"(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ. Умножьте строку i матрицы A на столбец j матрицы B (скалярное произведение); число столбцов A должно равняться числу строк B.","zh":"(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ。A 的第 i 行乘以 B 的第 j 列（点积）；要求 A 的列数等于 B 的行数。","pt_BR":"(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ. Multiplique a linha i de A pela coluna j de B (produto escalar); requer que o número de colunas de A seja igual ao número de linhas de B.","pt_PT":"(AB)ᵢⱼ = Σₖ AᵢₖBₖⱼ. Multiplique a linha i de A pela coluna j de B (produto escalar); requer que o número de colunas de A seja igual ao número de linhas de B."}, sort_order: 94 },
  { id: 'dc-math-0095', deck_id: 'deck-math', front: 'Determinant of a 2×2 Matrix', back: 'det([[a,b],[c,d]]) = ad - bc. The determinant measures the scaling factor of the linear transformation; a zero determinant means the matrix is singular (non-invertible).', front_translations: {"es":"Determinante de una matriz 2×2","de":"Determinante einer 2×2-Matrix","fr":"Déterminant d'une matrice 2×2","tr":"2×2 Matrisin Determinantı","nl":"Determinant van een 2×2-matrix","ru":"Определитель матрицы 2×2","zh":"2×2 矩阵的行列式","pt_BR":"Determinante de uma matriz 2×2","pt_PT":"Determinante de uma matriz 2×2"}, back_translations: {"es":"det([[a,b],[c,d]]) = ad - bc. El determinante mide el fator de escala de la transformación linear; un determinante zero significa que a matriz es singular (no invertible).","de":"det([[a,b],[c,d]]) = ad - bc. Die Determinante misst den Skalierungsfaktor der linearen Transformation; eine Null-Determinante bedeutet, dass die Matrix singulär (nicht invertierbar) ist.","fr":"det([[a,b],[c,d]]) = ad - bc. Le déterminant mesure le facteur d'échelle de la transformation linéaire ; un déterminant nul signifie que la matrice est singulière (non inversible).","tr":"det([[a,b],[c,d]]) = ad - bc. Determinant, doğrusal dönüşümün ölçekleme faktörünü ölçer; sıfır determinant, matrisin tekil (tersi alınamaz) olduğu anlamına gelir.","nl":"det([[a,b],[c,d]]) = ad - bc. De determinant meet de schaalfactor van de lineaire transformatie; een nuldeterminant betekent dat de matrix singulier (niet-inverteerbaar) is.","ru":"det([[a,b],[c,d]]) = ad - bc. Определитель измеряет масштабный коэффициент линейного преобразования; нулевой определитель означает, что матрица вырожденная (необратимая).","zh":"det([[a,b],[c,d]]) = ad - bc。行列式衡量线性变换的缩放因子；行列式为零意味着矩阵是奇异的（不可逆的）。","pt_BR":"det([[a,b],[c,d]]) = ad - bc. O determinante mede o fator de escala da transformação linear; um determinante zero significa que a matriz é singular (não invertível).","pt_PT":"det([[a,b],[c,d]]) = ad - bc. O determinante mede o factor de escala da transformação linear; um determinante zero significa que a matriz é singular (não invertível)."}, sort_order: 95 },
  { id: 'dc-math-0096', deck_id: 'deck-math', front: 'Inverse of a 2×2 Matrix', back: 'A⁻¹ = (1/det(A)) × [[d,-b],[-c,a]] for A = [[a,b],[c,d]]. Exists only if det(A) ≠ 0; A × A⁻¹ = I (identity matrix).', front_translations: {"es":"Inversa de una matriz 2×2","de":"Inverse einer 2×2-Matrix","fr":"Inverse d'une matrice 2×2","tr":"2×2 Matrisin Tersi","nl":"Inverse van een 2×2-matrix","ru":"Обратная матрица 2×2","zh":"2×2 矩阵的逆矩阵","pt_BR":"Inversa de uma matriz 2×2","pt_PT":"Inversa de uma matriz 2×2"}, back_translations: {"es":"La⁻¹ = (1/det(A)) × [[d,-b],[-c,a]] para A = [[a,b],[c,d]]. Existe solo se det(A) ≠ 0; La × A⁻¹ = I (matriz identidad).","de":"A⁻¹ = (1/det(A)) × [[d,-b],[-c,a]] für A = [[a,b],[c,d]]. Existiert nur wenn det(A) ≠ 0; A × A⁻¹ = I (Einheitsmatrix).","fr":"A⁻¹ = (1/det(A)) × [[d,-b],[-c,a]] pour A = [[a,b],[c,d]]. N'existe que si det(A) ≠ 0 ; A × A⁻¹ = I (matrice identité).","tr":"A = [[a,b],[c,d]] için A⁻¹ = (1/det(A)) × [[d,-b],[-c,a]]. Yalnızca det(A) ≠ 0 ise vardır; A × A⁻¹ = I (birim matris).","nl":"A⁻¹ = (1/det(A)) × [[d,-b],[-c,a]] voor A = [[a,b],[c,d]]. Bestaat alleen als det(A) ≠ 0; A × A⁻¹ = I (eenheidsmatrix).","ru":"A⁻¹ = (1/det(A)) × [[d,-b],[-c,a]] для A = [[a,b],[c,d]]. Существует только если det(A) ≠ 0; A × A⁻¹ = I (единичная матрица).","zh":"对 A = [[a,b],[c,d]]，A⁻¹ = (1/det(A)) × [[d,-b],[-c,a]]。仅当 det(A) ≠ 0 时存在；A × A⁻¹ = I（单位矩阵）。","pt_BR":"A⁻¹ = (1/det(A)) × [[d,-b],[-c,a]] para A = [[a,b],[c,d]]. Existe apenas se det(A) ≠ 0; A × A⁻¹ = I (matriz identidade).","pt_PT":"A⁻¹ = (1/det(A)) × [[d,-b],[-c,a]] para A = [[a,b],[c,d]]. Existe apenas se det(A) ≠ 0; A × A⁻¹ = I (matriz identidade)."}, sort_order: 96 },
  { id: 'dc-math-0097', deck_id: 'deck-math', front: 'Vector Dot Product', back: 'a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃. The dot product is a scalar; zero when vectors are perpendicular (θ = 90°).', front_translations: {"es":"Produto escalar de vetores","de":"Skalarprodukt von Vektoren","fr":"Produit scalaire de vecteurs","tr":"Vektör Nokta Çarpımı","nl":"Vectorinproduct","ru":"Скалярное произведение векторов","zh":"向量点积","pt_BR":"Produto escalar de vetores","pt_PT":"Produto escalar de vetores"}, back_translations: {"es":"a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃. El producto escalar es un escalar; zero cuando los vetores son perpendiculares (θ = 90°).","de":"a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃. Das Skalarprodukt ist ein Skalar; null wenn die Vektoren senkrecht zueinander sind (θ = 90°).","fr":"a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃. Le produit scalaire est un scalaire ; nul quand les vecteurs sont perpendiculaires (θ = 90°).","tr":"a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃. Nokta çarpım bir skalerdir; vektörler dik olduğunda (θ = 90°) sıfırdır.","nl":"a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃. Het inproduct is een scalair; nul wanneer vectoren loodrecht staan (θ = 90°).","ru":"a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃. Скалярное произведение — это скаляр; равно нулю, когда векторы перпендикулярны (θ = 90°).","zh":"a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃。点积是标量；当向量垂直时（θ = 90°）为零。","pt_BR":"a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃. O produto escalar é um escalar; zero quando os vetores são perpendiculares (θ = 90°).","pt_PT":"a · b = |a||b|cos(θ) = a₁b₁ + a₂b₂ + a₃b₃. O produto escalar é um escalar; zero quando os vetores são perpendiculares (θ = 90°)."}, sort_order: 97 },
  { id: 'dc-math-0098', deck_id: 'deck-math', front: 'Vector Cross Product', back: 'a × b produces a vector perpendicular to both a and b with magnitude |a||b|sin(θ). Only defined in 3D; the direction follows the right-hand rule.', front_translations: {"es":"Produto vetorial","de":"Kreuzprodukt von Vektoren","fr":"Produit vectoriel","tr":"Vektörel Çarpım","nl":"Vectorkruisproduct","ru":"Векторное произведение","zh":"向量叉积","pt_BR":"Produto vetorial","pt_PT":"Produto vetorial"}, back_translations: {"es":"a × b produce un vetor perpendicular a ambos a y b con magnitude |a||b|sin(θ). Solo definido en 3D; a dirección sigue a regra de la mano direita.","de":"a × b erzeugt einen zu beiden Vektoren a und b senkrechten Vektor mit Betrag |a||b|sin(θ). Nur in 3D definiert; die Richtung folgt der Rechte-Hand-Regel.","fr":"a × b produit un vecteur perpendiculaire à la fois à a et b avec un module |a||b|sin(θ). Seulement défini en 3D ; la direction suit la règle de la main droite.","tr":"a × b, hem a hem de b'ye dik, büyüklüğü |a||b|sin(θ) olan bir vektör üretir. Yalnızca 3B'de tanımlıdır; yön sağ el kuralını izler.","nl":"a × b produceert een vector loodrecht op zowel a als b met grootte |a||b|sin(θ). Alleen gedefinieerd in 3D; de richting volgt de rechterhandregel.","ru":"a × b даёт вектор, перпендикулярный обоим a и b, с модулем |a||b|sin(θ). Определено только в 3D; направление определяется правилом правой руки.","zh":"a × b 产生一个同时垂直于 a 和 b 的向量，其大小为 |a||b|sin(θ)。仅在三维中定义；方向遵循右手定则。","pt_BR":"a × b produz um vetor perpendicular a ambos a e b com magnitude |a||b|sin(θ). Apenas definido em 3D; a direção segue a regra da mão direita.","pt_PT":"a × b produz um vetor perpendicular a ambos a e b com magnitude |a||b|sin(θ). Apenas definido em 3D; a direcção segue a regra da mão direita."}, sort_order: 98 },
  { id: 'dc-math-0099', deck_id: 'deck-math', front: 'Euler\'s Formula', back: 'e^(iθ) = cos(θ) + i·sin(θ). Connects the exponential function to trigonometry via imaginary numbers; Euler\'s identity e^(iπ) + 1 = 0 is a special case.', front_translations: {"es":"Fórmula de Euler","de":"Eulersche Formel","fr":"Formule d'Euler","tr":"Euler Formülü","nl":"Formule van Euler","ru":"Формула Эйлера","zh":"欧拉公式","pt_BR":"Fórmula de Euler","pt_PT":"Fórmula de Euler"}, back_translations: {"es":"y^(iθ) = cos(θ) + i·sin(θ). Conecta a función exponencial a la trigonometria via números imaginários; a identidad de Euler y^(iπ) + 1 = 0 es un caso especial.","de":"e^(iθ) = cos(θ) + i·sin(θ). Verbindet die Exponentialfunktion über imaginäre Zahlen mit der Trigonometrie; Eulers Identität e^(iπ) + 1 = 0 ist ein Spezialfall.","fr":"e^(iθ) = cos(θ) + i·sin(θ). Relie la fonction exponentielle à la trigonométrie via les nombres imaginaires ; l'identité d'Euler e^(iπ) + 1 = 0 en est un cas particulier.","tr":"e^(iθ) = cos(θ) + i·sin(θ). Üstel fonksiyonu, sanal sayılar aracılığıyla trigonometriyle ilişkilendirir; Euler kimliği e^(iπ) + 1 = 0 özel bir durumdur.","nl":"e^(iθ) = cos(θ) + i·sin(θ). Verbindt de exponentiële functie met trigonometrie via imaginaire getallen; Eulers identiteit e^(iπ) + 1 = 0 is een speciaal geval.","ru":"e^(iθ) = cos(θ) + i·sin(θ). Связывает показательную функцию с тригонометрией через мнимые числа; тождество Эйлера e^(iπ) + 1 = 0 — частный случай.","zh":"e^(iθ) = cos(θ) + i·sin(θ)。通过虚数将指数函数与三角函数联系起来；欧拉恒等式 e^(iπ) + 1 = 0 是其特例。","pt_BR":"e^(iθ) = cos(θ) + i·sin(θ). Conecta a função exponencial à trigonometria via números imaginários; a identidade de Euler e^(iπ) + 1 = 0 é um caso especial.","pt_PT":"e^(iθ) = cos(θ) + i·sin(θ). Liga a função exponencial à trigonometria via números imaginários; a identidade de Euler e^(iπ) + 1 = 0 é um caso especial."}, sort_order: 99 },
  { id: 'dc-math-0100', deck_id: 'deck-math', front: 'Complex Number', back: 'A number of the form a + bi where a is the real part, b is the imaginary part, and i = √(-1). Complex numbers extend the real number line to a 2D plane.', front_translations: {"es":"Número complexo","de":"Komplexe Zahl","fr":"Nombre complexe","tr":"Karmaşık Sayı","nl":"Complex getal","ru":"Комплексное число","zh":"复数","pt_BR":"Número complexo","pt_PT":"Número complexo"}, back_translations: {"es":"Un número de la forma a + bi donde a es a parte real, b es a parte imaginária y i = √(-1). Los números complexos estendem a reta real para un plano 2D.","de":"Eine Zahl der Form a + bi, wobei a der Realteil, b der Imaginärteil und i = √(-1) ist. Komplexe Zahlen erweitern die reelle Zahlengeraden auf eine 2D-Ebene.","fr":"Un nombre de la forme a + bi où a est la partie réelle, b la partie imaginaire et i = √(-1). Les nombres complexes étendent la droite réelle à un plan 2D.","tr":"a + bi formunda bir sayı; a reel kısım, b sanal kısım ve i = √(-1). Karmaşık sayılar, reel sayı doğrusunu 2B düzleme genişletir.","nl":"Een getal van de vorm a + bi waarbij a het reële deel, b het imaginaire deel en i = √(-1) is. Complexe getallen breiden de reële getallenlijn uit naar een 2D-vlak.","ru":"Число вида a + bi, где a — вещественная часть, b — мнимая часть, и i = √(-1). Комплексные числа расширяют вещественную числовую прямую до двумерной плоскости.","zh":"形如 a + bi 的数，其中 a 为实部，b 为虚部，i = √(-1)。复数将实数轴扩展到二维平面。","pt_BR":"Um número da forma a + bi onde a é a parte real, b é a parte imaginária e i = √(-1). Os números complexos estendem a reta real para um plano 2D.","pt_PT":"Um número da forma a + bi onde a é a parte real, b é a parte imaginária e i = √(-1). Os números complexos estendem a recta real para um plano 2D."}, sort_order: 100 },
  { id: 'dc-math-0101', deck_id: 'deck-math', front: 'Prime Number', back: 'A natural number greater than 1 that has no positive divisors other than 1 and itself. The first primes are 2, 3, 5, 7, 11, 13... There are infinitely many primes.', front_translations: {"es":"Número primo","de":"Primzahl","fr":"Nombre premier","tr":"Asal Sayı","nl":"Priemgetal","ru":"Простое число","zh":"质数","pt_BR":"Número primo","pt_PT":"Número primo"}, back_translations: {"es":"Un número natural mayor que 1 que no tiene divisores positivos além de 1 y si mismo. Los primeros primos son 2, 3, 5, 7, 11, 13... Há infinitos números primos.","de":"Eine natürliche Zahl größer als 1, die keine positiven Teiler außer 1 und sich selbst hat. Die ersten Primzahlen sind 2, 3, 5, 7, 11, 13... Es gibt unendlich viele Primzahlen.","fr":"Un nombre naturel supérieur à 1 qui n'a pas d'autres diviseurs positifs que 1 et lui-même. Les premiers nombres premiers sont 2, 3, 5, 7, 11, 13... Il y en a une infinité.","tr":"1 ve kendisi dışında pozitif bölen olmayan, 1'den büyük doğal sayı. İlk asal sayılar 2, 3, 5, 7, 11, 13... Sonsuz sayıda asal sayı vardır.","nl":"Een natuurlijk getal groter dan 1 dat geen positieve delers heeft behalve 1 en zichzelf. De eerste priemgetallen zijn 2, 3, 5, 7, 11, 13... Er zijn oneindig veel priemgetallen.","ru":"Натуральное число больше 1, не имеющее положительных делителей, кроме 1 и самого себя. Первые простые числа: 2, 3, 5, 7, 11, 13... Простых чисел бесконечно много.","zh":"大于 1 的自然数，除 1 和其本身外没有其他正因数。最小的质数是 2, 3, 5, 7, 11, 13...质数有无穷多个。","pt_BR":"Um número natural maior que 1 que não tem divisores positivos além de 1 e si mesmo. Os primeiros primos são 2, 3, 5, 7, 11, 13... Há infinitos números primos.","pt_PT":"Um número natural maior que 1 que não tem divisores positivos além de 1 e si mesmo. Os primeiros primos são 2, 3, 5, 7, 11, 13... Há infinitos números primos."}, sort_order: 101 },
  { id: 'dc-math-0102', deck_id: 'deck-math', front: 'Fundamental Theorem of Arithmetic', back: 'Every integer greater than 1 can be expressed uniquely as a product of prime factors (ignoring order). This factorization is unique for every integer.', front_translations: {"es":"Teorema fundamental de la aritmética","de":"Fundamentalsatz der Arithmetik","fr":"Théorème fondamental de l'arithmétique","tr":"Aritmetiğin Temel Teoremi","nl":"Fundamentele stelling van de rekenkunde","ru":"Основная теорема арифметики","zh":"算术基本定理","pt_BR":"Teorema fundamental da aritmética","pt_PT":"Teorema fundamental da aritmética"}, back_translations: {"es":"Todo intero mayor que 1 puede ser expresso de forma única como producto de fatores primos (ignorando a ordem). Esta fatoración es única para cada intero.","de":"Jede ganze Zahl größer als 1 lässt sich eindeutig als Produkt von Primfaktoren darstellen (ohne Berücksichtigung der Reihenfolge). Diese Faktorisierung ist für jede ganze Zahl eindeutig.","fr":"Tout entier supérieur à 1 peut être exprimé de façon unique comme produit de facteurs premiers (en ignorant l'ordre). Cette factorisation est unique pour chaque entier.","tr":"1'den büyük her tam sayı, asal çarpanların çarpımı olarak benzersiz biçimde ifade edilebilir (sıra gözetilmeksizin). Bu çarpanlara ayırma her tam sayı için benzersizdir.","nl":"Elk geheel getal groter dan 1 kan uniek worden uitgedrukt als een product van priemfactoren (ongeacht volgorde). Deze factorisatie is uniek voor elk geheel getal.","ru":"Каждое целое число, большее 1, может быть единственным образом представлено в виде произведения простых множителей (без учёта порядка). Это разложение единственно для каждого целого числа.","zh":"每个大于 1 的整数都可以唯一地表示为质因数之积（忽略顺序）。这种分解对每个整数都是唯一的。","pt_BR":"Todo inteiro maior que 1 pode ser expresso de forma única como produto de fatores primos (ignorando a ordem). Esta fatoração é única para cada inteiro.","pt_PT":"Todo inteiro maior que 1 pode ser expresso de forma única como produto de factores primos (ignorando a ordem). Esta fatoração é única para cada inteiro."}, sort_order: 102 },
  { id: 'dc-math-0103', deck_id: 'deck-math', front: 'Greatest Common Divisor (GCD)', back: 'The largest positive integer that divides two numbers without a remainder. The Euclidean algorithm efficiently computes GCD: GCD(a,b) = GCD(b, a mod b).', front_translations: {"es":"Máximo Divisor Comum (MDC)","de":"Größter gemeinsamer Teiler (ggT)","fr":"Plus grand commun diviseur (PGCD)","tr":"En Büyük Ortak Bölen (EBOB)","nl":"Grootste gemene deler (GGD)","ru":"Наибольший общий делитель (НОД)","zh":"最大公因数（GCD）","pt_BR":"Máximo Divisor Comum (MDC)","pt_PT":"Máximo Divisor Comum (MDC)"}, back_translations: {"es":"El mayor intero positivo que divide de los números sin resto. El algoritmo de Euclides calcula el MDC eficientemente: MDC(a,b) = MDC(b, a mod b).","de":"Die größte positive ganze Zahl, die zwei Zahlen ohne Rest teilt. Der Euklidische Algorithmus berechnet den ggT effizient: ggT(a,b) = ggT(b, a mod b).","fr":"Le plus grand entier positif qui divise deux nombres sans reste. L'algorithme d'Euclide calcule efficacement le PGCD : PGCD(a,b) = PGCD(b, a mod b).","tr":"İki sayıyı kalansız bölen en büyük pozitif tam sayı. Öklid algoritması EBOB'u verimli biçimde hesaplar: EBOB(a,b) = EBOB(b, a mod b).","nl":"Het grootste positieve gehele getal dat twee getallen deelt zonder rest. Het algoritme van Euclides berekent efficiënt de GGD: GGD(a,b) = GGD(b, a mod b).","ru":"Наибольшее натуральное число, делящее оба числа без остатка. Алгоритм Евклида эффективно вычисляет НОД: НОД(a,b) = НОД(b, a mod b).","zh":"整除两个数（无余数）的最大正整数。欧几里得算法高效计算 GCD：GCD(a,b) = GCD(b, a mod b)。","pt_BR":"O maior inteiro positivo que divide dois números sem resto. O algoritmo de Euclides calcula o MDC eficientemente: MDC(a,b) = MDC(b, a mod b).","pt_PT":"O maior inteiro positivo que divide dois números sem resto. O algoritmo de Euclides calcula o MDC eficientemente: MDC(a,b) = MDC(b, a mod b)."}, sort_order: 103 },
  { id: 'dc-math-0104', deck_id: 'deck-math', front: 'Least Common Multiple (LCM)', back: 'The smallest positive integer divisible by both a and b. LCM(a,b) = (a × b) / GCD(a,b); useful for adding fractions with different denominators.', front_translations: {"es":"Mínimo Múltiplo Comum (MMC)","de":"Kleinstes gemeinsames Vielfaches (kgV)","fr":"Plus petit commun multiple (PPCM)","tr":"En Küçük Ortak Kat (EKOK)","nl":"Kleinste gemene veelvoud (KGV)","ru":"Наименьшее общее кратное (НОК)","zh":"最小公倍数（LCM）","pt_BR":"Mínimo Múltiplo Comum (MMC)","pt_PT":"Mínimo Múltiplo Comum (MMC)"}, back_translations: {"es":"El menor intero positivo divisible por a y b. MMC(a,b) = (a × b) / MDC(a,b); útil para somar fracciones con denominadores diferentes.","de":"Die kleinste positive ganze Zahl, die sowohl durch a als auch durch b teilbar ist. kgV(a,b) = (a × b) / ggT(a,b); nützlich zum Addieren von Brüchen mit verschiedenen Nennern.","fr":"Le plus petit entier positif divisible par a et b. PPCM(a,b) = (a × b) / PGCD(a,b) ; utile pour additionner des fractions de dénominateurs différents.","tr":"Hem a hem de b'ye bölünebilen en küçük pozitif tam sayı. EKOK(a,b) = (a × b) / EBOB(a,b); farklı paydalarla kesir toplamak için kullanışlıdır.","nl":"Het kleinste positieve gehele getal dat deelbaar is door zowel a als b. KGV(a,b) = (a × b) / GGD(a,b); handig voor het optellen van breuken met verschillende noemers.","ru":"Наименьшее натуральное число, делящееся и на a, и на b. НОК(a,b) = (a × b) / НОД(a,b); полезно при сложении дробей с разными знаменателями.","zh":"能被 a 和 b 整除的最小正整数。LCM(a,b) = (a × b) / GCD(a,b)；用于不同分母的分数相加。","pt_BR":"O menor inteiro positivo divisível por a e b. MMC(a,b) = (a × b) / MDC(a,b); útil para somar frações com denominadores diferentes.","pt_PT":"O menor inteiro positivo divisível por a e b. MMC(a,b) = (a × b) / MDC(a,b); útil para somar frações com denominadores diferentes."}, sort_order: 104 },
  { id: 'dc-math-0105', deck_id: 'deck-math', front: 'Modular Arithmetic', back: 'a ≡ b (mod n) means a and b have the same remainder when divided by n. It is the mathematics of remainders, fundamental to cryptography and computer science.', front_translations: {"es":"Aritmética modular","de":"Modulare Arithmetik","fr":"Arithmétique modulaire","tr":"Modüler Aritmetik","nl":"Modulaire rekenkunde","ru":"Модульная арифметика","zh":"模运算","pt_BR":"Aritmética modular","pt_PT":"Aritmética modular"}, back_translations: {"es":"a ≡ b (mod n) significa que a y b tienen el mismo resto cuando divididos por n. É a matemática de los restos, fundamental para criptografia y ciencia de la computación.","de":"a ≡ b (mod n) bedeutet, dass a und b bei Division durch n denselben Rest haben. Es ist die Mathematik der Reste, grundlegend für Kryptographie und Informatik.","fr":"a ≡ b (mod n) signifie que a et b ont le même reste lors de la division par n. C'est la mathématique des restes, fondamentale en cryptographie et en informatique.","tr":"a ≡ b (mod n), a ve b'nin n'ye bölündüğünde aynı kalanı verdiği anlamına gelir. Kriptografi ve bilgisayar biliminin temeli olan kalanlar matematiğidir.","nl":"a ≡ b (mod n) betekent dat a en b hetzelfde restant hebben bij deling door n. Het is de wiskunde van resten, fundamenteel voor cryptografie en informatica.","ru":"a ≡ b (mod n) означает, что a и b дают одинаковый остаток при делении на n. Это математика остатков, фундаментальная для криптографии и информатики.","zh":"a ≡ b (mod n) 表示 a 和 b 除以 n 的余数相同。这是余数数学，是密码学和计算机科学的基础。","pt_BR":"a ≡ b (mod n) significa que a e b têm o mesmo resto quando divididos por n. É a matemática dos restos, fundamental para criptografia e ciência da computação.","pt_PT":"a ≡ b (mod n) significa que a e b têm o mesmo resto quando divididos por n. É a matemática dos restos, fundamental para criptografia e ciência da computação."}, sort_order: 105 },
  { id: 'dc-math-0106', deck_id: 'deck-math', front: 'Rational vs. Irrational Numbers', back: 'Rational numbers can be expressed as p/q where p,q are integers and q ≠ 0 (e.g., 1/2, 0.75). Irrational numbers cannot (e.g., √2, π, e); their decimal expansions never repeat.', front_translations: {"es":"Números racionais vs. irracionais","de":"Rationale vs. irrationale Zahlen","fr":"Nombres rationnels et irrationnels","tr":"Rasyonel ve İrrasyonel Sayılar","nl":"Rationale vs. irrationele getallen","ru":"Рациональные и иррациональные числа","zh":"有理数与无理数","pt_BR":"Números racionais vs. irracionais","pt_PT":"Números racionais vs. irracionais"}, back_translations: {"es":"Números racionais pueden ser expressos como p/q donde p, q son interos y q ≠ 0 (ex.: 1/2, 0,75). Irracionais no pueden (ex.: √2, π, y); sus expansões decimais nunca se repetem.","de":"Rationale Zahlen können als p/q ausgedrückt werden, wobei p, q ganze Zahlen und q ≠ 0 sind (z.B. 1/2, 0,75). Irrationale Zahlen können es nicht (z.B. √2, π, e); ihre Dezimalentwicklungen wiederholen sich nie.","fr":"Les nombres rationnels peuvent être exprimés sous la forme p/q où p,q sont des entiers et q ≠ 0 (ex. 1/2, 0,75). Les irrationnels ne le peuvent pas (ex. √2, π, e) ; leurs développements décimaux ne se répètent jamais.","tr":"Rasyonel sayılar, p ve q tam sayı ve q ≠ 0 olmak üzere p/q biçiminde ifade edilebilir (örn. 1/2, 0,75). İrrasyonel sayılar ifade edilemez (örn. √2, π, e); ondalık açılımları hiçbir zaman tekrarlanmaz.","nl":"Rationale getallen kunnen worden uitgedrukt als p/q waarbij p, q gehele getallen zijn en q ≠ 0 (bijv. 1/2, 0,75). Irrationele getallen niet (bijv. √2, π, e); hun decimale uitbreidingen herhalen zich nooit.","ru":"Рациональные числа можно выразить в виде p/q, где p, q — целые числа и q ≠ 0 (напр., 1/2, 0,75). Иррациональные — нельзя (напр., √2, π, e); их десятичные разложения никогда не повторяются.","zh":"有理数可表示为 p/q，其中 p、q 为整数且 q ≠ 0（如 1/2、0.75）。无理数不能（如 √2、π、e）；其小数展开永不循环。","pt_BR":"Números racionais podem ser expressos como p/q onde p, q são inteiros e q ≠ 0 (ex.: 1/2, 0,75). Irracionais não podem (ex.: √2, π, e); suas expansões decimais nunca se repetem.","pt_PT":"Números racionais podem ser expressos como p/q onde p, q são inteiros e q ≠ 0 (ex.: 1/2, 0,75). Irracionais não podem (ex.: √2, π, e); as suas expansões decimais nunca se repetem."}, sort_order: 106 },
  { id: 'dc-math-0107', deck_id: 'deck-math', front: 'Proof by Induction', back: 'A two-step proof method: (1) Base case: verify P(1) is true; (2) Inductive step: assume P(k) is true, then prove P(k+1) is true. Together these prove P(n) for all n ≥ 1.', front_translations: {"es":"Prova por indución","de":"Beweis durch vollständige Induktion","fr":"Démonstration par récurrence","tr":"Tümevarım ile İspat","nl":"Bewijs door inductie","ru":"Доказательство по индукции","zh":"数学归纳法","pt_BR":"Prova por indução","pt_PT":"Prova por indução"}, back_translations: {"es":"Un método de prueba en de los passos: (1) Caso base: verificar que P(1) es verdadero; (2) Passo indutivo: assumir P(k) verdadero, después provar P(k+1) verdadero. Juntos provam P(n) para todo n ≥ 1.","de":"Eine zweistufige Beweismethode: (1) Basisfall: P(1) ist wahr; (2) Induktionsschritt: Wenn P(k) wahr ist, dann ist P(k+1) wahr. Zusammen beweisen sie P(n) für alle n ≥ 1.","fr":"Une méthode de preuve en deux étapes : (1) Cas de base : vérifier que P(1) est vrai ; (2) Étape d'induction : supposer P(k) vrai, puis prouver P(k+1) vrai. Ensemble, ils prouvent P(n) pour tout n ≥ 1.","tr":"İki adımlı ispat yöntemi: (1) Taban durumu: P(1)'in doğru olduğunu doğrula; (2) Tümevarım adımı: P(k)'nın doğru olduğunu varsay, ardından P(k+1)'in doğru olduğunu kanıtla. Birlikte tüm n ≥ 1 için P(n)'yi kanıtlarlar.","nl":"Een tweestapsmethode: (1) Basisgeval: verifieer dat P(1) waar is; (2) Inductiestap: stel P(k) waar is, bewijs dan dat P(k+1) waar is. Samen bewijzen ze P(n) voor alle n ≥ 1.","ru":"Двухшаговый метод доказательства: (1) База: убедиться, что P(1) истинно; (2) Шаг индукции: предположить, что P(k) истинно, затем доказать P(k+1). Вместе они доказывают P(n) для всех n ≥ 1.","zh":"两步证明方法：(1) 基础情形：验证 P(1) 成立；(2) 归纳步骤：假设 P(k) 成立，证明 P(k+1) 成立。两者合起来证明对所有 n ≥ 1，P(n) 成立。","pt_BR":"Um método de prova em dois passos: (1) Caso base: verificar que P(1) é verdadeiro; (2) Passo indutivo: assumir P(k) verdadeiro, depois provar P(k+1) verdadeiro. Juntos provam P(n) para todo n ≥ 1.","pt_PT":"Um método de prova em dois passos: (1) Caso base: verificar que P(1) é verdadeiro; (2) Passo indutivo: assumir P(k) verdadeiro, depois provar P(k+1) verdadeiro. Juntos provam P(n) para todo n ≥ 1."}, sort_order: 107 },
  { id: 'dc-math-0108', deck_id: 'deck-math', front: 'Proof by Contradiction', back: 'Assume the negation of the statement to be proved; derive a logical contradiction; conclude the original statement must be true. Used to prove √2 is irrational.', front_translations: {"es":"Prova por contradición","de":"Beweis durch Widerspruch","fr":"Démonstration par l'absurde","tr":"Çelişki ile İspat","nl":"Bewijs door tegenspraak","ru":"Доказательство от противного","zh":"反证法","pt_BR":"Prova por contradição","pt_PT":"Prova por contradição"}, back_translations: {"es":"Assumir a negación del enunciado a ser provado; derivar una contradición lógica; concluir que el enunciado original deve ser verdadero. Usado para provar que √2 es irracional.","de":"Nimm die Negation der zu beweisenden Aussage an; leite einen logischen Widerspruch ab; schlussfolgere, dass die ursprüngliche Aussage wahr sein muss. Wird verwendet, um √2 als irrational zu beweisen.","fr":"Supposer la négation de l'énoncé à prouver ; en déduire une contradiction logique ; conclure que l'énoncé original est vrai. Utilisé pour prouver que √2 est irrationnel.","tr":"İspatlanacak ifadenin olumsuzunu varsay; mantıksal bir çelişki türet; orijinal ifadenin doğru olması gerektiği sonucuna var. √2'nin irrasyonel olduğunu kanıtlamak için kullanılır.","nl":"Neem de negatie van de te bewijzen stelling; leid een logische tegenspraak af; concludeer dat de oorspronkelijke stelling waar moet zijn. Gebruikt om te bewijzen dat √2 irrationeel is.","ru":"Предположить отрицание доказываемого утверждения; вывести логическое противоречие; заключить, что исходное утверждение истинно. Используется для доказательства иррациональности √2.","zh":"假设待证命题的否命题成立；推导出逻辑矛盾；从而得出原命题必定成立的结论。用于证明 √2 是无理数。","pt_BR":"Assumir a negação do enunciado a ser provado; derivar uma contradição lógica; concluir que o enunciado original deve ser verdadeiro. Usado para provar que √2 é irracional.","pt_PT":"Assumir a negação do enunciado a ser provado; derivar uma contradição lógica; concluir que o enunciado original deve ser verdadeiro. Usado para provar que √2 é irracional."}, sort_order: 108 },
  { id: 'dc-math-0109', deck_id: 'deck-math', front: 'Set Theory: Union and Intersection', back: 'A ∪ B (union) contains elements in A or B or both. A ∩ B (intersection) contains only elements in both A and B. A \\ B (difference) contains elements in A but not B.', front_translations: {"es":"Teoria de los conjuntos: união y interseción","de":"Mengenlehre: Vereinigung und Schnittmenge","fr":"Théorie des ensembles : union et intersection","tr":"Küme Teorisi: Birleşim ve Kesişim","nl":"Verzamelingsleer: unie en doorsnede","ru":"Теория множеств: объединение и пересечение","zh":"集合论：并集与交集","pt_BR":"Teoria dos conjuntos: união e interseção","pt_PT":"Teoria dos conjuntos: união e interseção"}, back_translations: {"es":"La ∪ B (união) contiene elementos en A o B o ambos. La ∩ B (interseción) contiene solo elementos en ambos A y B. La \\ B (diferencia) contiene elementos en A pero no en B.","de":"A ∪ B (Vereinigung) enthält Elemente in A oder B oder beiden. A ∩ B (Schnittmenge) enthält nur Elemente in sowohl A als auch B. A \\ B (Differenz) enthält Elemente in A, aber nicht in B.","fr":"A ∪ B (union) contient les éléments de A ou B ou des deux. A ∩ B (intersection) ne contient que les éléments à la fois dans A et B. A \\ B (différence) contient les éléments de A mais pas de B.","tr":"A ∪ B (birleşim), A veya B'deki ya da her ikisindeki elemanları içerir. A ∩ B (kesişim), yalnızca hem A hem de B'deki elemanları içerir. A \\ B (fark), A'da olup B'de olmayan elemanları içerir.","nl":"A ∪ B (unie) bevat elementen in A of B of beide. A ∩ B (doorsnede) bevat alleen elementen in zowel A als B. A \\ B (verschil) bevat elementen in A maar niet in B.","ru":"A ∪ B (объединение) содержит элементы из A или B, или из обоих. A ∩ B (пересечение) содержит только элементы, принадлежащие и A, и B. A \\ B (разность) содержит элементы из A, не входящие в B.","zh":"A ∪ B（并集）包含在 A 或 B 或两者中的元素。A ∩ B（交集）仅包含同时在 A 和 B 中的元素。A \\ B（差集）包含在 A 中但不在 B 中的元素。","pt_BR":"A ∪ B (união) contém elementos em A ou B ou ambos. A ∩ B (interseção) contém apenas elementos em ambos A e B. A \\ B (diferença) contém elementos em A mas não em B.","pt_PT":"A ∪ B (união) contém elementos em A ou B ou ambos. A ∩ B (interseção) contém apenas elementos em ambos A e B. A \\ B (diferença) contém elementos em A mas não em B."}, sort_order: 109 },
  { id: 'dc-math-0110', deck_id: 'deck-math', front: 'De Morgan\'s Laws', back: '(A ∪ B)\' = A\' ∩ B\' and (A ∩ B)\' = A\' ∪ B\'. The complement of a union is the intersection of complements, and vice versa; fundamental in logic and set theory.', front_translations: {"es":"Leis de De Morgan","de":"De Morganschen Gesetze","fr":"Lois de De Morgan","tr":"De Morgan Yasaları","nl":"Wetten van De Morgan","ru":"Законы де Моргана","zh":"德摩根定律","pt_BR":"Leis de De Morgan","pt_PT":"Leis de De Morgan"}, back_translations: {"es":"(A ∪ B)' = A' ∩ B' y (A ∩ B)' = A' ∪ B'. El complemento de una união es a interseción de los complementos y vice-versa; fundamental en lógica y teoría de los conjuntos.","de":"(A ∪ B)' = A' ∩ B' und (A ∩ B)' = A' ∪ B'. Das Komplement einer Vereinigung ist der Durchschnitt der Komplemente und umgekehrt; grundlegend in Logik und Mengenlehre.","fr":"(A ∪ B)' = A' ∩ B' et (A ∩ B)' = A' ∪ B'. Le complément d'une union est l'intersection des compléments, et vice versa ; fondamental en logique et en théorie des ensembles.","tr":"(A ∪ B)' = A' ∩ B' ve (A ∩ B)' = A' ∪ B'. Bir birleşimin tümleyeni, tümleyenlerin kesişimidir ve tersine; mantık ve küme teorisinde temeldir.","nl":"(A ∪ B)' = A' ∩ B' en (A ∩ B)' = A' ∪ B'. Het complement van een unie is de doorsnede van de complementen, en vice versa; fundamenteel in logica en verzamelingsleer.","ru":"(A ∪ B)' = A' ∩ B' и (A ∩ B)' = A' ∪ B'. Дополнение объединения — пересечение дополнений, и наоборот; основополагающие законы логики и теории множеств.","zh":"(A ∪ B)' = A' ∩ B' 和 (A ∩ B)' = A' ∪ B'。并集的补集是补集的交集，反之亦然；在逻辑学和集合论中具有基础性地位。","pt_BR":"(A ∪ B)' = A' ∩ B' e (A ∩ B)' = A' ∪ B'. O complemento de uma união é a interseção dos complementos e vice-versa; fundamental em lógica e teoria dos conjuntos.","pt_PT":"(A ∪ B)' = A' ∩ B' e (A ∩ B)' = A' ∪ B'. O complemento de uma união é a interseção dos complementos e vice-versa; fundamental em lógica e teoria dos conjuntos."}, sort_order: 110 },
  { id: 'dc-math-0111', deck_id: 'deck-math', front: 'Function Composition', back: '(f ∘ g)(x) = f(g(x)). First apply g to x, then apply f to the result. The domain of f∘g is the set of x in domain of g where g(x) is in the domain of f.', front_translations: {"es":"Composición de funciones","de":"Funktionenkomposition","fr":"Composition de fonctions","tr":"Fonksiyon Bileşimi","nl":"Functiesamenstelling","ru":"Композиция функций","zh":"函数复合","pt_BR":"Composição de funções","pt_PT":"Composição de funções"}, back_translations: {"es":"(f ∘ g)(x) = f(g(x)). Primero se aplica g a x, después se aplica f al resultado. El domínio de f∘g es el conjunto de los x en el domínio de g para los quais g(x) está en el domínio de f.","de":"(f ∘ g)(x) = f(g(x)). Erst g auf x anwenden, dann f auf das Ergebnis. Der Definitionsbereich von f∘g ist die Menge der x im Definitionsbereich von g, für die g(x) im Definitionsbereich von f liegt.","fr":"(f ∘ g)(x) = f(g(x)). D'abord appliquer g à x, puis appliquer f au résultat. Le domaine de f∘g est l'ensemble des x du domaine de g pour lesquels g(x) est dans le domaine de f.","tr":"(f ∘ g)(x) = f(g(x)). Önce g'yi x'e uygula, ardından f'yi sonuca uygula. f∘g'nin tanım kümesi, g'nin tanım kümesindeki x değerlerinden g(x)'in f'nin tanım kümesinde olduğu küme.","nl":"(f ∘ g)(x) = f(g(x)). Eerst g toepassen op x, dan f toepassen op het resultaat. Het domein van f∘g is de verzameling x in het domein van g waarvoor g(x) in het domein van f ligt.","ru":"(f ∘ g)(x) = f(g(x)). Сначала применить g к x, затем применить f к результату. Область определения f∘g — это множество таких x из области определения g, что g(x) принадлежит области определения f.","zh":"(f ∘ g)(x) = f(g(x))。先对 x 应用 g，再对结果应用 f。f∘g 的定义域是 g 的定义域中使 g(x) 属于 f 的定义域的那些 x 的集合。","pt_BR":"(f ∘ g)(x) = f(g(x)). Primeiro aplica-se g a x, depois aplica-se f ao resultado. O domínio de f∘g é o conjunto dos x no domínio de g para os quais g(x) está no domínio de f.","pt_PT":"(f ∘ g)(x) = f(g(x)). Primeiro aplica-se g a x, depois aplica-se f ao resultado. O domínio de f∘g é o conjunto dos x no domínio de g para os quais g(x) está no domínio de f."}, sort_order: 111 },
  { id: 'dc-math-0112', deck_id: 'deck-math', front: 'Inverse Function', back: 'f⁻¹(x) is the function such that f(f⁻¹(x)) = x. It "undoes" f; exists only if f is bijective (one-to-one and onto). The graph of f⁻¹ is the reflection of f across y = x.', front_translations: {"es":"Función inversa","de":"Umkehrfunktion","fr":"Fonction inverse","tr":"Ters Fonksiyon","nl":"Inverse functie","ru":"Обратная функция","zh":"反函数","pt_BR":"Função inversa","pt_PT":"Função inversa"}, back_translations: {"es":"f⁻¹(x) es a función tal que f(f⁻¹(x)) = x. 'Desfaz' f; existe solo se f for bijetiva (injetiva y sobrejetiva). El gráfico de f⁻¹ es a reflexão de f en relación con y = x.","de": "f⁻¹(x) ist die Funktion, für die f(f⁻¹(x)) = x gilt. Sie 'macht f rückgängig'; existiert nur wenn f bijektiv ist (eineindeutig und surjektiv). Der Graph von f⁻¹ ist die Spiegelung von f an y = x.", "fr": "f⁻¹(x) est la fonction telle que f(f⁻¹(x)) = x. Elle 'annule' f ; n'existe que si f est bijective (injective et surjective). Le graphe de f⁻¹ est la réflexion de f par rapport à y = x.", "tr": "f⁻¹(x), f(f⁻¹(x)) = x sağlayan fonksiyondur. f'yi 'geri alır'; yalnızca f birebirsa ve örten ise mevcuttur. f⁻¹'nin grafiği, f'nin y = x'e göre yansımasıdır.", "nl": "f⁻¹(x) is de functie zodat f(f⁻¹(x)) = x. Het 'maakt f ongedaan'; bestaat alleen als f bijectief is (één-op-één en surjectief). De grafiek van f⁻¹ is de spiegeling van f over y = x.", "ru": "f⁻¹(x) — это функция такая, что f(f⁻¹(x)) = x. Она «отменяет» f; существует только если f биективна (однозначна и сюръективна). График f⁻¹ — отражение f относительно y = x.", "zh": "f⁻¹(x) 是满足 f(f⁻¹(x)) = x 的函数。它\\\"撤销\\\" f；仅当 f 是双射（既单射又满射）时存在。f⁻¹ 的图像是 f 关于 y = x 的对称。", "pt_BR": "f⁻¹(x) é a função tal que f(f⁻¹(x)) = x. 'Desfaz' f; existe apenas se f for bijetiva (injetiva e sobrejetiva). O gráfico de f⁻¹ é a reflexão de f em relação a y = x.", "pt_PT": "f⁻¹(x) é a função tal que f(f⁻¹(x)) = x. 'Desfaz' f; existe apenas se f for bijectiva (injectiva e sobrejectiva). O gráfico de f⁻¹ é a reflexão de f em relação a y = x."}, sort_order: 112 },
  { id: 'dc-math-0113', deck_id: 'deck-math', front: 'Even and Odd Functions', back: 'Even: f(-x) = f(x); symmetric about the y-axis (e.g., cos x, x²). Odd: f(-x) = -f(x); symmetric about the origin (e.g., sin x, x³).', front_translations: {"es":"Funciones pares y ímpares","de":"Gerade und ungerade Funktionen","fr":"Fonctions paires et impaires","tr":"Çift ve Tek Fonksiyonlar","nl":"Even en oneven functies","ru":"Чётные и нечётные функции","zh":"奇函数与偶函数","pt_BR":"Funções pares e ímpares","pt_PT":"Funções pares e ímpares"}, back_translations: {"es":"Par: f(-x) = f(x); simétrica en relación con el eixo y (ex.: cos x, x²). Ímpar: f(-x) = -f(x); simétrica en relación con la origem (ex.: sin x, x³).","de":"Gerade: f(-x) = f(x); symmetrisch zur y-Achse (z.B. cos x, x²). Ungerade: f(-x) = -f(x); symmetrisch zum Ursprung (z.B. sin x, x³).","fr":"Paire : f(-x) = f(x) ; symétrique par rapport à l'axe des y (ex. cos x, x²). Impaire : f(-x) = -f(x) ; symétrique par rapport à l'origine (ex. sin x, x³).","tr":"Çift: f(-x) = f(x); y eksenine göre simetrik (örn. cos x, x²). Tek: f(-x) = -f(x); orijine göre simetrik (örn. sin x, x³).","nl":"Even: f(-x) = f(x); symmetrisch over de y-as (bijv. cos x, x²). Oneven: f(-x) = -f(x); symmetrisch over de oorsprong (bijv. sin x, x³).","ru":"Чётная: f(-x) = f(x); симметрична относительно оси y (напр., cos x, x²). Нечётная: f(-x) = -f(x); симметрична относительно начала координат (напр., sin x, x³).","zh":"偶函数：f(-x) = f(x)；关于 y 轴对称（如 cos x、x²）。奇函数：f(-x) = -f(x)；关于原点对称（如 sin x、x³）。","pt_BR":"Par: f(-x) = f(x); simétrica em relação ao eixo y (ex.: cos x, x²). Ímpar: f(-x) = -f(x); simétrica em relação à origem (ex.: sin x, x³).","pt_PT":"Par: f(-x) = f(x); simétrica em relação ao eixo y (ex.: cos x, x²). Ímpar: f(-x) = -f(x); simétrica em relação à origem (ex.: sin x, x³)."}, sort_order: 113 },
  { id: 'dc-math-0114', deck_id: 'deck-math', front: 'Vertex Form of a Parabola', back: 'y = a(x - h)² + k. The vertex is at (h, k); a > 0 opens upward (minimum), a < 0 opens downward (maximum). The axis of symmetry is x = h.', front_translations: {"es":"Forma de vértice de una parábola","de":"Scheitelpunktform einer Parabel","fr":"Forme canonique d'une parabole","tr":"Parabolün Köşe Noktası Formu","nl":"Toppuntvorm van een parabool","ru":"Вершинная форма параболы","zh":"抛物线的顶点式","pt_BR":"Forma de vértice de uma parábola","pt_PT":"Forma de vértice de uma parábola"}, back_translations: {"es":"y = a(x - h)² + k. El vértice está en (h, k); a > 0 abre para cima (mínimo), a < 0 abre para bajo (máximo). El eixo de simetría es x = h.","de":"y = a(x - h)² + k. Der Scheitelpunkt liegt bei (h, k); a > 0 öffnet nach oben (Minimum), a < 0 nach unten (Maximum). Die Symmetrieachse ist x = h.","fr":"y = a(x - h)² + k. Le sommet est en (h, k) ; a > 0 s'ouvre vers le haut (minimum), a < 0 vers le bas (maximum). L'axe de symétrie est x = h.","tr":"y = a(x - h)² + k. Köşe noktası (h, k)'dadır; a > 0 yukarı açılır (minimum), a < 0 aşağı açılır (maksimum). Simetri ekseni x = h'dir.","nl":"y = a(x - h)² + k. De top is bij (h, k); a > 0 opent omhoog (minimum), a < 0 opent omlaag (maximum). De symmetrieas is x = h.","ru":"y = a(x - h)² + k. Вершина в точке (h, k); при a > 0 парабола открыта вверх (минимум), при a < 0 — вниз (максимум). Ось симметрии x = h.","zh":"y = a(x - h)² + k。顶点在 (h, k)；a > 0 开口向上（极小值），a < 0 开口向下（极大值）。对称轴为 x = h。","pt_BR":"y = a(x - h)² + k. O vértice está em (h, k); a > 0 abre para cima (mínimo), a < 0 abre para baixo (máximo). O eixo de simetria é x = h.","pt_PT":"y = a(x - h)² + k. O vértice está em (h, k); a > 0 abre para cima (mínimo), a < 0 abre para baixo (máximo). O eixo de simetria é x = h."}, sort_order: 114 },
  { id: 'dc-math-0115', deck_id: 'deck-math', front: 'Completing the Square', back: 'A method to rewrite ax² + bx + c in vertex form by adding and subtracting (b/2a)². Used to solve quadratics, derive the quadratic formula, and analyze conic sections.', front_translations: {"es":"Completar el cuadrado","de":"Quadratische Ergänzung","fr":"Complétion du carré","tr":"Kareyi Tamamlama","nl":"Kwadraat voltooien","ru":"Выделение полного квадрата","zh":"配方法","pt_BR":"Completar o quadrado","pt_PT":"Completar o quadrado"}, back_translations: {"es":"Un método para reescrever ax² + bx + c en la forma de vértice adicionando y subtraindo (b/2a)². Usado para resolver ecuaciones quadráticas, derivar a fórmula cuadrática y analisar seciones conicas.","de":"Eine Methode, um ax² + bx + c in Scheitelpunktform umzuschreiben, indem (b/2a)² addiert und subtrahiert wird. Wird zum Lösen quadratischer Gleichungen, Ableiten der Lösungsformel und Analysieren von Kegelschnitten verwendet.","fr":"Une méthode pour réécrire ax² + bx + c en forme canonique en ajoutant et soustrayant (b/2a)². Utilisée pour résoudre les équations du second degré, dériver la formule quadratique et analyser les coniques.","tr":"(b/2a)² ekleyip çıkararak ax² + bx + c'yi köşe noktası formuna yeniden yazmak için bir yöntem. İkinci dereceden denklemleri çözmek, ikinci dereceden formülü türetmek ve konik kesitleri analiz etmek için kullanılır.","nl":"Een methode om ax² + bx + c te herschrijven in toppuntvorm door (b/2a)² op te tellen en af te trekken. Gebruikt om kwadraten op te lossen, de kwadratische formule af te leiden en kegelsneden te analyseren.","ru":"Метод записи ax² + bx + c в вершинной форме путём прибавления и вычитания (b/2a)². Используется для решения квадратных уравнений, вывода формулы корней и анализа конических сечений.","zh":"通过加减 (b/2a)² 将 ax² + bx + c 改写为顶点式的方法。用于求解二次方程、推导求根公式及分析圆锥截线。","pt_BR":"Um método para reescrever ax² + bx + c na forma de vértice adicionando e subtraindo (b/2a)². Usado para resolver equações quadráticas, derivar a fórmula quadrática e analisar seções cônicas.","pt_PT":"Um método para reescrever ax² + bx + c na forma de vértice adicionando e subtraindo (b/2a)². Usado para resolver equações quadráticas, derivar a fórmula quadrática e analisar secções cónicas."}, sort_order: 115 },
  { id: 'dc-math-0116', deck_id: 'deck-math', front: 'Discriminant', back: 'Δ = b² - 4ac in the quadratic formula. If Δ > 0: two real roots; Δ = 0: one real (repeated) root; Δ < 0: two complex conjugate roots with no real solutions.', front_translations: {"es":"Discriminante","de":"Diskriminante","fr":"Discriminant","tr":"Diskriminant","nl":"Discriminant","ru":"Дискриминант","zh":"判别式","pt_BR":"Discriminante","pt_PT":"Discriminante"}, back_translations: {"es":"Δ = b² - 4ac en la fórmula cuadrática. Se Δ > 0: de los raíces reais; Δ = 0: una raíz real (repetida); Δ < 0: de los raíces complexas conjugadas sin soluciones reais.","de":"Δ = b² - 4ac in der quadratischen Formel. Wenn Δ > 0: zwei reelle Wurzeln; Δ = 0: eine reelle (doppelte) Wurzel; Δ < 0: zwei komplexe konjugierte Wurzeln ohne reelle Lösungen.","fr":"Δ = b² - 4ac dans la formule quadratique. Si Δ > 0 : deux racines réelles ; Δ = 0 : une racine réelle (double) ; Δ < 0 : deux racines complexes conjuguées sans solution réelle.","tr":"İkinci dereceden formülde Δ = b² - 4ac. Δ > 0 ise: iki reel kök; Δ = 0 ise: bir reel (tekrarlayan) kök; Δ < 0 ise: reel çözüm olmadan iki karmaşık eşlenik kök.","nl":"Δ = b² - 4ac in de kwadratische formule. Als Δ > 0: twee reële wortels; Δ = 0: één reële (dubbele) wortel; Δ < 0: twee complexe geconjugeerde wortels zonder reële oplossingen.","ru":"Δ = b² - 4ac в формуле квадратного уравнения. Если Δ > 0: два вещественных корня; Δ = 0: один вещественный (кратный) корень; Δ < 0: два комплексно-сопряжённых корня без вещественных решений.","zh":"在求根公式中 Δ = b² - 4ac。若 Δ > 0：两个实根；Δ = 0：一个实数重根；Δ < 0：两个复共轭根，无实数解。","pt_BR":"Δ = b² - 4ac na fórmula quadrática. Se Δ > 0: duas raízes reais; Δ = 0: uma raiz real (repetida); Δ < 0: duas raízes complexas conjugadas sem soluções reais.","pt_PT":"Δ = b² - 4ac na fórmula quadrática. Se Δ > 0: duas raízes reais; Δ = 0: uma raiz real (repetida); Δ < 0: duas raízes complexas conjugadas sem soluções reais."}, sort_order: 116 },
  { id: 'dc-math-0117', deck_id: 'deck-math', front: 'Polynomial Long Division', back: 'Divides one polynomial by another of lower degree, analogous to long division of integers. The result is a quotient plus a remainder over the divisor.', front_translations: {"es":"Divisão ancha de polinomios","de":"Polynomdivision","fr":"Division euclidienne des polynômes","tr":"Polinom Uzun Bölümü","nl":"Lange deling van polynomen","ru":"Деление полиномов в столбик","zh":"多项式长除法","pt_BR":"Divisão longa de polinômios","pt_PT":"Divisão longa de polinómios"}, back_translations: {"es":"Divide un polinomio por outro de grau menor, análogo a la divisão ancha de interos. El resultado es un quociente más un resto sobre el divisor.","de":"Dividiert ein Polynom durch ein anderes mit niedrigerem Grad, analog zur langen Division ganzer Zahlen. Das Ergebnis ist ein Quotient plus ein Rest über dem Divisor.","fr":"Divise un polynôme par un autre de degré inférieur, analogue à la division euclidienne des entiers. Le résultat est un quotient plus un reste sur le diviseur.","tr":"Bir polinomu, tam sayıların uzun bölümüne benzer şekilde daha düşük dereceli başka bir polinoma böler. Sonuç, bir bölüm artı bir bölene bölünmüş kalandan oluşur.","nl":"Deelt een polynoom door een ander van lagere graad, analoog aan de lange deling van gehele getallen. Het resultaat is een quotiënt plus een rest over de deler.","ru":"Делит один полином на другой, меньшей степени, аналогично делению целых чисел в столбик. Результат — частное плюс остаток, делённый на делитель.","zh":"将一个多项式除以次数较低的另一个多项式，类比整数的长除法。结果是商加上余式除以除式。","pt_BR":"Divide um polinômio por outro de grau menor, análogo à divisão longa de inteiros. O resultado é um quociente mais um resto sobre o divisor.","pt_PT":"Divide um polinómio por outro de grau menor, análogo à divisão longa de inteiros. O resultado é um quociente mais um resto sobre o divisor."}, sort_order: 117 },
  { id: 'dc-math-0118', deck_id: 'deck-math', front: 'Remainder Theorem', back: 'When polynomial p(x) is divided by (x - a), the remainder equals p(a). If p(a) = 0, then (x - a) is a factor of p(x) (Factor Theorem).', front_translations: {"es":"Teorema del resto","de":"Restsatz","fr":"Théorème du reste","tr":"Kalan Teoremi","nl":"Reststelling","ru":"Теорема об остатке","zh":"余数定理","pt_BR":"Teorema do resto","pt_PT":"Teorema do resto"}, back_translations: {"es":"Cuando el polinomio p(x) es dividido por (x - a), el resto es igual a p(a). Se p(a) = 0, entonces (x - a) es un fator de p(x) (Teorema del Fator).","de":"Wenn das Polynom p(x) durch (x - a) geteilt wird, ist der Rest gleich p(a). Wenn p(a) = 0, dann ist (x - a) ein Faktor von p(x) (Faktorsatz).","fr":"Quand le polynôme p(x) est divisé par (x - a), le reste vaut p(a). Si p(a) = 0, alors (x - a) est un facteur de p(x) (théorème des facteurs).","tr":"p(x) polinomu (x - a)'ya bölündüğünde kalan p(a)'ya eşittir. Eğer p(a) = 0 ise, (x - a), p(x)'in bir çarpanıdır (Çarpan Teoremi).","nl":"Wanneer polynoom p(x) wordt gedeeld door (x - a), is de rest gelijk aan p(a). Als p(a) = 0, dan is (x - a) een factor van p(x) (Factorstelling).","ru":"При делении полинома p(x) на (x - a) остаток равен p(a). Если p(a) = 0, то (x - a) является множителем p(x) (теорема о множителе).","zh":"多项式 p(x) 除以 (x - a) 时，余数等于 p(a)。若 p(a) = 0，则 (x - a) 是 p(x) 的因式（因式定理）。","pt_BR":"Quando o polinômio p(x) é dividido por (x - a), o resto é igual a p(a). Se p(a) = 0, então (x - a) é um fator de p(x) (Teorema do Fator).","pt_PT":"Quando o polinómio p(x) é dividido por (x - a), o resto é igual a p(a). Se p(a) = 0, então (x - a) é um factor de p(x) (Teorema do Factor)."}, sort_order: 118 },
  { id: 'dc-math-0119', deck_id: 'deck-math', front: 'Rational Root Theorem', back: 'If p/q is a rational root of aₙxⁿ + ... + a₀ = 0, then p divides the constant term a₀ and q divides the leading coefficient aₙ; limits the candidates for rational roots.', front_translations: {"es":"Teorema de las raíces racionais","de":"Rationale-Wurzeln-Satz","fr":"Théorème des racines rationnelles","tr":"Rasyonel Kök Teoremi","nl":"Rationale-wortelstelling","ru":"Теорема о рациональных корнях","zh":"有理根定理","pt_BR":"Teorema das raízes racionais","pt_PT":"Teorema das raízes racionais"}, back_translations: {"es":"Se p/q es una raíz racional de aₙxⁿ + ... + a₀ = 0, entonces p divide el termo constante a₀ y q divide el coeficiente líder aₙ; limita los candidatos a raíces racionais.","de":"Wenn p/q eine rationale Wurzel von aₙxⁿ + ... + a₀ = 0 ist, dann teilt p den konstanten Term a₀ und q teilt den führenden Koeffizienten aₙ; schränkt die Kandidaten für rationale Wurzeln ein.","fr":"Si p/q est une racine rationnelle de aₙxⁿ + ... + a₀ = 0, alors p divise le terme constant a₀ et q divise le coefficient dominant aₙ ; limite les candidats aux racines rationnelles.","tr":"p/q, aₙxⁿ + ... + a₀ = 0'ın rasyonel kökü ise, p sabit terimi a₀'ı böler ve q baş katsayıyı aₙ'yi böler; rasyonel köklerin adaylarını sınırlar.","nl":"Als p/q een rationale wortel is van aₙxⁿ + ... + a₀ = 0, dan deelt p de constante term a₀ en deelt q de hoofdcoëfficiënt aₙ; beperkt de kandidaten voor rationale wortels.","ru":"Если p/q является рациональным корнем aₙxⁿ + ... + a₀ = 0, то p делит свободный член a₀, а q делит старший коэффициент aₙ; ограничивает множество кандидатов на рациональные корни.","zh":"若 p/q 是 aₙxⁿ + ... + a₀ = 0 的有理根，则 p 整除常数项 a₀，q 整除首项系数 aₙ；限制了有理根的候选范围。","pt_BR":"Se p/q é uma raiz racional de aₙxⁿ + ... + a₀ = 0, então p divide o termo constante a₀ e q divide o coeficiente líder aₙ; limita os candidatos a raízes racionais.","pt_PT":"Se p/q é uma raiz racional de aₙxⁿ + ... + a₀ = 0, então p divide o termo constante a₀ e q divide o coeficiente líder aₙ; limita os candidatos a raízes racionais."}, sort_order: 119 },
  { id: 'dc-math-0120', deck_id: 'deck-math', front: 'Logarithmic vs. Exponential Growth', back: 'Exponential growth: f(x) = aˣ, grows faster than any polynomial. Logarithmic growth: f(x) = log(x), grows slower than any polynomial. They are inverse functions.', front_translations: {"es":"Crescimento logarítmico vs. exponencial","de":"Logarithmisches vs. exponentielles Wachstum","fr":"Croissance logarithmique vs exponentielle","tr":"Logaritmik ve Üstel Büyüme","nl":"Logaritmische vs. exponentiële groei","ru":"Логарифмический и экспоненциальный рост","zh":"对数增长与指数增长","pt_BR":"Crescimento logarítmico vs. exponencial","pt_PT":"Crescimento logarítmico vs. exponencial"}, back_translations: {"es":"Crescimento exponencial: f(x) = aˣ, crece más rápido que cualquier polinomio. Crescimento logarítmico: f(x) = log(x), crece más devagar que cualquier polinomio. São funciones inversas.","de":"Exponentielles Wachstum: f(x) = aˣ, wächst schneller als jedes Polynom. Logarithmisches Wachstum: f(x) = log(x), wächst langsamer als jedes Polynom. Sie sind Umkehrfunktionen.","fr":"Croissance exponentielle : f(x) = aˣ, croît plus vite que tout polynôme. Croissance logarithmique : f(x) = log(x), croît plus lentement que tout polynôme. Ce sont des fonctions inverses.","tr":"Üstel büyüme: f(x) = aˣ, herhangi bir polinomdan daha hızlı büyür. Logaritmik büyüme: f(x) = log(x), herhangi bir polinomdan daha yavaş büyür. Bunlar ters fonksiyonlardır.","nl":"Exponentiële groei: f(x) = aˣ, groeit sneller dan elk polynoom. Logaritmische groei: f(x) = log(x), groeit langzamer dan elk polynoom. Ze zijn elkaars inverse functies.","ru":"Экспоненциальный рост: f(x) = aˣ, растёт быстрее любого многочлена. Логарифмический рост: f(x) = log(x), растёт медленнее любого многочлена. Они являются взаимно обратными функциями.","zh":"指数增长：f(x) = aˣ，比任何多项式增长都快。对数增长：f(x) = log(x)，比任何多项式增长都慢。它们互为反函数。","pt_BR":"Crescimento exponencial: f(x) = aˣ, cresce mais rápido que qualquer polinômio. Crescimento logarítmico: f(x) = log(x), cresce mais devagar que qualquer polinômio. São funções inversas.","pt_PT":"Crescimento exponencial: f(x) = aˣ, cresce mais rápido que qualquer polinómio. Crescimento logarítmico: f(x) = log(x), cresce mais devagar que qualquer polinómio. São funções inversas."}, sort_order: 120 },
  { id: 'dc-math-0121', deck_id: 'deck-math', front: 'Partial Fractions', back: 'A technique to decompose a rational function into a sum of simpler fractions; used before integrating rational functions. E.g., 1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1)).', front_translations: {"es":"Fraciones parciais","de":"Partialbruchzerlegung","fr":"Décomposition en fractions partielles","tr":"Kısmi Kesirler","nl":"Partiële fracties","ru":"Разложение на простые дроби","zh":"部分分式分解","pt_BR":"Frações parciais","pt_PT":"Fracções parciais"}, back_translations: {"es":"Una técnica para decompor una función racional en una suma de fracciones más simples; usada antes de integrar funciones racionais. Ex.: 1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1)).","de":"Eine Technik zum Zerlegen einer rationalen Funktion in eine Summe einfacherer Brüche; wird vor der Integration rationaler Funktionen verwendet. Z.B. 1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1)).","fr":"Une technique pour décomposer une fonction rationnelle en une somme de fractions plus simples ; utilisée avant d'intégrer des fonctions rationnelles. Ex. 1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1)).","tr":"Bir rasyonel fonksiyonu daha basit kesirlerin toplamına ayırmak için bir teknik; rasyonel fonksiyonları integre etmeden önce kullanılır. Örn. 1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1)).","nl":"Een techniek om een rationale functie te ontbinden in een som van eenvoudigere breuken; gebruikt vóór het integreren van rationale functies. Bijv. 1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1)).","ru":"Метод разложения рациональной функции в сумму более простых дробей; применяется перед интегрированием рациональных функций. Напр., 1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1)).","zh":"将有理函数分解为较简单分式之和的技巧；用于对有理函数积分之前。例：1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1))。","pt_BR":"Uma técnica para decompor uma função racional em uma soma de frações mais simples; usada antes de integrar funções racionais. Ex.: 1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1)).","pt_PT":"Uma técnica para decompor uma função racional em uma soma de fracções mais simples; usada antes de integrar funções racionais. Ex.: 1/(x²-1) = 1/2·(1/(x-1)) - 1/2·(1/(x+1))."}, sort_order: 121 },
  { id: 'dc-math-0122', deck_id: 'deck-math', front: 'Implicit Differentiation', back: 'A technique to differentiate equations where y is not explicitly solved for x; differentiate both sides with respect to x, applying the chain rule to any y terms (dy/dx).', front_translations: {"es":"Diferenciación implícita","de":"Implizite Differentiation","fr":"Différentiation implicite","tr":"Örtük Türev Alma","nl":"Impliciete differentiatie","ru":"Неявное дифференцирование","zh":"隐函数求导","pt_BR":"Diferenciação implícita","pt_PT":"Diferenciação implícita"}, back_translations: {"es":"Una técnica para diferenciar ecuaciones donde y no es explicitamente resolvido para x; diferencie ambos los lados en relación con x, aplicando a regra de la cadeia a los termos y (dy/dx).","de":"Eine Technik zum Differenzieren von Gleichungen, bei denen y nicht explizit nach x aufgelöst ist; beide Seiten nach x differenzieren und die Kettenregel auf alle y-Terme anwenden (dy/dx).","fr":"Une technique pour différentier des équations où y n'est pas explicitement exprimé en fonction de x ; différentier les deux membres par rapport à x en appliquant la règle de la chaîne aux termes en y (dy/dx).","tr":"y'nin açıkça x cinsinden çözülmediği denklemleri türevlendirmek için bir teknik; her iki tarafı x'e göre türevlendir ve tüm y terimlerine zincir kuralını uygula (dy/dx).","nl":"Een techniek om vergelijkingen te differentiëren waarbij y niet expliciet is opgelost voor x; differentieer beide zijden naar x, pas de kettingregel toe op y-termen (dy/dx).","ru":"Метод дифференцирования уравнений, в которых y явно не выражено через x; дифференцировать обе части по x, применяя правило цепочки к любым членам с y (dy/dx).","zh":"对 y 未显式用 x 表达的方程进行求导的技巧；对两边关于 x 求导，对任何含 y 的项应用链式法则（dy/dx）。","pt_BR":"Uma técnica para diferenciar equações onde y não é explicitamente resolvido para x; diferencie ambos os lados em relação a x, aplicando a regra da cadeia aos termos y (dy/dx).","pt_PT":"Uma técnica para diferenciar equações onde y não é explicitamente resolvido para x; diferencie ambos os lados em relação a x, aplicando a regra da cadeia aos termos y (dy/dx)."}, sort_order: 122 },
  { id: 'dc-math-0123', deck_id: 'deck-math', front: 'Related Rates', back: 'A calculus application using implicit differentiation with respect to time; given the rate of change of one quantity, find the rate of change of a related quantity.', front_translations: {"es":"Taxas relacionadas","de":"Verwandte Raten","fr":"Taux liés","tr":"İlişkili Hızlar","nl":"Gerelateerde snelheden","ru":"Связанные скорости изменения","zh":"相关变化率","pt_BR":"Taxas relacionadas","pt_PT":"Taxas relacionadas"}, back_translations: {"es":"Una aplicación del cálculo usando diferenciación implícita en relación con el tiempo; dato a taxa de variación de una cantidad, encontrar a taxa de variación de una cantidad relacionada.","de":"Eine Kalkülsanwendung mit impliziter Differentiation nach der Zeit; gegeben die Änderungsrate einer Größe, die Änderungsrate einer damit zusammenhängenden Größe finden.","fr":"Une application du calcul utilisant la différentiation implicite par rapport au temps ; à partir du taux de variation d'une grandeur, trouver le taux de variation d'une grandeur liée.","tr":"Zamana göre örtük türev almayı kullanan bir kalkülüs uygulaması; bir büyüklüğün değişim hızı verildiğinde, ilgili bir büyüklüğün değişim hızını bul.","nl":"Een calculus-toepassing die impliciete differentiatie naar de tijd gebruikt; gegeven de veranderingssnelheid van een grootheid, zoek de veranderingssnelheid van een gerelateerde grootheid.","ru":"Приложение математического анализа с использованием неявного дифференцирования по времени; зная скорость изменения одной величины, найти скорость изменения связанной с ней величины.","zh":"微积分的应用，使用关于时间的隐函数求导；给定一个量的变化率，求相关量的变化率。","pt_BR":"Uma aplicação do cálculo usando diferenciação implícita em relação ao tempo; dado a taxa de variação de uma quantidade, encontrar a taxa de variação de uma quantidade relacionada.","pt_PT":"Uma aplicação do cálculo usando diferenciação implícita em relação ao tempo; dada a taxa de variação de uma quantidade, encontrar a taxa de variação de uma quantidade relacionada."}, sort_order: 123 },
  { id: 'dc-math-0124', deck_id: 'deck-math', front: 'Taylor Series', back: 'f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ. Expresses a function as an infinite polynomial centered at a. The Maclaurin series is centered at a = 0.', front_translations: {"es":"Série de Taylor","de":"Taylorreihe","fr":"Série de Taylor","tr":"Taylor Serisi","nl":"Taylorreeks","ru":"Ряд Тейлора","zh":"泰勒级数","pt_BR":"Série de Taylor","pt_PT":"Série de Taylor"}, back_translations: {"es":"f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ. Expressa una función como un polinomio infinito centrado en a. La série de Maclaurin está centrada en a = 0.","de":"f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ. Stellt eine Funktion als unendliches Polynom zentriert bei a dar. Die Maclaurinreihe ist bei a = 0 zentriert.","fr":"f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ. Exprime une fonction comme un polynôme infini centré en a. La série de Maclaurin est centrée en a = 0.","tr":"f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ. Bir fonksiyonu a noktasında merkezlenmiş sonsuz bir polinom olarak ifade eder. Maclaurin serisi a = 0'da merkezlenir.","nl":"f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ. Drukt een functie uit als een oneindig polynoom gecentreerd bij a. De Maclaurinreeks is gecentreerd bij a = 0.","ru":"f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ. Представляет функцию в виде бесконечного многочлена с центром в точке a. Ряд Маклорена — частный случай при a = 0.","zh":"f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ。将函数表示为以 a 为中心的无穷多项式。麦克劳林级数以 a = 0 为中心。","pt_BR":"f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ. Expressa uma função como um polinômio infinito centrado em a. A série de Maclaurin está centrada em a = 0.","pt_PT":"f(x) = Σ f⁽ⁿ⁾(a)/n! × (x-a)ⁿ. Expressa uma função como um polinómio infinito centrado em a. A série de Maclaurin está centrada em a = 0."}, sort_order: 124 },
  { id: 'dc-math-0125', deck_id: 'deck-math', front: 'Maclaurin Series for eˣ', back: 'eˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!. This series converges for all x.', front_translations: {"es":"Série de Maclaurin para yˣ","de":"Maclaurin-Reihe für eˣ","fr":"Série de Maclaurin pour eˣ","tr":"eˣ için Maclaurin Serisi","nl":"Maclaurinreeks voor eˣ","ru":"Ряд Маклорена для eˣ","zh":"eˣ 的麦克劳林级数","pt_BR":"Série de Maclaurin para eˣ","pt_PT":"Série de Maclaurin para eˣ"}, back_translations: {"es":"yˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!. Esta série converge para todo x.","de":"eˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!. Diese Reihe konvergiert für alle x.","fr":"eˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!. Cette série converge pour tout x.","tr":"eˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!. Bu seri tüm x için yakınsar.","nl":"eˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!. Deze reeks convergeert voor alle x.","ru":"eˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!. Этот ряд сходится для всех x.","zh":"eˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!。该级数对所有 x 收敛。","pt_BR":"eˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!. Esta série converge para todo x.","pt_PT":"eˣ = 1 + x + x²/2! + x³/3! + x⁴/4! + ... = Σ xⁿ/n!. Esta série converge para todo x."}, sort_order: 125 },
  { id: 'dc-math-0126', deck_id: 'deck-math', front: 'Maclaurin Series for sin(x)', back: 'sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!. Contains only odd powers; converges for all x.', front_translations: {"es":"Série de Maclaurin para sin(x)","de":"Maclaurin-Reihe für sin(x)","fr":"Série de Maclaurin pour sin(x)","tr":"sin(x) için Maclaurin Serisi","nl":"Maclaurinreeks voor sin(x)","ru":"Ряд Маклорена для sin(x)","zh":"sin(x) 的麦克劳林级数","pt_BR":"Série de Maclaurin para sin(x)","pt_PT":"Série de Maclaurin para sin(x)"}, back_translations: {"es":"sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!. Contém solo potencias ímpares; converge para todo x.","de":"sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!. Enthält nur ungerade Potenzen; konvergiert für alle x.","fr":"sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!. Contient uniquement des puissances impaires ; converge pour tout x.","tr":"sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!. Yalnızca tek kuvvetler içerir; tüm x için yakınsar.","nl":"sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!. Bevat alleen oneven machten; convergeert voor alle x.","ru":"sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!. Содержит только нечётные степени; сходится для всех x.","zh":"sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!。只含奇次幂；对所有 x 收敛。","pt_BR":"sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!. Contém apenas potências ímpares; converge para todo x.","pt_PT":"sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + ... = Σ (-1)ⁿx^(2n+1)/(2n+1)!. Contém apenas potências ímpares; converge para todo x."}, sort_order: 126 },
  { id: 'dc-math-0127', deck_id: 'deck-math', front: 'Maclaurin Series for cos(x)', back: 'cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!. Contains only even powers; converges for all x.', front_translations: {"es":"Série de Maclaurin para cos(x)","de":"Maclaurin-Reihe für cos(x)","fr":"Série de Maclaurin pour cos(x)","tr":"cos(x) için Maclaurin Serisi","nl":"Maclaurinreeks voor cos(x)","ru":"Ряд Маклорена для cos(x)","zh":"cos(x) 的麦克劳林级数","pt_BR":"Série de Maclaurin para cos(x)","pt_PT":"Série de Maclaurin para cos(x)"}, back_translations: {"es":"cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!. Contém solo potencias pares; converge para todo x.","de":"cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!. Enthält nur gerade Potenzen; konvergiert für alle x.","fr":"cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!. Contient uniquement des puissances paires ; converge pour tout x.","tr":"cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!. Yalnızca çift kuvvetler içerir; tüm x için yakınsar.","nl":"cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!. Bevat alleen even machten; convergeert voor alle x.","ru":"cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!. Содержит только чётные степени; сходится для всех x.","zh":"cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!。只含偶次幂；对所有 x 收敛。","pt_BR":"cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!. Contém apenas potências pares; converge para todo x.","pt_PT":"cos(x) = 1 - x²/2! + x⁴/4! - x⁶/6! + ... = Σ (-1)ⁿx^(2n)/(2n)!. Contém apenas potências pares; converge para todo x."}, sort_order: 127 },
  { id: 'dc-math-0128', deck_id: 'deck-math', front: 'Ellipse Equation', back: 'x²/a² + y²/b² = 1. An ellipse centered at the origin with semi-major axis a (horizontal) and semi-minor axis b (vertical); a circle is the special case a = b = r.', front_translations: {"es":"Equación de una elipse","de":"Ellipsengleichung","fr":"Équation d'une ellipse","tr":"Elips Denklemi","nl":"Vergelijking van een ellips","ru":"Уравнение эллипса","zh":"椭圆方程","pt_BR":"Equação de uma elipse","pt_PT":"Equação de uma elipse"}, back_translations: {"es":"x²/a² + y²/b² = 1. Una elipse centrada en la origem con semi-eixo mayor a (horizontal) y semi-eixo menor b (vertical); un círculo es el caso especial a = b = r.","de":"x²/a² + y²/b² = 1. Eine Ellipse mit Mittelpunkt im Ursprung, Haupthalbachse a (horizontal) und Nebenhalbachse b (vertikal); ein Kreis ist der Spezialfall a = b = r.","fr":"x²/a² + y²/b² = 1. Une ellipse centrée à l'origine avec le demi-grand axe a (horizontal) et le demi-petit axe b (vertical) ; un cercle est le cas particulier a = b = r.","tr":"x²/a² + y²/b² = 1. Orijinde merkezlenmiş, büyük yarı ekseni a (yatay) ve küçük yarı ekseni b (dikey) olan bir elips; a = b = r özel durumu bir dairedir.","nl":"x²/a² + y²/b² = 1. Een ellips gecentreerd bij de oorsprong met semi-hoofdas a (horizontaal) en semi-kleine as b (verticaal); een cirkel is het speciale geval a = b = r.","ru":"x²/a² + y²/b² = 1. Эллипс с центром в начале координат, большой полуосью a (горизонтальной) и малой полуосью b (вертикальной); окружность — частный случай при a = b = r.","zh":"x²/a² + y²/b² = 1。以原点为中心、半长轴 a（水平）和半短轴 b（垂直）的椭圆；a = b = r 是圆的特例。","pt_BR":"x²/a² + y²/b² = 1. Uma elipse centrada na origem com semi-eixo maior a (horizontal) e semi-eixo menor b (vertical); um círculo é o caso especial a = b = r.","pt_PT":"x²/a² + y²/b² = 1. Uma elipse centrada na origem com semi-eixo maior a (horizontal) e semi-eixo menor b (vertical); um círculo é o caso especial a = b = r."}, sort_order: 128 },
  { id: 'dc-math-0129', deck_id: 'deck-math', front: 'Hyperbola Equation', back: 'x²/a² - y²/b² = 1 (horizontal) or y²/a² - x²/b² = 1 (vertical). A hyperbola has two branches; its asymptotes are y = ±(b/a)x.', front_translations: {"es":"Equación de una hipérbole","de":"Hyperbelgleichung","fr":"Équation d'une hyperbole","tr":"Hiperbol Denklemi","nl":"Vergelijking van een hyperbool","ru":"Уравнение гиперболы","zh":"双曲线方程","pt_BR":"Equação de uma hipérbole","pt_PT":"Equação de uma hipérbole"}, back_translations: {"es":"x²/a² - y²/b² = 1 (horizontal) o y²/a² - x²/b² = 1 (vertical). Una hipérbole tiene de los ramos; sus assíntotas son y = ±(b/a)x.","de":"x²/a² - y²/b² = 1 (horizontal) oder y²/a² - x²/b² = 1 (vertikal). Eine Hyperbel hat zwei Äste; ihre Asymptoten sind y = ±(b/a)x.","fr":"x²/a² - y²/b² = 1 (horizontale) ou y²/a² - x²/b² = 1 (verticale). Une hyperbole a deux branches ; ses asymptotes sont y = ±(b/a)x.","tr":"x²/a² - y²/b² = 1 (yatay) veya y²/a² - x²/b² = 1 (dikey). Hiperbolün iki kolu vardır; asimptotları y = ±(b/a)x'tir.","nl":"x²/a² - y²/b² = 1 (horizontaal) of y²/a² - x²/b² = 1 (verticaal). Een hyperbool heeft twee takken; zijn asymptoten zijn y = ±(b/a)x.","ru":"x²/a² - y²/b² = 1 (горизонтальная) или y²/a² - x²/b² = 1 (вертикальная). Гипербола имеет две ветви; её асимптоты y = ±(b/a)x.","zh":"x²/a² - y²/b² = 1（水平）或 y²/a² - x²/b² = 1（垂直）。双曲线有两条支；其渐近线为 y = ±(b/a)x。","pt_BR":"x²/a² - y²/b² = 1 (horizontal) ou y²/a² - x²/b² = 1 (vertical). Uma hipérbole tem dois ramos; suas assíntotas são y = ±(b/a)x.","pt_PT":"x²/a² - y²/b² = 1 (horizontal) ou y²/a² - x²/b² = 1 (vertical). Uma hipérbole tem dois ramos; as suas assíntotas são y = ±(b/a)x."}, sort_order: 129 },
  { id: 'dc-math-0130', deck_id: 'deck-math', front: 'Parabola (Conic Section)', back: 'y = ax² + bx + c or x = ay² + by + c. A conic section formed by cutting a cone parallel to its slant edge; the path of a projectile under constant gravity.', front_translations: {"es":"Parábola (seción conica)","de":"Parabel (Kegelschnitt)","fr":"Parabole (conique)","tr":"Parabol (Konik Kesit)","nl":"Parabool (kegelsnede)","ru":"Парабола (коническое сечение)","zh":"抛物线（圆锥截线）","pt_BR":"Parábola (seção cônica)","pt_PT":"Parábola (secção cónica)"}, back_translations: {"es":"y = ax² + bx + c o x = ay² + by + c. Una seción conica formada cortando un cone paralelamente a la su aresta oblíqua; a trajetória de un projétil sob gravidad constante.","de":"y = ax² + bx + c oder x = ay² + by + c. Ein Kegelschnitt, der durch einen Schnitt parallel zur Mantellinie des Kegels entsteht; die Bahn eines Projektils unter konstanter Schwerkraft.","fr":"y = ax² + bx + c ou x = ay² + by + c. Une conique formée en coupant un cône parallèlement à son arête oblique ; la trajectoire d'un projectile sous gravité constante.","tr":"y = ax² + bx + c veya x = ay² + by + c. Koninin eğik kenarına paralel kesilerek oluşturulan konik kesit; sabit yerçekimi altında bir merminin yolu.","nl":"y = ax² + bx + c of x = ay² + by + c. Een kegelsnede gevormd door een kegel te snijden evenwijdig aan zijn schuine rand; het pad van een projectiel onder constante zwaartekracht.","ru":"y = ax² + bx + c или x = ay² + by + c. Коническое сечение, образованное рассечением конуса параллельно образующей; траектория снаряда при постоянном ускорении силы тяжести.","zh":"y = ax² + bx + c 或 x = ay² + by + c。通过平行于圆锥母线截锥体形成的圆锥截线；在恒定重力下抛体的运动轨迹。","pt_BR":"y = ax² + bx + c ou x = ay² + by + c. Uma seção cônica formada cortando um cone paralelamente à sua aresta oblíqua; a trajetória de um projétil sob gravidade constante.","pt_PT":"y = ax² + bx + c ou x = ay² + by + c. Uma secção cónica formada cortando um cone paralelamente à sua aresta oblíqua; a trajectória de um projéctil sob gravidade constante."}, sort_order: 130 },
  { id: 'dc-math-0131', deck_id: 'deck-math', front: 'Polar Coordinates', back: 'A 2D coordinate system where a point is given by (r, θ): r is the distance from the origin and θ is the angle from the positive x-axis. x = r cos θ, y = r sin θ.', front_translations: {"es":"Coordenadas polares","de":"Polarkoordinaten","fr":"Coordonnées polaires","tr":"Kutupsal Koordinatlar","nl":"Poolcoördinaten","ru":"Полярные координаты","zh":"极坐标","pt_BR":"Coordenadas polares","pt_PT":"Coordenadas polares"}, back_translations: {"es":"Un sistema de coordenadas 2D donde un punto es dato por (r, θ): r es a distancia de la origem y θ es el ángulo del eixo x positivo. x = r cos θ, y = r sin θ.","de":"Ein 2D-Koordinatensystem, bei dem ein Punkt durch (r, θ) gegeben ist: r ist der Abstand vom Ursprung und θ ist der Winkel von der positiven x-Achse. x = r cos θ, y = r sin θ.","fr":"Un système de coordonnées 2D où un point est donné par (r, θ) : r est la distance à l'origine et θ est l'angle par rapport à l'axe x positif. x = r cos θ, y = r sin θ.","tr":"Bir noktanın (r, θ) ile verildiği 2B koordinat sistemi: r, orijinden uzaklık ve θ, pozitif x ekseninden açıdır. x = r cos θ, y = r sin θ.","nl":"Een 2D-coördinatensysteem waarbij een punt gegeven is door (r, θ): r is de afstand tot de oorsprong en θ is de hoek met de positieve x-as. x = r cos θ, y = r sin θ.","ru":"Двумерная система координат, в которой точка задаётся парой (r, θ): r — расстояние от начала координат, θ — угол от положительной оси x. x = r cos θ, y = r sin θ.","zh":"二维坐标系，点由 (r, θ) 表示：r 是到原点的距离，θ 是与正 x 轴的夹角。x = r cos θ，y = r sin θ。","pt_BR":"Um sistema de coordenadas 2D onde um ponto é dado por (r, θ): r é a distância da origem e θ é o ângulo do eixo x positivo. x = r cos θ, y = r sin θ.","pt_PT":"Um sistema de coordenadas 2D onde um ponto é dado por (r, θ): r é a distância da origem e θ é o ângulo do eixo x positivo. x = r cos θ, y = r sin θ."}, sort_order: 131 },
  { id: 'dc-math-0132', deck_id: 'deck-math', front: 'Arc Length Formula', back: 'L = ∫[a to b] √(1 + (dy/dx)²) dx. The length of a curve from x = a to x = b; in parametric form L = ∫√((dx/dt)² + (dy/dt)²) dt.', front_translations: {"es":"Fórmula del comprimento de arco","de":"Bogenlängenformel","fr":"Formule de la longueur d'arc","tr":"Yay Uzunluğu Formülü","nl":"Booglengte-formule","ru":"Формула длины дуги","zh":"弧长公式","pt_BR":"Fórmula do comprimento de arco","pt_PT":"Fórmula do comprimento de arco"}, back_translations: {"es":"L = ∫[a a b] √(1 + (dy/dx)²) dx. El comprimento de una curva de x = a a x = b; en la forma paramétrica L = ∫√((dx/dt)² + (dy/dt)²) dt.","de":"L = ∫[a bis b] √(1 + (dy/dx)²) dx. Die Länge einer Kurve von x = a bis x = b; in Parameterform L = ∫√((dx/dt)² + (dy/dt)²) dt.","fr":"L = ∫[a à b] √(1 + (dy/dx)²) dx. La longueur d'une courbe de x = a à x = b ; en forme paramétrique L = ∫√((dx/dt)² + (dy/dt)²) dt.","tr":"L = ∫[a'dan b'ye] √(1 + (dy/dx)²) dx. x = a'dan x = b'ye kadar bir eğrinin uzunluğu; parametrik formda L = ∫√((dx/dt)² + (dy/dt)²) dt.","nl":"L = ∫[a tot b] √(1 + (dy/dx)²) dx. De lengte van een curve van x = a tot x = b; in parametrische vorm L = ∫√((dx/dt)² + (dy/dt)²) dt.","ru":"L = ∫[a до b] √(1 + (dy/dx)²) dx. Длина кривой от x = a до x = b; в параметрической форме L = ∫√((dx/dt)² + (dy/dt)²) dt.","zh":"L = ∫[a 到 b] √(1 + (dy/dx)²) dx。曲线从 x = a 到 x = b 的长度；参数形式 L = ∫√((dx/dt)² + (dy/dt)²) dt。","pt_BR":"L = ∫[a a b] √(1 + (dy/dx)²) dx. O comprimento de uma curva de x = a a x = b; na forma paramétrica L = ∫√((dx/dt)² + (dy/dt)²) dt.","pt_PT":"L = ∫[a a b] √(1 + (dy/dx)²) dx. O comprimento de uma curva de x = a a x = b; na forma paramétrica L = ∫√((dx/dt)² + (dy/dt)²) dt."}, sort_order: 132 },
  { id: 'dc-math-0133', deck_id: 'deck-math', front: 'Surface Area of Revolution', back: 'SA = 2π ∫[a to b] f(x) √(1 + (f\'(x))²) dx. The surface area generated by rotating curve y = f(x) about the x-axis.', front_translations: {"es":"Área de superficie de revolución","de":"Rotationsfläche","fr":"Aire de révolution","tr":"Dönel Yüzey Alanı","nl":"Oppervlakte van omwenteling","ru":"Площадь поверхности вращения","zh":"旋转体表面积","pt_BR":"Área de superfície de revolução","pt_PT":"Área de superfície de revolução"}, back_translations: {"es":"SA = 2π ∫[a a b] f(x) √(1 + (f'(x))²) dx. La área superficial gerada por la rotación de la curva y = f(x) en torno del eixo x.","de":"SA = 2π ∫[a bis b] f(x) √(1 + (f'(x))²) dx. Die Oberfläche, die durch das Rotieren der Kurve y = f(x) um die x-Achse entsteht.","fr":"SA = 2π ∫[a à b] f(x) √(1 + (f'(x))²) dx. L'aire de la surface générée par la rotation de la courbe y = f(x) autour de l'axe des x.","tr":"SA = 2π ∫[a'dan b'ye] f(x) √(1 + (f'(x))²) dx. y = f(x) eğrisinin x ekseni etrafında döndürülmesiyle oluşturulan yüzey alanı.","nl":"SA = 2π ∫[a tot b] f(x) √(1 + (f'(x))²) dx. De oppervlakte gegenereerd door curve y = f(x) om de x-as te roteren.","ru":"SA = 2π ∫[a до b] f(x) √(1 + (f'(x))²) dx. Площадь поверхности, образованной вращением кривой y = f(x) вокруг оси x.","zh":"SA = 2π ∫[a 到 b] f(x) √(1 + (f'(x))²) dx。曲线 y = f(x) 绕 x 轴旋转所得旋转体的表面积。","pt_BR":"SA = 2π ∫[a a b] f(x) √(1 + (f'(x))²) dx. A área superficial gerada pela rotação da curva y = f(x) em torno do eixo x.","pt_PT":"SA = 2π ∫[a a b] f(x) √(1 + (f'(x))²) dx. A área superficial gerada pela rotação da curva y = f(x) em torno do eixo x."}, sort_order: 133 },
  { id: 'dc-math-0134', deck_id: 'deck-math', front: 'Differential Equation (ODE)', back: 'An equation relating a function to its derivatives. Order is the highest derivative present; degree is its power. e.g., dy/dx = ky models exponential growth/decay.', front_translations: {"es":"Equación diferencial ordinária (EDO)","de":"Differentialgleichung (ODE)","fr":"Équation différentielle (EDO)","tr":"Diferansiyel Denklem (ODE)","nl":"Differentiaalvergelijking (ODE)","ru":"Обыкновенное дифференциальное уравнение (ОДУ)","zh":"常微分方程（ODE）","pt_BR":"Equação diferencial ordinária (EDO)","pt_PT":"Equação diferencial ordinária (EDO)"}, back_translations: {"es":"Una ecuación que relaciona una función a las sus derivadas. La ordem es a derivada más alta presente; el grau es su potencia. Ex.: dy/dx = ky modela crecimiento/decaimento exponencial.","de":"Eine Gleichung, die eine Funktion mit ihren Ableitungen in Beziehung setzt. Die Ordnung ist die höchste vorhandene Ableitung; der Grad ist ihre Potenz. z.B. modelliert dy/dx = ky exponentielles Wachstum/Zerfall.","fr":"Une équation reliant une fonction à ses dérivées. L'ordre est la dérivée la plus haute présente ; le degré est sa puissance. Ex. dy/dx = ky modélise la croissance/décroissance exponentielle.","tr":"Bir fonksiyonu türevleriyle ilişkilendiren bir denklem. Derece, mevcut en yüksek türevdir; kuvvet ise onun üssüdür. Örn. dy/dx = ky, üstel büyüme/bozunmayı modellendirir.","nl":"Een vergelijking die een functie relateert aan zijn afgeleiden. De orde is de hoogste aanwezige afgeleide; de graad is de macht ervan. Bijv. dy/dx = ky modelleert exponentiële groei/verval.","ru":"Уравнение, связывающее функцию с её производными. Порядок — наивысшая присутствующая производная; степень — её показатель. Напр., dy/dx = ky моделирует экспоненциальный рост/распад.","zh":"将函数与其导数联系起来的方程。阶数是方程中出现的最高阶导数；次数是其幂次。例如，dy/dx = ky 模拟指数增长/衰减。","pt_BR":"Uma equação que relaciona uma função às suas derivadas. A ordem é a derivada mais alta presente; o grau é sua potência. Ex.: dy/dx = ky modela crescimento/decaimento exponencial.","pt_PT":"Uma equação que relaciona uma função às suas derivadas. A ordem é a derivada mais alta presente; o grau é a sua potência. Ex.: dy/dx = ky modela crescimento/decaimento exponencial."}, sort_order: 134 },
  { id: 'dc-math-0135', deck_id: 'deck-math', front: 'Separable Differential Equation', back: 'A first-order ODE that can be written as f(y)dy = g(x)dx; solved by integrating both sides separately. e.g., dy/dx = xy separates to (1/y)dy = x dx.', front_translations: {"es":"Equación diferencial separable","de":"Trennbare Differentialgleichung","fr":"Équation différentielle à variables séparables","tr":"Ayrılabilir Diferansiyel Denklem","nl":"Scheidbare differentiaalvergelijking","ru":"Разделяемое дифференциальное уравнение","zh":"可分离变量的微分方程","pt_BR":"Equação diferencial separável","pt_PT":"Equação diferencial separável"}, back_translations: {"es":"Una EDO de primera ordem que puede ser escrita como f(y)dy = g(x)dx; resolvida integrando ambos los lados separadamente. Ex.: dy/dx = xy separa-se en (1/y)dy = x dx.","de":"Eine Differentialgleichung erster Ordnung, die als f(y)dy = g(x)dx geschrieben werden kann; gelöst durch getrennte Integration beider Seiten. z.B. separiert dy/dx = xy zu (1/y)dy = x dx.","fr":"Une EDO du premier ordre qui peut s'écrire f(y)dy = g(x)dx ; résolue en intégrant les deux membres séparément. Ex. dy/dx = xy se sépare en (1/y)dy = x dx.","tr":"f(y)dy = g(x)dx olarak yazılabilen birinci dereceden ODE; her iki taraf ayrı ayrı integre edilerek çözülür. Örn. dy/dx = xy, (1/y)dy = x dx'e ayrılır.","nl":"Een eersteorde ODE die geschreven kan worden als f(y)dy = g(x)dx; opgelost door beide zijden afzonderlijk te integreren. Bijv. dy/dx = xy wordt gescheiden tot (1/y)dy = x dx.","ru":"ОДУ первого порядка, записываемое в виде f(y)dy = g(x)dx; решается интегрированием обеих частей по отдельности. Напр., dy/dx = xy разделяется до (1/y)dy = x dx.","zh":"可以写成 f(y)dy = g(x)dx 的一阶 ODE；通过分别对两边积分求解。例：dy/dx = xy 分离为 (1/y)dy = x dx。","pt_BR":"Uma EDO de primeira ordem que pode ser escrita como f(y)dy = g(x)dx; resolvida integrando ambos os lados separadamente. Ex.: dy/dx = xy separa-se em (1/y)dy = x dx.","pt_PT":"Uma EDO de primeira ordem que pode ser escrita como f(y)dy = g(x)dx; resolvida integrando ambos os lados separadamente. Ex.: dy/dx = xy separa-se em (1/y)dy = x dx."}, sort_order: 135 },
  { id: 'dc-math-0136', deck_id: 'deck-math', front: 'Exponential Growth/Decay Formula', back: 'N(t) = N₀eᵏᵗ. Solution to dN/dt = kN; k > 0 models growth (population, compound interest), k < 0 models decay (radioactive decay, cooling).', front_translations: {"es":"Fórmula de crecimiento/decaimento exponencial","de":"Formel für exponentielles Wachstum/Zerfall","fr":"Formule de croissance/décroissance exponentielle","tr":"Üstel Büyüme/Bozunma Formülü","nl":"Formule voor exponentiële groei/verval","ru":"Формула экспоненциального роста/убывания","zh":"指数增长/衰减公式","pt_BR":"Fórmula de crescimento/decaimento exponencial","pt_PT":"Fórmula de crescimento/decaimento exponencial"}, back_translations: {"es":"N(t) = N₀yᵏᵗ. Solución para dN/dt = kN; k > 0 modela crecimiento (población, juros compuestos), k < 0 modela decaimento (decaimento radioativo, resfriamento).","de":"N(t) = N₀eᵏᵗ. Lösung von dN/dt = kN; k > 0 modelliert Wachstum (Bevölkerung, Zinseszins), k < 0 modelliert Zerfall (radioaktiver Zerfall, Abkühlung).","fr":"N(t) = N₀eᵏᵗ. Solution de dN/dt = kN ; k > 0 modélise la croissance (population, intérêts composés), k < 0 modélise la décroissance (désintégration radioactive, refroidissement).","tr":"N(t) = N₀eᵏᵗ. dN/dt = kN'nin çözümü; k > 0 büyümeyi modellendirir (nüfus, bileşik faiz), k < 0 bozunmayı modellendirir (radyoaktif bozunma, soğuma).","nl":"N(t) = N₀eᵏᵗ. Oplossing van dN/dt = kN; k > 0 modelleert groei (bevolking, samengestelde rente), k < 0 modelleert verval (radioactief verval, afkoeling).","ru":"N(t) = N₀eᵏᵗ. Решение dN/dt = kN; k > 0 моделирует рост (население, сложные проценты), k < 0 — убывание (радиоактивный распад, охлаждение).","zh":"N(t) = N₀eᵏᵗ。dN/dt = kN 的解；k > 0 模拟增长（人口、复利），k < 0 模拟衰减（放射性衰变、冷却）。","pt_BR":"N(t) = N₀eᵏᵗ. Solução para dN/dt = kN; k > 0 modela crescimento (população, juros compostos), k < 0 modela decaimento (decaimento radioativo, resfriamento).","pt_PT":"N(t) = N₀eᵏᵗ. Solução para dN/dt = kN; k > 0 modela crescimento (população, juros compostos), k < 0 modela decaimento (decaimento radioativo, arrefecimento)."}, sort_order: 136 },
  { id: 'dc-math-0137', deck_id: 'deck-math', front: 'Half-Life Formula', back: 't₁/₂ = ln(2)/k. The time for a quantity to reduce to half its initial value in exponential decay; derived from N(t) = N₀e^(-kt) setting N = N₀/2.', front_translations: {"es":"Fórmula de la media-vida","de":"Halbwertzeitformel","fr":"Formule de la demi-vie","tr":"Yarı-Ömür Formülü","nl":"Halveringstijdformule","ru":"Формула периода полураспада","zh":"半衰期公式","pt_BR":"Fórmula da meia-vida","pt_PT":"Fórmula da meia-vida"}, back_translations: {"es":"t₁/₂ = ln(2)/k. El tiempo para una cantidad reduzir a la metade de su valor inicial en el decaimento exponencial; derivado de N(t) = N₀y^(-kt) con N = N₀/2.","de":"t₁/₂ = ln(2)/k. Die Zeit, in der eine Größe auf die Hälfte ihres Anfangswerts beim exponentiellen Zerfall reduziert wird; abgeleitet aus N(t) = N₀e^(-kt) mit N = N₀/2.","fr":"t₁/₂ = ln(2)/k. Le temps pour qu'une quantité se réduise à la moitié de sa valeur initiale lors d'une décroissance exponentielle ; dérivé de N(t) = N₀e^(-kt) en posant N = N₀/2.","tr":"t₁/₂ = ln(2)/k. Üstel bozunmada bir miktarın başlangıç değerinin yarısına düşmesi için geçen süre; N = N₀/2 alınarak N(t) = N₀e^(-kt)'den türetilir.","nl":"t₁/₂ = ln(2)/k. De tijd voor een hoeveelheid om te halveren bij exponentieel verval; afgeleid uit N(t) = N₀e^(-kt) met N = N₀/2.","ru":"t₁/₂ = ln(2)/k. Время, за которое величина уменьшается вдвое при экспоненциальном распаде; выводится из N(t) = N₀e^(-kt) при N = N₀/2.","zh":"t₁/₂ = ln(2)/k。指数衰减中某量减少到初始值一半所需的时间；由 N(t) = N₀e^(-kt) 令 N = N₀/2 推导而来。","pt_BR":"t₁/₂ = ln(2)/k. O tempo para uma quantidade reduzir à metade de seu valor inicial no decaimento exponencial; derivado de N(t) = N₀e^(-kt) com N = N₀/2.","pt_PT":"t₁/₂ = ln(2)/k. O tempo para uma quantidade reduzir a metade do seu valor inicial no decaimento exponencial; derivado de N(t) = N₀e^(-kt) com N = N₀/2."}, sort_order: 137 },
  { id: 'dc-math-0138', deck_id: 'deck-math', front: 'Compound Interest Formula', back: 'A = P(1 + r/n)^(nt). P = principal, r = annual rate, n = compounding periods per year, t = years. For continuous compounding: A = Peʳᵗ.', front_translations: {"es":"Fórmula de juros compuestos","de":"Zinseszinsformel","fr":"Formule des intérêts composés","tr":"Bileşik Faiz Formülü","nl":"Samengestelde rente formule","ru":"Формула сложных процентов","zh":"复利公式","pt_BR":"Fórmula de juros compostos","pt_PT":"Fórmula de juros compostos"}, back_translations: {"es":"La = P(1 + r/n)^(nt). P = principal, r = taxa anual, n = períodos de composición por ano, t = anos. Para composición contínua: La = Peʳᵗ.","de":"A = P(1 + r/n)^(nt). P = Kapital, r = jährlicher Zinssatz, n = Zinsperioden pro Jahr, t = Jahre. Für kontinuierliche Verzinsung: A = Peʳᵗ.","fr":"A = P(1 + r/n)^(nt). P = capital, r = taux annuel, n = périodes de capitalisation par an, t = années. Pour la capitalisation continue : A = Peʳᵗ.","tr":"A = P(1 + r/n)^(nt). P = ana para, r = yıllık oran, n = yıllık bileşim dönemi sayısı, t = yıl. Sürekli bileşim için: A = Peʳᵗ.","nl":"A = P(1 + r/n)^(nt). P = hoofdsom, r = jaarlijkse rente, n = samenstellingsperioden per jaar, t = jaren. Voor continue samenstelling: A = Peʳᵗ.","ru":"A = P(1 + r/n)^(nt). P — основная сумма, r — годовая ставка, n — количество периодов начисления в год, t — лет. При непрерывном начислении: A = Peʳᵗ.","zh":"A = P(1 + r/n)^(nt)。P = 本金，r = 年利率，n = 每年计息次数，t = 年数。连续复利时：A = Peʳᵗ。","pt_BR":"A = P(1 + r/n)^(nt). P = principal, r = taxa anual, n = períodos de composição por ano, t = anos. Para composição contínua: A = Peʳᵗ.","pt_PT":"A = P(1 + r/n)^(nt). P = capital, r = taxa anual, n = períodos de capitalização por ano, t = anos. Para capitalização contínua: A = Peʳᵗ."}, sort_order: 138 },
  { id: 'dc-math-0139', deck_id: 'deck-math', front: 'Expected Value', back: 'E(X) = Σ xᵢ P(xᵢ). The weighted average outcome of a random variable, with probabilities as weights. For continuous distributions: E(X) = ∫ x f(x) dx.', front_translations: {"es":"Valor esperado","de":"Erwartungswert","fr":"Espérance mathématique","tr":"Beklenen Değer","nl":"Verwachte waarde","ru":"Математическое ожидание","zh":"期望值","pt_BR":"Valor esperado","pt_PT":"Valor esperado"}, back_translations: {"es":"Y(X) = Σ xᵢ P(xᵢ). La média ponderada del resultado de una variable aleatória, con probabilidades como pesos. Para distribuiciones contínuas: Y(X) = ∫ x f(x) dx.","de":"E(X) = Σ xᵢ P(xᵢ). Das gewichtete Mittel des Ergebnisses einer Zufallsvariablen, mit den Wahrscheinlichkeiten als Gewichten. Für stetige Verteilungen: E(X) = ∫ x f(x) dx.","fr":"E(X) = Σ xᵢ P(xᵢ). La moyenne pondérée du résultat d'une variable aléatoire, avec les probabilités comme poids. Pour les distributions continues : E(X) = ∫ x f(x) dx.","tr":"E(X) = Σ xᵢ P(xᵢ). Olasılıkları ağırlık olarak kullanan rastgele bir değişkenin ağırlıklı ortalama sonucu. Sürekli dağılımlar için: E(X) = ∫ x f(x) dx.","nl":"E(X) = Σ xᵢ P(xᵢ). Het gewogen gemiddelde uitkomst van een willekeurige variabele, met kansen als gewichten. Voor continue verdelingen: E(X) = ∫ x f(x) dx.","ru":"E(X) = Σ xᵢ P(xᵢ). Взвешенное среднее значение случайной величины, где весами служат вероятности. Для непрерывных распределений: E(X) = ∫ x f(x) dx.","zh":"E(X) = Σ xᵢ P(xᵢ)。以概率为权重的随机变量的加权平均结果。对于连续分布：E(X) = ∫ x f(x) dx。","pt_BR":"E(X) = Σ xᵢ P(xᵢ). A média ponderada do resultado de uma variável aleatória, com probabilidades como pesos. Para distribuições contínuas: E(X) = ∫ x f(x) dx.","pt_PT":"E(X) = Σ xᵢ P(xᵢ). A média ponderada do resultado de uma variável aleatória, com probabilidades como pesos. Para distribuições contínuas: E(X) = ∫ x f(x) dx."}, sort_order: 139 },
  { id: 'dc-math-0140', deck_id: 'deck-math', front: 'Binomial Distribution', back: 'P(X=k) = C(n,k) pᵏ (1-p)^(n-k). Models the number of successes k in n independent trials with success probability p; mean = np, variance = np(1-p).', front_translations: {"es":"Distribuición binomial","de":"Binomialverteilung","fr":"Distribution binomiale","tr":"Binom Dağılımı","nl":"Binomiale verdeling","ru":"Биномиальное распределение","zh":"二项分布","pt_BR":"Distribuição binomial","pt_PT":"Distribuição binomial"}, back_translations: {"es":"P(X=k) = C(n,k) pᵏ (1-p)^(n-k). Modela el número de sucessos k en n ensaios independentes con probabilidad de éxito p; média = np, variancia = np(1-p).","de":"P(X=k) = C(n,k) pᵏ (1-p)^(n-k). Modelliert die Anzahl der Erfolge k in n unabhängigen Versuchen mit Erfolgswahrscheinlichkeit p; Mittelwert = np, Varianz = np(1-p).","fr":"P(X=k) = C(n,k) pᵏ (1-p)^(n-k). Modélise le nombre de succès k en n essais indépendants avec probabilité de succès p ; moyenne = np, variance = np(1-p).","tr":"P(X=k) = C(n,k) pᵏ (1-p)^(n-k). Başarı olasılığı p olan n bağımsız denemede k başarı sayısını modellendirir; ortalama = np, varyans = np(1-p).","nl":"P(X=k) = C(n,k) pᵏ (1-p)^(n-k). Modelleert het aantal successen k in n onafhankelijke proeven met succesk kans p; gemiddelde = np, variantie = np(1-p).","ru":"P(X=k) = C(n,k) pᵏ (1-p)^(n-k). Моделирует количество успехов k в n независимых испытаниях с вероятностью успеха p; среднее = np, дисперсия = np(1-p).","zh":"P(X=k) = C(n,k) pᵏ (1-p)^(n-k)。模拟在 n 次独立试验中成功 k 次的情况，成功概率为 p；均值 = np，方差 = np(1-p)。","pt_BR":"P(X=k) = C(n,k) pᵏ (1-p)^(n-k). Modela o número de sucessos k em n ensaios independentes com probabilidade de sucesso p; média = np, variância = np(1-p).","pt_PT":"P(X=k) = C(n,k) pᵏ (1-p)^(n-k). Modela o número de sucessos k em n ensaios independentes com probabilidade de sucesso p; média = np, variância = np(1-p)."}, sort_order: 140 },
  { id: 'dc-math-0141', deck_id: 'deck-math', front: 'Poisson Distribution', back: 'P(X=k) = (λᵏ e^(-λ)) / k!. Models the number of rare events in a fixed interval when the average rate is λ; both mean and variance equal λ.', front_translations: {"es":"Distribuición de Poisson","de":"Poisson-Verteilung","fr":"Distribution de Poisson","tr":"Poisson Dağılımı","nl":"Poisson-verdeling","ru":"Распределение Пуассона","zh":"泊松分布","pt_BR":"Distribuição de Poisson","pt_PT":"Distribuição de Poisson"}, back_translations: {"es":"P(X=k) = (λᵏ y^(-λ)) / k!. Modela el número de eventos raros en un intervalo fixo cuando a taxa média es λ; tanto a média quanto a variancia son iguais a λ.","de":"P(X=k) = (λᵏ e^(-λ)) / k!. Modelliert die Anzahl seltener Ereignisse in einem festen Intervall bei einer Durchschnittsrate λ; sowohl Mittelwert als auch Varianz sind gleich λ.","fr":"P(X=k) = (λᵏ e^(-λ)) / k!. Modélise le nombre d'événements rares dans un intervalle fixe quand le taux moyen est λ ; la moyenne et la variance sont toutes deux égales à λ.","tr":"P(X=k) = (λᵏ e^(-λ)) / k!. Ortalama oran λ olduğunda sabit bir aralıkta nadir olayların sayısını modellendirir; hem ortalama hem de varyans λ'ya eşittir.","nl":"P(X=k) = (λᵏ e^(-λ)) / k!. Modelleert het aantal zeldzame gebeurtenissen in een vast interval wanneer de gemiddelde snelheid λ is; zowel gemiddelde als variantie zijn gelijk aan λ.","ru":"P(X=k) = (λᵏ e^(-λ)) / k!. Моделирует количество редких событий в фиксированном интервале при средней скорости λ; среднее и дисперсия равны λ.","zh":"P(X=k) = (λᵏ e^(-λ)) / k!。模拟在平均速率为 λ 的固定区间内稀有事件的数量；均值和方差均等于 λ。","pt_BR":"P(X=k) = (λᵏ e^(-λ)) / k!. Modela o número de eventos raros em um intervalo fixo quando a taxa média é λ; tanto a média quanto a variância são iguais a λ.","pt_PT":"P(X=k) = (λᵏ e^(-λ)) / k!. Modela o número de eventos raros num intervalo fixo quando a taxa média é λ; tanto a média como a variância são iguais a λ."}, sort_order: 141 },
  { id: 'dc-math-0142', deck_id: 'deck-math', front: 'Confidence Interval (95%)', back: 'CI = x̄ ± 1.96 × (σ/√n). A range estimated to contain the true population parameter with 95% confidence; wider for smaller samples or larger variance.', front_translations: {"es":"Intervalo de confiança (95%)","de":"Konfidenzintervall (95%)","fr":"Intervalle de confiance (95%)","tr":"Güven Aralığı (%95)","nl":"Betrouwbaarheidsinterval (95%)","ru":"Доверительный интервал (95%)","zh":"置信区间（95%）","pt_BR":"Intervalo de confiança (95%)","pt_PT":"Intervalo de confiança (95%)"}, back_translations: {"es":"IC = x̄ ± 1,96 × (σ/√n). Un intervalo estimado para conter el verdadero parametro populacional con 95% de confiança; más ancho para amostras menores o mayor variancia.","de":"KI = x̄ ± 1,96 × (σ/√n). Ein Bereich, der den wahren Populationsparameter mit 95%iger Wahrscheinlichkeit enthält; breiter bei kleineren Stichproben oder größerer Varianz.","fr":"IC = x̄ ± 1,96 × (σ/√n). Une plage estimée contenir le vrai paramètre de population avec 95% de confiance ; plus large pour de petits échantillons ou une grande variance.","tr":"GA = x̄ ± 1,96 × (σ/√n). Gerçek popülasyon parametresini %95 güvenle içerdiği tahmin edilen bir aralık; daha küçük örnekler veya daha büyük varyans için daha geniştir.","nl":"BI = x̄ ± 1,96 × (σ/√n). Een bereik dat naar schatting de werkelijke populatieparameter met 95% betrouwbaarheid bevat; breder voor kleinere steekproeven of grotere variantie.","ru":"ДИ = x̄ ± 1,96 × (σ/√n). Интервал, который, по оценке, содержит истинный параметр генеральной совокупности с вероятностью 95%; шире при меньших выборках или большей дисперсии.","zh":"CI = x̄ ± 1.96 × (σ/√n)。估计以 95% 置信度包含真实总体参数的范围；样本较小或方差较大时更宽。","pt_BR":"IC = x̄ ± 1,96 × (σ/√n). Um intervalo estimado para conter o verdadeiro parâmetro populacional com 95% de confiança; mais largo para amostras menores ou maior variância.","pt_PT":"IC = x̄ ± 1,96 × (σ/√n). Um intervalo estimado para conter o verdadeiro parâmetro populacional com 95% de confiança; mais largo para amostras menores ou maior variância."}, sort_order: 142 },
  { id: 'dc-math-0143', deck_id: 'deck-math', front: 'Hypothesis Testing: p-value', back: 'The probability of observing results at least as extreme as those obtained, assuming the null hypothesis is true. A p-value below the significance level (e.g., 0.05) leads to rejection of H₀.', front_translations: {"es":"Teste de hipótese: valor p","de":"Hypothesentest: p-Wert","fr":"Test d'hypothèse : valeur p","tr":"Hipotez Testi: p-değeri","nl":"Hypothesetoets: p-waarde","ru":"Проверка гипотезы: p-значение","zh":"假设检验：p 值","pt_BR":"Teste de hipótese: valor p","pt_PT":"Teste de hipótese: valor p"}, back_translations: {"es":"La probabilidad de observar resultados por el menos tão extremos quanto los obtidos, assumindo que a hipótese nula es verdadera. Un valor p debajo del nivel de significancia (ex.: 0,05) leva a la rejeición de H₀.","de":"Die Wahrscheinlichkeit, Ergebnisse zu beobachten, die mindestens so extrem sind wie die erhaltenen, unter der Annahme, dass die Nullhypothese wahr ist. Ein p-Wert unterhalb des Signifikanzniveaus (z.B. 0,05) führt zur Ablehnung von H₀.","fr":"La probabilité d'observer des résultats au moins aussi extrêmes que ceux obtenus, en supposant que l'hypothèse nulle est vraie. Une valeur p inférieure au niveau de signification (ex. 0,05) conduit au rejet de H₀.","tr":"Sıfır hipotezinin doğru olduğu varsayımıyla, elde edilenler kadar aşırı sonuçlar gözlemlenme olasılığı. Anlamlılık düzeyinin (örn. 0,05) altındaki bir p-değeri H₀'ın reddedilmesine yol açar.","nl":"De kans op het waarnemen van resultaten ten minste zo extreem als de verkregen, ervan uitgaande dat de nulhypothese waar is. Een p-waarde onder het significantieniveau (bijv. 0,05) leidt tot verwerping van H₀.","ru":"Вероятность наблюдать результаты не менее экстремальные, чем полученные, при условии истинности нулевой гипотезы. p-значение ниже уровня значимости (напр., 0,05) приводит к отклонению H₀.","zh":"假设原假设为真时，观察到至少与所得结果一样极端的结果的概率。p 值低于显著性水平（如 0.05）导致拒绝 H₀。","pt_BR":"A probabilidade de observar resultados pelo menos tão extremos quanto os obtidos, assumindo que a hipótese nula é verdadeira. Um valor p abaixo do nível de significância (ex.: 0,05) leva à rejeição de H₀.","pt_PT":"A probabilidade de observar resultados pelo menos tão extremos quanto os obtidos, assumindo que a hipótese nula é verdadeira. Um valor p abaixo do nível de significância (ex.: 0,05) leva à rejeição de H₀."}, sort_order: 143 },
  { id: 'dc-math-0144', deck_id: 'deck-math', front: 'Type I and Type II Errors', back: 'Type I error (α): rejecting a true null hypothesis (false positive). Type II error (β): failing to reject a false null hypothesis (false negative). Power = 1 - β.', front_translations: {"es":"Erros Tipo I y Tipo II","de":"Fehler 1. und 2. Art","fr":"Erreurs de type I et II","tr":"Tip I ve Tip II Hatalar","nl":"Type I en type II fouten","ru":"Ошибки первого и второго рода","zh":"第一类错误和第二类错误","pt_BR":"Erros Tipo I e Tipo II","pt_PT":"Erros Tipo I e Tipo II"}, back_translations: {"es":"Erro Tipo I (α): rejeitar una hipótese nula verdadera (falso positivo). Erro Tipo II (β): no rejeitar una hipótese nula falsa (falso negativo). Poder = 1 - β.","de":"Fehler 1. Art (α): Ablehnung einer wahren Nullhypothese (falsch positiv). Fehler 2. Art (β): Nicht-Ablehnung einer falschen Nullhypothese (falsch negativ). Teststärke = 1 - β.","fr":"Erreur de type I (α) : rejeter une hypothèse nulle vraie (faux positif). Erreur de type II (β) : ne pas rejeter une hypothèse nulle fausse (faux négatif). Puissance = 1 - β.","tr":"Tip I hata (α): Doğru sıfır hipotezini reddetme (yanlış pozitif). Tip II hata (β): Yanlış sıfır hipotezini reddedememe (yanlış negatif). Güç = 1 - β.","nl":"Type I fout (α): verwerpen van een ware nulhypothese (vals positief). Type II fout (β): niet verwerpen van een valse nulhypothese (vals negatief). Vermogen = 1 - β.","ru":"Ошибка первого рода (α): отклонение истинной нулевой гипотезы (ложноположительный результат). Ошибка второго рода (β): непринятие ложной нулевой гипотезы (ложноотрицательный). Мощность = 1 - β.","zh":"第一类错误（α）：拒绝真实的原假设（假阳性）。第二类错误（β）：未能拒绝错误的原假设（假阴性）。检验功效 = 1 - β。","pt_BR":"Erro Tipo I (α): rejeitar uma hipótese nula verdadeira (falso positivo). Erro Tipo II (β): não rejeitar uma hipótese nula falsa (falso negativo). Poder = 1 - β.","pt_PT":"Erro Tipo I (α): rejeitar uma hipótese nula verdadeira (falso positivo). Erro Tipo II (β): não rejeitar uma hipótese nula falsa (falso negativo). Poder = 1 - β."}, sort_order: 144 },
  { id: 'dc-math-0145', deck_id: 'deck-math', front: 'Pearson Correlation Coefficient (r)', back: 'r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ). Ranges from -1 to +1; r = ±1 indicates perfect linear correlation, r = 0 indicates no linear relationship.', front_translations: {"es":"Coeficiente de correlación de Pearson (r)","de":"Pearsonscher Korrelationskoeffizient (r)","fr":"Coefficient de corrélation de Pearson (r)","tr":"Pearson Korelasyon Katsayısı (r)","nl":"Pearson correlatiecoëfficiënt (r)","ru":"Коэффициент корреляции Пирсона (r)","zh":"皮尔逊相关系数（r）","pt_BR":"Coeficiente de correlação de Pearson (r)","pt_PT":"Coeficiente de correlação de Pearson (r)"}, back_translations: {"es":"r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ). Varia de -1 a +1; r = ±1 indica correlación linear perfeita, r = 0 indica ausencia de relación linear.","de":"r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ). Liegt zwischen -1 und +1; r = ±1 zeigt perfekte lineare Korrelation, r = 0 zeigt keine lineare Beziehung.","fr":"r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ). Varie de -1 à +1 ; r = ±1 indique une corrélation linéaire parfaite, r = 0 indique l'absence de relation linéaire.","tr":"r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ). -1 ile +1 arasında değişir; r = ±1 mükemmel doğrusal korelasyonu, r = 0 doğrusal ilişki olmadığını gösterir.","nl":"r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ). Varieert van -1 tot +1; r = ±1 geeft perfecte lineaire correlatie aan, r = 0 geeft geen lineair verband aan.","ru":"r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ). Варьируется от -1 до +1; r = ±1 означает идеальную линейную корреляцию, r = 0 — отсутствие линейной зависимости.","zh":"r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ)。范围从 -1 到 +1；r = ±1 表示完全线性相关，r = 0 表示无线性关系。","pt_BR":"r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ). Varia de -1 a +1; r = ±1 indica correlação linear perfeita, r = 0 indica ausência de relação linear.","pt_PT":"r = Σ(xᵢ-x̄)(yᵢ-ȳ) / (nσₓσᵧ). Varia de -1 a +1; r = ±1 indica correlação linear perfeita, r = 0 indica ausência de relação linear."}, sort_order: 145 },
  { id: 'dc-math-0146', deck_id: 'deck-math', front: 'Linear Regression Formula', back: 'ŷ = a + bx, where b = r(σᵧ/σₓ) and a = ȳ - bx̄. The best-fit line minimizes the sum of squared residuals (least squares method).', front_translations: {"es":"Fórmula de regresión linear","de":"Lineare Regressionformel","fr":"Formule de régression linéaire","tr":"Doğrusal Regresyon Formülü","nl":"Lineaire regressieformule","ru":"Формула линейной регрессии","zh":"线性回归公式","pt_BR":"Fórmula de regressão linear","pt_PT":"Fórmula de regressão linear"}, back_translations: {"es":"ŷ = a + bx, donde b = r(σᵧ/σₓ) y a = ȳ - bx̄. La línea de mejor ajuste minimiza a suma de los resíduos al cuadrado (método de los mínimos cuadrados).","de":"ŷ = a + bx, wobei b = r(σᵧ/σₓ) und a = ȳ - bx̄. Die Anpassungslinie minimiert die Summe der quadratischen Residuen (Methode der kleinsten Quadrate).","fr":"ŷ = a + bx, où b = r(σᵧ/σₓ) et a = ȳ - bx̄. La droite d'ajustement minimise la somme des carrés des résidus (méthode des moindres carrés).","tr":"ŷ = a + bx, burada b = r(σᵧ/σₓ) ve a = ȳ - bx̄. En uygun doğru, artıkların karelerinin toplamını en aza indirir (en küçük kareler yöntemi).","nl":"ŷ = a + bx, waarbij b = r(σᵧ/σₓ) en a = ȳ - bx̄. De best passende lijn minimaliseert de som van gekwadrateerde residuen (kleinste kwadraten methode).","ru":"ŷ = a + bx, где b = r(σᵧ/σₓ) и a = ȳ - bx̄. Линия наилучшего соответствия минимизирует сумму квадратов остатков (метод наименьших квадратов).","zh":"ŷ = a + bx，其中 b = r(σᵧ/σₓ)，a = ȳ - bx̄。最佳拟合线使残差平方和最小（最小二乘法）。","pt_BR":"ŷ = a + bx, onde b = r(σᵧ/σₓ) e a = ȳ - bx̄. A linha de melhor ajuste minimiza a soma dos resíduos ao quadrado (método dos mínimos quadrados).","pt_PT":"ŷ = a + bx, onde b = r(σᵧ/σₓ) e a = ȳ - bx̄. A linha de melhor ajuste minimiza a soma dos resíduos ao quadrado (método dos mínimos quadrados)."}, sort_order: 146 },
  { id: 'dc-math-0147', deck_id: 'deck-math', front: 'Interquartile Range (IQR)', back: 'IQR = Q3 - Q1. The range of the middle 50% of data; a robust measure of spread. Outliers are often defined as points more than 1.5 × IQR below Q1 or above Q3.', front_translations: {"es":"Amplitude interquartil (IQR)","de":"Interquartilsabstand (IQR)","fr":"Écart interquartile (IQR)","tr":"Çeyrekler Arası Aralık (IQR)","nl":"Interkwartielafstand (IQR)","ru":"Межквартильный размах (IQR)","zh":"四分位距（IQR）","pt_BR":"Amplitude interquartil (IQR)","pt_PT":"Amplitude interquartil (IQR)"}, back_translations: {"es":"IQR = Q3 - Q1. El intervalo de los 50% centrais de los datos; una medida robusta de dispersão. Valores atípicos son frecuentemente definidos como puntos más de 1,5 × IQR por debajo de Q1 o por encima de Q3.","de":"IQR = Q3 - Q1. Der Bereich der mittleren 50% der Daten; ein robustes Streuungsmaß. Ausreißer werden oft als Punkte definiert, die mehr als 1,5 × IQR unter Q1 oder über Q3 liegen.","fr":"IQR = Q3 - Q1. L'étendue des 50% centraux des données ; une mesure robuste de dispersion. Les valeurs aberrantes sont souvent définies comme des points à plus de 1,5 × IQR en dessous de Q1 ou au-dessus de Q3.","tr":"IQR = Q3 - Q1. Verilerin orta %50'sinin aralığı; sağlam bir yayılım ölçüsü. Aykırı değerler çoğunlukla Q1'in 1,5 × IQR altında veya Q3'ün 1,5 × IQR üstünde olan noktalar olarak tanımlanır.","nl":"IQR = Q3 - Q1. Het bereik van de middelste 50% van de gegevens; een robuuste maatstaf voor spreiding. Uitschieters worden vaak gedefinieerd als punten meer dan 1,5 × IQR onder Q1 of boven Q3.","ru":"IQR = Q3 - Q1. Диапазон средних 50% данных; устойчивая мера разброса. Выбросы часто определяются как точки, находящиеся более чем на 1,5 × IQR ниже Q1 или выше Q3.","zh":"IQR = Q3 - Q1。数据中间 50% 的范围；一种稳健的分散度量。异常值通常定义为低于 Q1 或高于 Q3 超过 1.5 × IQR 的点。","pt_BR":"IQR = Q3 - Q1. O intervalo dos 50% centrais dos dados; uma medida robusta de dispersão. Valores atípicos são frequentemente definidos como pontos mais de 1,5 × IQR abaixo de Q1 ou acima de Q3.","pt_PT":"IQR = Q3 - Q1. O intervalo dos 50% centrais dos dados; uma medida robusta de dispersão. Valores atípicos são frequentemente definidos como pontos mais de 1,5 × IQR abaixo de Q1 ou acima de Q3."}, sort_order: 147 },
  { id: 'dc-math-0148', deck_id: 'deck-math', front: 'Euler\'s Number (e)', back: 'e ≈ 2.71828. Defined as lim[n→∞](1 + 1/n)ⁿ; it is the base of the natural logarithm and is irrational and transcendental. It arises naturally in continuous growth problems.', front_translations: {"es":"Número de Euler (y)","de":"Eulersche Zahl (e)","fr":"Nombre d'Euler (e)","tr":"Euler Sayısı (e)","nl":"Getal van Euler (e)","ru":"Число Эйлера (e)","zh":"欧拉数（e）","pt_BR":"Número de Euler (e)","pt_PT":"Número de Euler (e)"}, back_translations: {"es":"y ≈ 2,71828. Definido como lim[n→∞](1 + 1/n)ⁿ; es a base del logaritmo natural y es irracional y transcendental. Surge naturalmente en problemas de crecimiento contínuo.","de":"e ≈ 2,71828. Definiert als lim[n→∞](1 + 1/n)ⁿ; es ist die Basis des natürlichen Logarithmus und irrational und transzendent. Es tritt natürlich in Problemen des kontinuierlichen Wachstums auf.","fr":"e ≈ 2,71828. Défini comme lim[n→∞](1 + 1/n)ⁿ ; c'est la base du logarithme naturel, il est irrationnel et transcendant. Il apparaît naturellement dans les problèmes de croissance continue.","tr":"e ≈ 2,71828. lim[n→∞](1 + 1/n)ⁿ olarak tanımlanır; doğal logaritmanın tabanıdır ve irrasyonel ve transandandır. Sürekli büyüme problemlerinde doğal olarak ortaya çıkar.","nl":"e ≈ 2,71828. Gedefinieerd als lim[n→∞](1 + 1/n)ⁿ; het is de basis van de natuurlijke logaritme en is irrationeel en transcendentaal. Het treedt op een natuurlijke manier op in problemen van continue groei.","ru":"e ≈ 2,71828. Определяется как lim[n→∞](1 + 1/n)ⁿ; является основанием натурального логарифма, иррационально и трансцендентно. Естественно возникает в задачах непрерывного роста.","zh":"e ≈ 2.71828。定义为 lim[n→∞](1 + 1/n)ⁿ；是自然对数的底数，是无理数和超越数。在连续增长问题中自然出现。","pt_BR":"e ≈ 2,71828. Definido como lim[n→∞](1 + 1/n)ⁿ; é a base do logaritmo natural e é irracional e transcendental. Surge naturalmente em problemas de crescimento contínuo.","pt_PT":"e ≈ 2,71828. Definido como lim[n→∞](1 + 1/n)ⁿ; é a base do logaritmo natural e é irracional e transcendental. Surge naturalmente em problemas de crescimento contínuo."}, sort_order: 148 },
  { id: 'dc-math-0149', deck_id: 'deck-math', front: 'Pi (π)', back: 'π ≈ 3.14159. The ratio of a circle\'s circumference to its diameter; it is irrational and transcendental. It appears throughout mathematics, from geometry to probability to complex analysis.', front_translations: {"es":"Pi (π)","de":"Pi (π)","fr":"Pi (π)","tr":"Pi (π)","nl":"Pi (π)","ru":"Пи (π)","zh":"圆周率（π）","pt_BR":"Pi (π)","pt_PT":"Pi (π)"}, back_translations: {"es":"π ≈ 3,14159. La razão de la circunferencia de un círculo al su diametro; es irracional y transcendental. Aparece en toda a matemática, de la geometría a la probabilidad a la análise complexa.","de":"π ≈ 3,14159. Das Verhältnis des Umfangs eines Kreises zu seinem Durchmesser; es ist irrational und transzendent. Es taucht überall in der Mathematik auf, von der Geometrie bis zur Wahrscheinlichkeit und komplexen Analysis.","fr":"π ≈ 3,14159. Le rapport de la circonférence d'un cercle à son diamètre ; il est irrationnel et transcendant. Il apparaît dans toute la mathématique, de la géométrie aux probabilités en passant par l'analyse complexe.","tr":"π ≈ 3,14159. Bir dairenin çevresinin çapına oranı; irrasyonel ve transandandır. Geometriden olasılığa ve karmaşık analize kadar matematiğin her yerinde karşımıza çıkar.","nl":"π ≈ 3,14159. De verhouding van de omtrek van een cirkel tot zijn diameter; het is irrationeel en transcendentaal. Het verschijnt overal in de wiskunde, van meetkunde tot kansrekening tot complexe analyse.","ru":"π ≈ 3,14159. Отношение длины окружности к её диаметру; иррационально и трансцендентно. Встречается повсюду в математике — от геометрии до теории вероятностей и комплексного анализа.","zh":"π ≈ 3.14159。圆的周长与直径之比；是无理数和超越数。它贯穿数学各领域，从几何到概率再到复分析。","pt_BR":"π ≈ 3,14159. A razão da circunferência de um círculo ao seu diâmetro; é irracional e transcendental. Aparece em toda a matemática, da geometria à probabilidade à análise complexa.","pt_PT":"π ≈ 3,14159. A razão da circunferência de um círculo ao seu diâmetro; é irracional e transcendental. Aparece em toda a matemática, da geometria à probabilidade à análise complexa."}, sort_order: 149 },
  { id: 'dc-math-0150', deck_id: 'deck-math', front: 'The Golden Ratio (φ)', back: 'φ = (1 + √5)/2 ≈ 1.61803. A number with the property that φ² = φ + 1; appears in art, architecture, the Fibonacci sequence (ratio of consecutive terms converges to φ), and nature.', front_translations: {"es":"La razão áurea (φ)","de":"Der Goldene Schnitt (φ)","fr":"Le nombre d'or (φ)","tr":"Altın Oran (φ)","nl":"De gulden snede (φ)","ru":"Золотое сечение (φ)","zh":"黄金比例（φ）","pt_BR":"A razão áurea (φ)","pt_PT":"A razão áurea (φ)"}, back_translations: {"es":"φ = (1 + √5)/2 ≈ 1,61803. Un número con a propiedad que φ² = φ + 1; aparece en la arte, arquitetura, secuencia de Fibonacci (a razão de termos consecutivos converge para φ) y en la natureza.","de":"φ = (1 + √5)/2 ≈ 1,61803. Eine Zahl mit der Eigenschaft φ² = φ + 1; erscheint in Kunst, Architektur, der Fibonacci-Folge (das Verhältnis aufeinanderfolgender Glieder konvergiert gegen φ) und in der Natur.","fr":"φ = (1 + √5)/2 ≈ 1,61803. Un nombre avec la propriété que φ² = φ + 1 ; apparaît dans l'art, l'architecture, la suite de Fibonacci (le rapport de termes consécutifs converge vers φ) et dans la nature.","tr":"φ = (1 + √5)/2 ≈ 1,61803. φ² = φ + 1 özelliğine sahip bir sayı; sanatta, mimaride, Fibonacci dizisinde (ardışık terimlerin oranı φ'ye yakınsar) ve doğada görülür.","nl":"φ = (1 + √5)/2 ≈ 1,61803. Een getal met de eigenschap dat φ² = φ + 1; verschijnt in kunst, architectuur, de rij van Fibonacci (de verhouding van opeenvolgende termen convergeert naar φ) en in de natuur.","ru":"φ = (1 + √5)/2 ≈ 1,61803. Число со свойством φ² = φ + 1; встречается в искусстве, архитектуре, последовательности Фибоначчи (отношение соседних членов стремится к φ) и в природе.","zh":"φ = (1 + √5)/2 ≈ 1.61803。满足 φ² = φ + 1 性质的数；出现在艺术、建筑、斐波那契数列（相邻项之比收敛于 φ）和自然界中。","pt_BR":"φ = (1 + √5)/2 ≈ 1,61803. Um número com a propriedade que φ² = φ + 1; aparece na arte, arquitetura, sequência de Fibonacci (a razão de termos consecutivos converge para φ) e na natureza.","pt_PT":"φ = (1 + √5)/2 ≈ 1,61803. Um número com a propriedade que φ² = φ + 1; aparece na arte, arquitectura, sequência de Fibonacci (a razão de termos consecutivos converge para φ) e na natureza."}, sort_order: 150 },
];
